INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'complete-urinalysis'), 'A comprehensive test of the physical and chemical properties of urine and its sediment', 'Sveobuhvatna analiza fizičkih, hemijskih svojstava mokraće i sedimenta', 'Свеобухватна анализа физичких, хемијских својстава мокраће и седимента', 'Комплексный анализ физических, химических свойств мочи и осадка', 'Eine umfassende Untersuchung der physikalischen und chemischen Eigenschaften des Urins und des Sediments', 'İdrarın fiziksel ve kimyasal özellikleri ile sedimentinin kapsamlı analizi', 'A single morning urine sample in a container, no needles or injections involved', 'Jednokratni uzorak jutarnje mokraće u posudi, bez igala i uboda', 'Једнократни узорак јутарње мокраће у посуди, без игала и убода', 'Разовая утренняя порция мочи в контейнер, без иглы и уколов', 'Eine einmalige Morgenurinprobe in einem Behälter, ohne Nadeln oder Injektionen', 'Bir kaba tek seferlik sabah idrarı örneği alınması, iğne veya enjeksiyon gerekmez', 'Preventive check-up, routine health screening, symptoms related to the kidneys/urinary tract, monitoring during pregnancy', 'Preventivni pregled, sistematski pregled, simptomi sa strane bubrega/mokraćnih puteva, kontrola tokom trudnoće', 'Превентивни преглед, систематски преглед, симптоми са стране бубрега/мокраћних путева, контрола током трудноће', 'Профилактический осмотр, диспансеризация, симптомы со стороны почек/мочевых путей, контроль при беременности', 'Vorsorgeuntersuchung, Routine-Gesundheitscheck, Beschwerden im Bereich der Nieren/Harnwege, Kontrolle während der Schwangerschaft', 'Rutin kontrol, genel sağlık taraması, böbrek/idrar yolları ile ilgili semptomlar, gebelikte takip', 'Morning urine after hygiene; for 1–2 days beforehand avoid beetroot and other coloring foods and heavy physical exertion; mention if menstruating', 'Jutarnja mokraća poslije higijene; 1–2 dana ranije izbjegavati cveklu i namirnice koje boje mokraću, kao i veće fizičke napore; napomenuti ako je menstruacija', 'Јутарња мокраћа послије хигијене; 1–2 дана раније избјегавати цвеклу и намирнице које боје мокраћу, као и веће физичке напоре; напоменути ако је менструација', 'Утренняя моча после гигиены; за 1–2 дня — без свёклы и красящих продуктов, без больших физических нагрузок; предупредить о менструации', 'Morgenurin nach der Hygiene; 1–2 Tage vorher rote Bete und andere färbende Lebensmittel sowie starke körperliche Anstrengung vermeiden; eine Menstruation sollte angegeben werden', 'Hijyen sonrası sabah idrarı; 1–2 gün öncesinden pancar ve idrarı renklendiren gıdalardan ve yoğun fiziksel efordan kaçınılmalı; adet dönemindeyseniz belirtin', 'Changes may be related to processes in the kidneys, urinary tract, metabolism, or temporary factors (exertion, diet). The exact cause is determined by a doctor based on the overall picture', 'Promjene mogu biti povezane sa procesima u bubrezima, mokraćnim putevima, metabolizmom ili privremenim faktorima (napor, ishrana). Tačan uzrok utvrđuje ljekar na osnovu cjelokupne slike', 'Промјене могу бити повезане са процесима у бубрезима, мокраћним путевима, метаболизмом или привременим факторима (напор, исхрана). Тачан узрок утврђује љекар на основу цјелокупне слике', 'Изменения могут быть связаны с процессами в почках, мочевых путях, обменом веществ или временными факторами (нагрузка, питание). Точную причину определяет врач по совокупности показателей', 'Veränderungen können mit Vorgängen in den Nieren, den Harnwegen, dem Stoffwechsel oder vorübergehenden Faktoren (Belastung, Ernährung) zusammenhängen. Die genaue Ursache wird vom Arzt anhand des Gesamtbilds festgestellt', 'Değişiklikler böbreklerdeki, idrar yollarındaki, metabolizmadaki süreçlerle veya geçici etkenlerle (efor, beslenme) ilişkili olabilir. Kesin nedeni hekim genel tabloya göre belirler')
