INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'glucose'), 'Blood test for blood sugar (glucose) level', 'Analiza krvi na nivo šećera (glukoze)', 'Анализа крви на ниво шећера (глукозе)', 'Анализ крови на уровень сахара (глюкозы)', 'Bluttest zur Bestimmung des Blutzuckerspiegels (Glukose)', 'Kandaki şeker (glukoz) düzeyini ölçen kan testi', 'Venous blood draw on an empty stomach', 'Uzimanje venske krvi natašte', 'Узимање венске крви наташте', 'Забор венозной крови натощак', 'Entnahme von venösem Blut nüchtern', 'Aç karnına toplardamardan kan alınması', 'Routine check-ups, monitoring diabetes mellitus, thirst/weakness, screening during pregnancy', 'Sistematski pregled, kontrola šećerne bolesti, žeđ/slabost, skrining tokom trudnoće', 'Систематски преглед, контрола шећерне болести, жеђ/слабост, скрининг током трудноће', 'Диспансеризация, контроль сахарного диабета, жажда/слабость, скрининг при беременности', 'Vorsorgeuntersuchung, Kontrolle bei Diabetes mellitus, Durst/Schwäche, Screening während der Schwangerschaft', 'Rutin kontrol, diyabetin takibi, susama/halsizlik, gebelikte tarama', 'Fasting for 8–12 hours, only water allowed; avoid alcohol and heavy food the day before', 'Natašte 8–12 sati, dozvoljena samo voda; dan ranije izbjegavati alkohol i tešku hranu', 'Наташте 8–12 сати, дозвољена само вода; дан раније избјегавати алкохол и тешку храну', 'Натощак 8–12 часов, разрешена только вода; накануне избегать алкоголя и тяжёлой пищи', 'Nüchtern seit 8–12 Stunden, nur Wasser erlaubt; am Vortag Alkohol und schwere Mahlzeiten vermeiden', '8–12 saat aç karnına, sadece su içilebilir; bir önceki gün alkol ve ağır yiyeceklerden kaçınılmalıdır', 'Changes in the level may be related to disturbances in carbohydrate metabolism or temporary factors (stress, food intake, medications). The diagnosis is made by a doctor based on several indicators', 'Promjene nivoa mogu biti povezane sa poremećajem metabolizma ugljenih hidrata ili privremenim faktorima (stres, uzimanje hrane, lijekovi). Dijagnozu postavlja ljekar na osnovu više pokazatelja', 'Промјене нивоа могу бити повезане са поремећајем метаболизма угљених хидрата или привременим факторима (стрес, узимање хране, лијекови). Дијагнозу поставља љекар на основу више показатеља', 'Изменения уровня могут быть связаны с нарушением углеводного обмена или временными факторами (стресс, приём пищи, лекарства). Диагноз ставит врач на основании нескольких показателей', 'Veränderungen des Werts können mit einer Störung des Kohlenhydratstoffwechsels oder vorübergehenden Faktoren (Stress, Nahrungsaufnahme, Medikamente) zusammenhängen. Die Diagnose wird vom Arzt anhand mehrerer Werte gestellt', 'Değerdeki değişiklikler karbonhidrat metabolizması bozukluğu veya geçici etkenlerle (stres, yemek yeme, ilaçlar) ilişkili olabilir. Tanı, birden fazla göstergeye dayanarak hekim tarafından konur')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'cholesterol'), 'Blood test for total cholesterol — one of the indicators of lipid metabolism', 'Analiza krvi na ukupni holesterol — jedan od pokazatelja lipidnog metabolizma', 'Анализа крви на укупни холестерол — један од показатеља липидног метаболизма', 'Анализ крови на общее содержание холестерина — один из показателей липидного обмена', 'Bluttest zur Bestimmung des Gesamtcholesterins — eines der Indikatoren des Fettstoffwechsels', 'Lipid metabolizmasının göstergelerinden biri olan toplam kolesterol için kan testi', 'Venous blood draw, usually together with the rest of the lipid profile', 'Uzimanje venske krvi, obično zajedno sa ostalim lipidnim profilom', 'Узимање венске крви, обично заједно са осталим липидним профилом', 'Забор венозной крови, обычно вместе с остальным липидным профилем', 'Entnahme von venösem Blut, meist zusammen mit dem restlichen Lipidprofil', 'Genellikle diğer lipid profili değerleriyle birlikte toplardamardan kan alınması', 'Cardiovascular risk screening, routine check-ups, monitoring during lipid-lowering therapy', 'Skrining kardiovaskularnog rizika, sistematski pregled, kontrola tokom uzimanja lijekova za snižavanje lipida', 'Скрининг кардиоваскуларног ризика, систематски преглед, контрола током узимања лијекова за снижавање липида', 'Скрининг сердечно-сосудистого риска, диспансеризация, контроль на фоне гиполипидемических препаратов', 'Screening des kardiovaskulären Risikos, Vorsorgeuntersuchung, Kontrolle während einer lipidsenkenden Therapie', 'Kardiyovasküler risk taraması, rutin kontrol, yağ düşürücü tedavi sırasında takip', 'Fasting for 9–12 hours; avoid fatty food and alcohol the day before', 'Natašte 9–12 sati; dan ranije izbjegavati masnu hranu i alkohol', 'Наташте 9–12 сати; дан раније избјегавати масну храну и алкохол', 'Натощак 9–12 часов; за сутки избегать жирной пищи и алкоголя', '9–12 Stunden nüchtern; am Vortag fettreiche Speisen und Alkohol vermeiden', '9–12 saat aç karnına; bir önceki gün yağlı yiyecekler ve alkolden kaçınılmalıdır', 'Changes may be related to diet, lifestyle, heredity, or metabolic disorders. The overall risk is assessed by a doctor together with other fractions (LDL, HDL, triglycerides) and the clinical picture', 'Promjene mogu biti povezane sa ishranom, načinom života, nasljeđem ili poremećajem metabolizma. Ukupan rizik ljekar procjenjuje zajedno sa ostalim frakcijama (LDL, HDL, trigliceridi) i kliničkom slikom', 'Промјене могу бити повезане са исхраном, начином живота, насљеђем или поремећајем метаболизма. Укупан ризик љекар процјењује заједно са осталим фракцијама (ЛДЛ, ХДЛ, триглицериди) и клиничком сликом', 'Изменения могут быть связаны с питанием, образом жизни, наследственностью или нарушением обмена веществ. Общий риск врач оценивает вместе с другими фракциями (ЛПНП, ЛПВП, триглицериды) и клинической картиной', 'Veränderungen können mit Ernährung, Lebensstil, erblichen Faktoren oder Stoffwechselstörungen zusammenhängen. Das Gesamtrisiko bewertet der Arzt zusammen mit den weiteren Werten (LDL, HDL, Triglyceride) und dem klinischen Bild', 'Değişiklikler beslenme, yaşam tarzı, kalıtım veya metabolizma bozukluğuyla ilişkili olabilir. Genel riski hekim, diğer değerlerle (LDL, HDL, trigliseritler) ve klinik tabloyla birlikte değerlendirir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'creatinine'), 'Blood test reflecting kidney filtration function', 'Analiza krvi koja odražava filtracionu funkciju bubrega', 'Анализа крви која одражава филтрациону функцију бубрега', 'Анализ крови, отражающий фильтрационную функцию почек', 'Bluttest, der die Filtrationsfunktion der Nieren widerspiegelt', 'Böbreklerin filtrasyon fonksiyonunu yansıtan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Toplardamardan kan alınması', 'Assessment of kidney function, preparation for surgery/procedures, monitoring during medications that put strain on the kidneys, routine check-ups', 'Procjena funkcije bubrega, priprema za operacije/procedure, kontrola tokom uzimanja lijekova koji opterećuju bubrege, sistematski pregled', 'Процјена функције бубрега, припрема за операције/процедуре, контрола током узимања лијекова који оптерећују бубреге, систематски преглед', 'Оценка функции почек, подготовка к операциям/процедурам, контроль на фоне препаратов с нагрузкой на почки, диспансеризация', 'Beurteilung der Nierenfunktion, Vorbereitung auf Operationen/Eingriffe, Kontrolle bei Medikamenten, die die Nieren belasten, Vorsorgeuntersuchung', 'Böbrek fonksiyonunun değerlendirilmesi, ameliyat/işlem öncesi hazırlık, böbrekleri yoran ilaçların kullanımında takip, rutin kontrol', 'No special preparation usually required; it is advisable to avoid intense physical exertion the day before', 'Obično nije potrebna posebna priprema; poželjno je izbjegavati intenzivne napore dan ranije', 'Обично није потребна посебна припрема; пожељно је избјегавати интензивне напоре дан раније', 'Специальной подготовки обычно не требуется; желательно избегать интенсивных нагрузок накануне', 'In der Regel keine besondere Vorbereitung erforderlich; intensive körperliche Anstrengung am Vortag sollte vermieden werden', 'Genellikle özel bir hazırlık gerekmez; bir önceki gün yoğun fiziksel efordan kaçınılması önerilir', 'Changes may be related to kidney function, muscle mass, dehydration, or certain medications. Interpretation by a doctor takes age, sex, and clinical picture into account', 'Promjene mogu biti povezane sa funkcijom bubrega, mišićnom masom, dehidracijom ili uzimanjem određenih lijekova. Ljekar tumači rezultat uzimajući u obzir godine, pol i kliničku sliku', 'Промјене могу бити повезане са функцијом бубрега, мишићном масом, дехидрацијом или узимањем одређених лијекова. Љекар тумачи резултат узимајући у обзир године, пол и клиничку слику', 'Изменения могут быть связаны с функцией почек, мышечной массой, обезвоживанием или приёмом некоторых препаратов. Интерпретирует врач с учётом возраста, пола и клинической картины', 'Veränderungen können mit der Nierenfunktion, der Muskelmasse, Dehydrierung oder bestimmten Medikamenten zusammenhängen. Der Arzt interpretiert das Ergebnis unter Berücksichtigung von Alter, Geschlecht und klinischem Bild', 'Değişiklikler böbrek fonksiyonu, kas kütlesi, sıvı kaybı veya bazı ilaçlarla ilişkili olabilir. Hekim, yaş, cinsiyet ve klinik tabloyu dikkate alarak yorumlar')
