INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'c-reactive-protein'), 'Blood test for a marker of acute inflammation', 'Analiza krvi na marker akutne upale', 'Анализа крви на маркер акутне упале', 'Анализ крови на маркер острого воспаления', 'Bluttest auf einen Marker für akute Entzündungen', 'Akut iltihabın bir belirtecine bakan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Toplardamardan kan alınması', 'Suspected inflammatory/infectious process, monitoring treatment progress, follow-up after surgery', 'Sumnja na upalni/infektivni proces, kontrola toka liječenja, praćenje poslije operacije', 'Сумња на упални/инфективни процес, контрола тока лијечења, праћење послије операције', 'Подозрение на воспалительный/инфекционный процесс, контроль динамики лечения, наблюдение после операции', 'Verdacht auf einen entzündlichen/infektiösen Prozess, Verlaufskontrolle der Behandlung, Kontrolle nach einer Operation', 'İltihabi/enfeksiyöz süreç şüphesi, tedavi seyrinin takibi, ameliyat sonrası izlem', 'Fasting is preferable; avoid intense physical exertion the day before', 'Poželjno natašte; dan ranije izbjegavati intenzivne napore', 'Пожељно наташте; дан раније избјегавати интензивне напоре', 'Желательно натощак; накануне избегать интенсивных нагрузок', 'Nüchtern ist vorzuziehen; am Vortag intensive körperliche Anstrengung vermeiden', 'Aç karnına yapılması tercih edilir; bir önceki gün yoğun fiziksel efordan kaçınılmalıdır', 'An elevated result may be related to infection, inflammation, injury, or other processes in the body. The marker alone does not point to a specific disease — the cause is determined by a doctor', 'Povećanje može biti povezano sa infekcijom, upalom, povredom ili drugim procesima u organizmu. Sam pokazatelj ne ukazuje na konkretnu bolest — uzrok utvrđuje ljekar', 'Повећање може бити повезано са инфекцијом, упалом, повредом или другим процесима у организму. Сам показатељ не указује на конкретну болест — узрок утврђује љекар', 'Повышение может быть связано с инфекцией, воспалением, травмой или другими процессами в организме. Сам по себе показатель не указывает на конкретное заболевание — причину определяет врач', 'Ein erhöhter Wert kann mit einer Infektion, Entzündung, Verletzung oder anderen Vorgängen im Körper zusammenhängen. Der Wert allein weist nicht auf eine bestimmte Erkrankung hin — die Ursache wird vom Arzt bestimmt', 'Yükselme, enfeksiyon, iltihap, yaralanma veya vücuttaki başka süreçlerle ilişkili olabilir. Belirtecin kendisi belirli bir hastalığa işaret etmez — nedeni hekim belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'triglycerides'), 'Blood test for triglycerides — one of the forms of fat circulating in the blood', 'Analiza krvi na nivo triglicerida — jednog od oblika masti koje cirkulišu u krvi', 'Анализа крви на ниво триглицерида — једног од облика масти које циркулишу у крви', 'Анализ крови на уровень триглицеридов — одной из форм жиров, циркулирующих в крови', 'Bluttest zur Bestimmung des Triglyceridspiegels — einer Form von Fetten, die im Blut zirkulieren', 'Kanda dolaşan yağ türlerinden biri olan trigliserit düzeyini ölçen kan testi', 'Venous blood draw, usually on an empty stomach', 'Uzimanje venske krvi, obično natašte', 'Узимање венске крви, обично наташте', 'Забор венозной крови, обычно натощак', 'Entnahme von venösem Blut, in der Regel nüchtern', 'Genellikle aç karnına toplardamardan kan alınması', 'Assessment of lipid metabolism, routine check-ups, monitoring cardiovascular risk, being overweight, taking medications that affect fat metabolism', 'Procjena lipidnog metabolizma, sistematski pregled, kontrola kardiovaskularnog rizika, prekomjerna tjelesna težina, uzimanje lijekova koji utiču na metabolizam masti', 'Процјена липидног метаболизма, систематски преглед, контрола кардиоваскуларног ризика, прекомјерна тјелесна тежина, узимање лијекова који утичу на метаболизам масти', 'Оценка липидного обмена, диспансеризация, контроль сердечно-сосудистых рисков, избыточный вес, приём препаратов, влияющих на обмен жиров', 'Beurteilung des Fettstoffwechsels, Vorsorgeuntersuchung, Kontrolle kardiovaskulärer Risiken, Übergewicht, Einnahme von Medikamenten, die den Fettstoffwechsel beeinflussen', 'Lipid metabolizmasının değerlendirilmesi, genel sağlık kontrolü, kardiyovasküler risklerin takibi, fazla kilo, yağ metabolizmasını etkileyen ilaç kullanımı', 'Fasting for 9–12 hours, only water allowed; avoid alcohol and fatty foods the day before', 'Natašte 9–12 sati, dozvoljena samo voda; dan ranije izbjegavati alkohol i masnu hranu', 'Наташте 9–12 сати, дозвољена само вода; дан раније избјегавати алкохол и масну храну', 'Натощак 9–12 часов, разрешена только вода; накануне избегать алкоголя и жирной пищи', '9–12 Stunden nüchtern, nur Wasser erlaubt; am Vortag Alkohol und fettreiche Speisen vermeiden', '9–12 saat aç karnına, sadece su içilebilir; bir önceki gün alkol ve yağlı yiyeceklerden kaçınılmalıdır', 'Changes in the level may be related to dietary habits, alcohol consumption, metabolic disorders, or temporary factors. The exact cause is determined by a doctor', 'Promjene nivoa mogu biti povezane sa navikama u ishrani, konzumiranjem alkohola, metaboličkim poremećajima ili privremenim faktorima. Tačan uzrok utvrđuje ljekar', 'Промјене нивоа могу бити повезане са навикама у исхрани, конзумирањем алкохола, метаболичким поремећајима или привременим факторима. Тачан узрок утврђује љекар', 'Изменения уровня могут быть связаны с особенностями питания, приёмом алкоголя, метаболическими нарушениями или временными факторами. Точную причину определяет врач', 'Veränderungen des Werts können mit Ernährungsgewohnheiten, Alkoholkonsum, Stoffwechselstörungen oder vorübergehenden Faktoren zusammenhängen. Die genaue Ursache wird vom Arzt festgestellt', 'Değerdeki değişiklikler beslenme alışkanlıkları, alkol tüketimi, metabolik bozukluklar veya geçici etkenlerle ilişkili olabilir. Kesin nedeni hekim belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'ldl-cholesterol'), 'Blood test for low-density lipoprotein (LDL), the so-called "bad" cholesterol', 'Analiza krvi na nivo lipoproteina niske gustine (LDL), takozvanog "lošeg" holesterola', 'Анализа крви на ниво липопротеина ниске густине (ЛДЛ), такозваног "лошег" холестерола', 'Анализ крови на уровень липопротеинов низкой плотности (ЛПНП), так называемого "плохого" холестерина', 'Bluttest zur Bestimmung des Low-Density-Lipoprotein-Spiegels (LDL), des sogenannten "schlechten" Cholesterins', 'Halk arasında "kötü" kolesterol olarak bilinen düşük yoğunluklu lipoprotein (LDL) düzeyini ölçen kan testi', 'Venous blood draw on an empty stomach', 'Uzimanje venske krvi natašte', 'Узимање венске крви наташте', 'Забор венозной крови натощак', 'Entnahme von venösem Blut nüchtern', 'Aç karnına toplardamardan kan alınması', 'Routine check-ups, assessment of cardiovascular risk, monitoring treatment for lipid metabolism disorders', 'Sistematski pregled, procjena kardiovaskularnog rizika, kontrola terapije kod poremećaja lipidnog metabolizma', 'Систематски преглед, процјена кардиоваскуларног ризика, контрола терапије код поремећаја липидног метаболизма', 'Диспансеризация, оценка сердечно-сосудистых рисков, контроль терапии при нарушениях липидного обмена', 'Vorsorgeuntersuchung, Beurteilung kardiovaskulärer Risiken, Kontrolle der Therapie bei Fettstoffwechselstörungen', 'Genel sağlık kontrolü, kardiyovasküler riskin değerlendirilmesi, lipid metabolizması bozukluklarında tedavi takibi', 'Fasting for 9–12 hours, only water allowed; avoid fatty foods and alcohol the day before', 'Natašte 9–12 sati, dozvoljena samo voda; dan ranije izbjegavati masnu hranu i alkohol', 'Наташте 9–12 сати, дозвољена само вода; дан раније избјегавати масну храну и алкохол', 'Натощак 9–12 часов, разрешена только вода; накануне избегать жирной пищи и алкоголя', '9–12 Stunden nüchtern, nur Wasser erlaubt; am Vortag fettreiche Speisen und Alkohol vermeiden', '9–12 saat aç karnına, sadece su içilebilir; bir önceki gün yağlı yiyecekler ve alkolden kaçınılmalıdır', 'Changes in the level may be related to dietary habits, heredity, or other factors affecting fat metabolism. Interpretation, taking other indicators into account, is carried out by a doctor', 'Promjene nivoa mogu biti povezane sa navikama u ishrani, nasljeđem ili drugim faktorima koji utiču na metabolizam masti. Tumačenje, uz uvid u druge pokazatelje, daje ljekar', 'Промјене нивоа могу бити повезане са навикама у исхрани, насљеђем или другим факторима који утичу на метаболизам масти. Тумачење, уз увид у друге показатеље, даје љекар', 'Изменения уровня могут быть связаны с особенностями питания, наследственностью или другими факторами, влияющими на обмен жиров. Интерпретацию с учётом других показателей проводит врач', 'Veränderungen des Werts können mit Ernährungsgewohnheiten, erblichen Faktoren oder anderen Einflüssen auf den Fettstoffwechsel zusammenhängen. Die Interpretation unter Berücksichtigung weiterer Werte erfolgt durch den Arzt', 'Değerdeki değişiklikler beslenme alışkanlıkları, kalıtım veya yağ metabolizmasını etkileyen diğer etkenlerle ilişkili olabilir. Diğer göstergeler de dikkate alınarak yorumlama hekim tarafından yapılır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

