INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'urea'), 'Blood test for urea — a breakdown product of proteins that is eliminated by the kidneys', 'Analiza krvi na ureu — proizvod razgradnje proteina koji se izlučuje putem bubrega', 'Анализа крви на уреу — производ разградње протеина који се излучује путем бубрега', 'Анализ крови на мочевину — продукт распада белков, который выводится почками', 'Bluttest zur Bestimmung des Harnstoffwerts — eines Abbauprodukts von Proteinen, das über die Nieren ausgeschieden wird', 'Proteinlerin yıkım ürünü olan ve böbrekler yoluyla vücuttan atılan üre düzeyini ölçen kan testi', 'Venous blood draw, usually on an empty stomach', 'Uzimanje venske krvi, obično natašte', 'Узимање венске крви, обично наташте', 'Забор венозной крови, обычно натощак', 'Entnahme von venösem Blut, in der Regel nüchtern', 'Genellikle aç karnına toplardamardan kan alınması', 'Assessment of kidney function, routine check-ups, monitoring chronic kidney disease, preoperative preparation', 'Procjena rada bubrega, sistematski pregled, kontrola kod hroničnih bubrežnih oboljenja, priprema za operacije', 'Процјена рада бубрега, систематски преглед, контрола код хроничних бубрежних обољења, припрема за операције', 'Оценка работы почек, диспансеризация, контроль при хронических заболеваниях почек, подготовка к операциям', 'Beurteilung der Nierenfunktion, Vorsorgeuntersuchung, Kontrolle bei chronischen Nierenerkrankungen, Vorbereitung auf Operationen', 'Böbrek fonksiyonunun değerlendirilmesi, genel sağlık kontrolü, kronik böbrek hastalıklarında takip, ameliyat öncesi hazırlık', 'No special preparation is required, but fasting is preferable; avoid excessive protein intake the day before', 'Posebna priprema nije potrebna, ali je poželjno uzimanje uzorka natašte; dan ranije izbjegavati prekomjeran unos proteinske hrane', 'Посебна припрема није потребна, али је пожељно узимање узорка наташте; дан раније избјегавати прекомјеран унос протеинске хране', 'Специальной подготовки не требуется, но желателен забор натощак; накануне избегать чрезмерного употребления белковой пищи', 'Keine besondere Vorbereitung erforderlich, nüchterne Blutentnahme ist jedoch vorzuziehen; am Vortag übermäßigen Konsum eiweißreicher Nahrung vermeiden', 'Özel bir hazırlık gerekmez, ancak aç karnına alınması tercih edilir; bir önceki gün aşırı proteinli gıda tüketiminden kaçınılmalıdır', 'Changes in the level may be related to kidney function, dietary habits, dehydration, or certain medications. The cause is determined by a doctor based on examination results', 'Promjene nivoa mogu biti povezane sa radom bubrega, načinom ishrane, dehidracijom ili uzimanjem određenih lijekova. Uzrok utvrđuje ljekar na osnovu rezultata pregleda', 'Промјене нивоа могу бити повезане са радом бубрега, начином исхране, дехидрацијом или узимањем одређених лијекова. Узрок утврђује љекар на основу резултата прегледа', 'Изменения уровня могут быть связаны с работой почек, характером питания, обезвоживанием или приёмом некоторых препаратов. Причину устанавливает врач по результатам обследования', 'Veränderungen des Werts können mit der Nierenfunktion, den Ernährungsgewohnheiten, Dehydrierung oder bestimmten Medikamenten zusammenhängen. Die Ursache wird vom Arzt anhand der Untersuchungsergebnisse festgestellt', 'Değerdeki değişiklikler böbrek fonksiyonu, beslenme şekli, sıvı kaybı veya bazı ilaçların kullanımıyla ilişkili olabilir. Neden, muayene sonuçlarına göre hekim tarafından belirlenir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'potassium'), 'Blood test for potassium — an electrolyte important for heart and muscle function', 'Analiza krvi na nivo kalijuma — elektrolita važnog za rad srca i mišića', 'Анализа крви на ниво калијума — електролита важног за рад срца и мишића', 'Анализ крови на уровень калия — электролита, важного для работы сердца и мышц', 'Bluttest zur Bestimmung des Kaliumspiegels — eines Elektrolyts, das für die Herz- und Muskelfunktion wichtig ist', 'Kalp ve kas fonksiyonu için önemli bir elektrolit olan potasyum düzeyini ölçen kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Toplardamardan kan alınması', 'Assessment of fluid and electrolyte balance, monitoring during diuretic therapy, kidney disease, cardiovascular disorders', 'Procjena vodeno-elektrolitne ravnoteže, kontrola tokom uzimanja diuretika, kod bubrežnih oboljenja, kardiovaskularnih poremećaja', 'Процјена водено-електролитне равнотеже, контрола током узимања диуретика, код бубрежних обољења, кардиоваскуларних поремећаја', 'Оценка водно-электролитного баланса, контроль при приёме мочегонных препаратов, заболеваниях почек, сердечно-сосудистых нарушениях', 'Beurteilung des Flüssigkeits- und Elektrolythaushalts, Kontrolle bei Einnahme von Diuretika, Nierenerkrankungen, kardiovaskulären Störungen', 'Sıvı-elektrolit dengesinin değerlendirilmesi, diüretik kullanımı, böbrek hastalıkları, kardiyovasküler bozukluklarda takip', 'No special preparation is required, but fasting is preferable, without prolonged tourniquet application', 'Posebna priprema nije potrebna, ali je poželjno uzimanje uzorka natašte, bez dužeg stezanja vene podvezom', 'Посебна припрема није потребна, али је пожељно узимање узорка наташте, без дужег стезања вене подвезом', 'Специальной подготовки не требуется, но желателен забор натощак без длительного пережатия вены жгутом', 'Keine besondere Vorbereitung erforderlich, nüchterne Blutentnahme ohne längeres Abbinden der Vene ist jedoch vorzuziehen', 'Özel bir hazırlık gerekmez, ancak aç karnına ve turnikenin uzun süre sıkılmadan alınması tercih edilir', 'Changes in the level may be related to kidney function, medication use, diet, or fluid balance disturbances. The doctor evaluates the significance of the changes', 'Promjene nivoa mogu biti povezane sa radom bubrega, uzimanjem lijekova, ishranom ili poremećajem ravnoteže tečnosti. Značaj promjena procjenjuje ljekar', 'Промјене нивоа могу бити повезане са радом бубрега, узимањем лијекова, исхраном или поремећајем равнотеже течности. Значај промјена процјењује љекар', 'Изменения уровня могут быть связаны с работой почек, приёмом лекарств, питанием или нарушением баланса жидкости. Оценку значимости изменений проводит врач', 'Veränderungen des Werts können mit der Nierenfunktion, der Medikamenteneinnahme, der Ernährung oder Störungen des Flüssigkeitshaushalts zusammenhängen. Die Bedeutung der Veränderungen beurteilt der Arzt', 'Değerdeki değişiklikler böbrek fonksiyonu, ilaç kullanımı, beslenme veya sıvı dengesindeki bozukluklarla ilişkili olabilir. Değişikliklerin önemini hekim değerlendirir')
