INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'calcium'), 'Blood test for total calcium — a mineral important for bones, muscles, and the nervous system', 'Analiza krvi na ukupni kalcijum — mineral važan za kosti, mišiće i nervni sistem', 'Анализа крви на укупни калцијум — минерал важан за кости, мишиће и нервни систем', 'Анализ крови на общий кальций — минерал, важный для костей, мышц и нервной системы', 'Bluttest zur Bestimmung des Gesamtcalciums — eines Minerals, das für Knochen, Muskeln und das Nervensystem wichtig ist', 'Kemikler, kaslar ve sinir sistemi için önemli bir mineral olan toplam kalsiyum düzeyini ölçen kan testi', 'Venous blood draw, usually on an empty stomach', 'Uzimanje venske krvi, obično natašte', 'Узимање венске крви, обично наташте', 'Забор венозной крови, обычно натощак', 'Entnahme von venösem Blut, in der Regel nüchtern', 'Genellikle aç karnına toplardamardan kan alınması', 'Assessment of bone metabolism, routine check-ups, examination for bone, kidney, or parathyroid disorders', 'Procjena koštanog metabolizma, sistematski pregled, ispitivanje kod oboljenja kostiju, bubrega, paratireoidnih žlijezda', 'Процјена коштаног метаболизма, систематски преглед, испитивање код обољења костију, бубрега, паратиреоидних жлијезда', 'Оценка костного обмена, диспансеризация, обследование при заболеваниях костей, почек, паращитовидных желёз', 'Beurteilung des Knochenstoffwechsels, Vorsorgeuntersuchung, Abklärung bei Knochen-, Nieren- oder Nebenschilddrüsenerkrankungen', 'Kemik metabolizmasının değerlendirilmesi, genel sağlık kontrolü, kemik, böbrek veya paratiroid bezi hastalıklarında inceleme', 'Fasting for 8–12 hours, only water allowed; avoid calcium supplements the day before unless approved by a doctor', 'Natašte 8–12 sati, dozvoljena samo voda; dan ranije izbjegavati uzimanje dodataka sa kalcijumom bez konsultacije sa ljekarom', 'Наташте 8–12 сати, дозвољена само вода; дан раније избјегавати узимање додатака са калцијумом без консултације са љекаром', 'Натощак 8–12 часов, разрешена только вода; накануне избегать приёма кальцийсодержащих добавок без согласования с врачом', '8–12 Stunden nüchtern, nur Wasser erlaubt; am Vortag calciumhaltige Nahrungsergänzungsmittel ohne ärztliche Rücksprache vermeiden', '8–12 saat aç karnına, sadece su içilebilir; bir önceki gün doktora danışılmadan kalsiyum içeren takviyelerden kaçınılmalıdır', 'Changes in the level may be related to parathyroid function, bone metabolism, diet, supplement use, or kidney disease. Interpretation is carried out by a doctor', 'Promjene nivoa mogu biti povezane sa radom paratireoidnih žlijezda, koštanim metabolizmom, ishranom, uzimanjem dodataka ishrani ili bubrežnim oboljenjima. Tumačenje daje ljekar', 'Промјене нивоа могу бити повезане са радом паратиреоидних жлијезда, коштаним метаболизмом, исхраном, узимањем додатака исхрани или бубрежним обољењима. Тумачење даје љекар', 'Изменения уровня могут быть связаны с работой паращитовидных желёз, костным обменом, питанием, приёмом добавок или заболеваниями почек. Интерпретацию проводит врач', 'Veränderungen des Werts können mit der Funktion der Nebenschilddrüsen, dem Knochenstoffwechsel, der Ernährung, der Einnahme von Nahrungsergänzungsmitteln oder Nierenerkrankungen zusammenhängen. Die Interpretation erfolgt durch den Arzt', 'Değerdeki değişiklikler paratiroid bezi fonksiyonu, kemik metabolizması, beslenme, takviye kullanımı veya böbrek hastalıklarıyla ilişkili olabilir. Yorumlama hekim tarafından yapılır')
