INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'ast'), 'Blood test for AST (aspartate aminotransferase) — an enzyme found in the cells of the liver, heart, and muscles', 'Analiza krvi na AST (aspartat-aminotransferazu) — enzim koji se nalazi u ćelijama jetre, srca i mišića', 'Анализа крви на АСТ (аспартат-аминотрансферазу) — ензим који се налази у ћелијама јетре, срца и мишића', 'Анализ крови на АСТ (аспартатаминотрансферазу) — фермент, содержащийся в клетках печени, сердца и мышц', 'Bluttest zur Bestimmung von AST (Aspartat-Aminotransferase) — einem Enzym, das in den Zellen von Leber, Herz und Muskeln vorkommt', 'Karaciğer, kalp ve kas hücrelerinde bulunan bir enzim olan AST (aspartat aminotransferaz) düzeyini ölçen kan testi', 'Venous blood draw, usually on an empty stomach', 'Uzimanje venske krvi, obično natašte', 'Узимање венске крви, обично наташте', 'Забор венозной крови, обычно натощак', 'Entnahme von venösem Blut, in der Regel nüchtern', 'Genellikle aç karnına toplardamardan kan alınması', 'Assessment of liver function, routine check-ups, monitoring during certain medication use, examination for muscle or heart complaints', 'Procjena rada jetre, sistematski pregled, kontrola tokom uzimanja određenih lijekova, ispitivanje kod tegoba sa mišićima ili srcem', 'Процјена рада јетре, систематски преглед, контрола током узимања одређених лијекова, испитивање код тегоба са мишићима или срцем', 'Оценка работы печени, диспансеризация, контроль при приёме некоторых препаратов, обследование при мышечных или сердечных жалобах', 'Beurteilung der Leberfunktion, Vorsorgeuntersuchung, Kontrolle bei Einnahme bestimmter Medikamente, Abklärung bei Muskel- oder Herzbeschwerden', 'Karaciğer fonksiyonunun değerlendirilmesi, genel sağlık kontrolü, bazı ilaçların kullanımında takip, kas veya kalp yakınmalarında inceleme', 'Fasting is preferable; avoid intense physical exertion and alcohol the day before', 'Poželjno je uzimanje uzorka natašte; dan ranije izbjegavati intenzivan fizički napor i alkohol', 'Пожељно је узимање узорка наташте; дан раније избјегавати интензиван физички напор и алкохол', 'Желателен забор натощак; накануне избегать интенсивных физических нагрузок и алкоголя', 'Nüchterne Blutentnahme ist vorzuziehen; am Vortag intensive körperliche Anstrengung und Alkohol vermeiden', 'Aç karnına alınması tercih edilir; bir önceki gün yoğun fiziksel eforlardan ve alkolden kaçınılmalıdır', 'Changes in the level may be related to liver condition, muscle exertion, medication use, or alcohol. The exact cause is determined by a doctor, taking other indicators into account', 'Promjene nivoa mogu biti povezane sa stanjem jetre, mišićnim naporom, uzimanjem lijekova ili alkohola. Tačan uzrok, uz uvid u druge pokazatelje, utvrđuje ljekar', 'Промјене нивоа могу бити повезане са стањем јетре, мишићним напором, узимањем лијекова или алкохола. Тачан узрок, уз увид у друге показатеље, утврђује љекар', 'Изменения уровня могут быть связаны с состоянием печени, мышечной нагрузкой, приёмом препаратов или алкоголя. Точную причину определяет врач с учётом других показателей', 'Veränderungen des Werts können mit dem Zustand der Leber, körperlicher Belastung der Muskulatur, der Medikamenteneinnahme oder Alkohol zusammenhängen. Die genaue Ursache wird vom Arzt unter Berücksichtigung weiterer Werte festgestellt', 'Değerdeki değişiklikler karaciğerin durumu, kas yorgunluğu, ilaç kullanımı veya alkolle ilişkili olabilir. Kesin neden, diğer göstergeler de dikkate alınarak hekim tarafından belirlenir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'alt'), 'Blood test for ALT (alanine aminotransferase) — an enzyme found predominantly in liver cells', 'Analiza krvi na ALT (alanin-aminotransferazu) — enzim koji se pretežno nalazi u ćelijama jetre', 'Анализа крви на АЛТ (аланин-аминотрансферазу) — ензим који се претежно налази у ћелијама јетре', 'Анализ крови на АЛТ (аланинаминотрансферазу) — фермент, преимущественно содержащийся в клетках печени', 'Bluttest zur Bestimmung von ALT (Alanin-Aminotransferase) — einem Enzym, das überwiegend in Leberzellen vorkommt', 'Ağırlıklı olarak karaciğer hücrelerinde bulunan bir enzim olan ALT (alanin aminotransferaz) düzeyini ölçen kan testi', 'Venous blood draw, usually on an empty stomach', 'Uzimanje venske krvi, obično natašte', 'Узимање венске крви, обично наташте', 'Забор венозной крови, обычно натощак', 'Entnahme von venösem Blut, in der Regel nüchtern', 'Genellikle aç karnına toplardamardan kan alınması', 'Assessment of liver function, routine check-ups, monitoring during hepatotoxic medication use, examination for liver-related complaints', 'Procjena rada jetre, sistematski pregled, kontrola tokom uzimanja hepatotoksičnih lijekova, ispitivanje kod tegoba sa jetrom', 'Процјена рада јетре, систематски преглед, контрола током узимања хепатотоксичних лијекова, испитивање код тегоба са јетром', 'Оценка работы печени, диспансеризация, контроль при приёме гепатотоксичных препаратов, обследование при жалобах со стороны печени', 'Beurteilung der Leberfunktion, Vorsorgeuntersuchung, Kontrolle bei Einnahme leberschädigender Medikamente, Abklärung bei leberbezogenen Beschwerden', 'Karaciğer fonksiyonunun değerlendirilmesi, genel sağlık kontrolü, karaciğere zarar verebilecek ilaçların kullanımında takip, karaciğerle ilgili yakınmalarda inceleme', 'Fasting is preferable; avoid alcohol and fatty foods the day before', 'Poželjno je uzimanje uzorka natašte; dan ranije izbjegavati alkohol i masnu hranu', 'Пожељно је узимање узорка наташте; дан раније избјегавати алкохол и масну храну', 'Желателен забор натощак; накануне избегать алкоголя и жирной пищи', 'Nüchterne Blutentnahme ist vorzuziehen; am Vortag Alkohol und fettreiche Speisen vermeiden', 'Aç karnına alınması tercih edilir; bir önceki gün alkol ve yağlı yiyeceklerden kaçınılmalıdır', 'Changes in the level may be related to liver condition, medication use, alcohol, or other factors. The diagnosis is made by a doctor based on a comprehensive examination', 'Promjene nivoa mogu biti povezane sa stanjem jetre, uzimanjem lijekova, alkohola ili drugim faktorima. Dijagnozu postavlja ljekar na osnovu sveobuhvatnog pregleda', 'Промјене нивоа могу бити повезане са стањем јетре, узимањем лијекова, алкохола или другим факторима. Дијагнозу поставља љекар на основу свеобухватног прегледа', 'Изменения уровня могут быть связаны с состоянием печени, приёмом лекарств, алкоголя или другими факторами. Диагноз ставит врач на основании комплексного обследования', 'Veränderungen des Werts können mit dem Zustand der Leber, der Medikamenteneinnahme, Alkohol oder anderen Faktoren zusammenhängen. Die Diagnose wird vom Arzt anhand einer umfassenden Untersuchung gestellt', 'Değerdeki değişiklikler karaciğerin durumu, ilaç kullanımı, alkol veya diğer etkenlerle ilişkili olabilir. Tanı, kapsamlı bir muayene sonucunda hekim tarafından konur')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'hba1c'), 'Blood test for glycated hemoglobin (HbA1c), reflecting the average blood sugar level over the past 2–3 months', 'Analiza krvi na glikozilirani hemoglobin (HbA1c), koji odražava prosječan nivo šećera u posljednja 2–3 mjeseca', 'Анализа крви на гликозилирани хемоглобин (HbA1c), који одражава просјечан ниво шећера у посљедња 2–3 мјесеца', 'Анализ крови на гликированный гемоглобин (HbA1c), отражающий средний уровень сахара за последние 2–3 месяца', 'Bluttest zur Bestimmung des glykierten Hämoglobins (HbA1c), der den durchschnittlichen Blutzuckerspiegel der letzten 2–3 Monate widerspiegelt', 'Son 2-3 aylık ortalama kan şekeri düzeyini yansıtan glikozillenmiş hemoglobin (HbA1c) düzeyini ölçen kan testi', 'Venous blood draw, no special preparation required', 'Uzimanje venske krvi, posebna priprema nije potrebna', 'Узимање венске крви, посебна припрема није потребна', 'Забор венозной крови, специальная подготовка не требуется', 'Entnahme von venösem Blut, keine besondere Vorbereitung erforderlich', 'Toplardamardan kan alınması, özel bir hazırlık gerekmez', 'Diagnosis and monitoring of diabetes mellitus, assessment of carbohydrate metabolism during routine check-ups', 'Dijagnostika i kontrola dijabetesa, procjena metabolizma ugljenih hidrata u okviru sistematskog pregleda', 'Дијагностика и контрола дијабетеса, процјена метаболизма угљених хидрата у оквиру систематског прегледа', 'Диагностика и контроль сахарного диабета, оценка углеводного обмена при диспансеризации', 'Diagnose und Kontrolle von Diabetes mellitus, Beurteilung des Kohlenhydratstoffwechsels im Rahmen einer Vorsorgeuntersuchung', 'Diyabetin tanısı ve takibi, genel sağlık kontrolünde karbonhidrat metabolizmasının değerlendirilmesi', 'No special preparation is required', 'Posebna priprema nije potrebna', 'Посебна припрема није потребна', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Changes in the level may be related to carbohydrate metabolism over an extended period. The exact interpretation and diagnosis are made by a doctor', 'Promjene nivoa mogu biti povezane sa metabolizmom ugljenih hidrata tokom dužeg perioda. Tačno tumačenje i dijagnozu daje ljekar', 'Промјене нивоа могу бити повезане са метаболизмом угљених хидрата током дужег периода. Тачно тумачење и дијагнозу даје љекар', 'Изменения уровня могут быть связаны с особенностями углеводного обмена за длительный период. Точную интерпретацию и диагноз даёт врач', 'Veränderungen des Werts können mit dem Kohlenhydratstoffwechsel über einen längeren Zeitraum zusammenhängen. Die genaue Interpretation und Diagnose erfolgt durch den Arzt', 'Değerdeki değişiklikler uzun bir dönem boyunca karbonhidrat metabolizmasıyla ilişkili olabilir. Kesin yorumlama ve tanı hekim tarafından yapılır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

