INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'total-bilirubin'), 'Blood test for total bilirubin — a pigment formed during the breakdown of red blood cells and neutralized by the liver', 'Analiza krvi na ukupni bilirubin — pigment koji nastaje razgradnjom eritrocita, a neutrališe ga jetra', 'Анализа крви на укупни билирубин — пигмент који настаје разградњом еритроцита, а неутралише га јетра', 'Анализ крови на общий билирубин — пигмент, образующийся при распаде эритроцитов и обезвреживаемый печенью', 'Bluttest zur Bestimmung des Gesamtbilirubins — eines Pigments, das beim Abbau roter Blutkörperchen entsteht und von der Leber verarbeitet wird', 'Alyuvarların yıkımı sırasında oluşan ve karaciğer tarafından zararsız hale getirilen bir pigment olan total bilirubin düzeyini ölçen kan testi', 'Venous blood draw, usually on an empty stomach', 'Uzimanje venske krvi, obično natašte', 'Узимање венске крви, обично наташте', 'Забор венозной крови, обычно натощак', 'Entnahme von venösem Blut, in der Regel nüchtern', 'Genellikle aç karnına toplardamardan kan alınması', 'Assessment of liver and bile duct function, examination for yellowing of the skin or sclera, routine check-ups', 'Procjena rada jetre i žučnih puteva, ispitivanje kod žutila kože ili bjeloočnica, sistematski pregled', 'Процјена рада јетре и жучних путева, испитивање код жутила коже или бјелоочница, систематски преглед', 'Оценка работы печени и желчевыводящих путей, обследование при желтухе кожи или склер, диспансеризация', 'Beurteilung der Leber- und Gallenwegsfunktion, Abklärung bei Gelbfärbung von Haut oder Skleren, Vorsorgeuntersuchung', 'Karaciğer ve safra yollarının fonksiyonunun değerlendirilmesi, ciltte veya göz akında sararma durumunda inceleme, genel sağlık kontrolü', 'Fasting for 4–8 hours, only water allowed; avoid fatty foods the day before', 'Natašte 4–8 sati, dozvoljena samo voda; dan ranije izbjegavati masnu hranu', 'Наташте 4–8 сати, дозвољена само вода; дан раније избјегавати масну храну', 'Натощак 4–8 часов, разрешена только вода; накануне избегать жирной пищи', '4–8 Stunden nüchtern, nur Wasser erlaubt; am Vortag fettreiche Speisen vermeiden', '4–8 saat aç karnına, sadece su içilebilir; bir önceki gün yağlı yiyeceklerden kaçınılmalıdır', 'Changes in the level may be related to liver function, bile duct function, or increased breakdown of red blood cells. The exact cause is determined by a doctor', 'Promjene nivoa mogu biti povezane sa radom jetre, žučnih puteva ili pojačanom razgradnjom eritrocita. Tačan uzrok utvrđuje ljekar', 'Промјене нивоа могу бити повезане са радом јетре, жучних путева или појачаном разградњом еритроцита. Тачан узрок утврђује љекар', 'Изменения уровня могут быть связаны с работой печени, желчевыводящих путей или повышенным распадом эритроцитов. Точную причину определяет врач', 'Veränderungen des Werts können mit der Leberfunktion, den Gallenwegen oder einem verstärkten Abbau roter Blutkörperchen zusammenhängen. Die genaue Ursache wird vom Arzt festgestellt', 'Değerdeki değişiklikler karaciğer fonksiyonu, safra yolları veya alyuvarların artmış yıkımıyla ilişkili olabilir. Kesin nedeni hekim belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'gamma-gt'), 'Blood test for a liver enzyme, often linked to the function of the bile ducts', 'Analiza krvi na jetreni enzim, često povezan sa radom žučnih puteva', 'Анализа крви на јетрени ензим, често повезан са радом жучних путева', 'Анализ крови на фермент печени, часто связанный с работой желчевыводящих путей', 'Bluttest auf ein Leberenzym, das oft mit der Funktion der Gallenwege zusammenhängt', 'Sıklıkla safra yollarının işleyişiyle ilişkili bir karaciğer enzimine bakan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Assessment of liver and bile duct function, monitoring during certain medications, monitoring with regular alcohol consumption', 'Procjena rada jetre i žučnih puteva, kontrola pri uzimanju određenih lijekova, praćenje kod redovne konzumacije alkohola', 'Процјена рада јетре и жучних путева, контрола при узимању одређених лијекова, праћење код редовне конзумације алкохола', 'Оценка работы печени и желчевыводящих путей, контроль при приёме некоторых препаратов, наблюдение при регулярном употреблении алкоголя', 'Beurteilung der Leber- und Gallenwegsfunktion, Kontrolle bei Einnahme bestimmter Medikamente, Überwachung bei regelmäßigem Alkoholkonsum', 'Karaciğer ve safra yolları işlevinin değerlendirilmesi, belirli ilaçların kullanımı sırasında kontrol, düzenli alkol tüketiminde izleme', 'Preferably fasting; avoid alcohol the day before', 'Poželjno natašte; dan ranije izbjegavati alkohol', 'Пожељно наташте; дан раније избјегавати алкохол', 'Желательно натощак; накануне избегать алкоголя', 'Vorzugsweise nüchtern; am Vortag auf Alkohol verzichten', 'Tercihen aç karnına; bir önceki gün alkolden kaçınılmalı', 'An elevated level may be related to liver or bile duct disorders, certain medications, or alcohol consumption. The exact cause is determined by a doctor.', 'Povećanje može biti povezano sa poremećajima rada jetre, žučnih puteva, uzimanjem određenih lijekova ili alkohola. Tačan uzrok određuje ljekar.', 'Повећање може бити повезано са поремећајима рада јетре, жучних путева, узимањем одређених лијекова или алкохола. Тачан узрок одређује љекар.', 'Повышение может быть связано с нарушениями работы печени, желчевыводящих путей, приёмом некоторых препаратов или алкоголя. Точную причину определяет врач', 'Ein erhöhter Wert kann mit Leber- oder Gallenwegserkrankungen, bestimmten Medikamenten oder Alkoholkonsum zusammenhängen. Die genaue Ursache wird vom Arzt bestimmt.', 'Yükselme, karaciğer veya safra yolu bozuklukları, belirli ilaçlar ya da alkol kullanımıyla ilişkili olabilir. Kesin nedeni hekim belirler.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'alkaline-phosphatase'), 'Blood test for an enzyme produced mainly by the liver and bone tissue', 'Analiza krvi na enzim koji se stvara pretežno u jetri i koštanom tkivu', 'Анализа крви на ензим који се ствара претежно у јетри и коштаном ткиву', 'Анализ крови на фермент, вырабатываемый преимущественно печенью и костной тканью', 'Bluttest auf ein Enzym, das hauptsächlich von Leber und Knochengewebe gebildet wird', 'Başlıca karaciğer ve kemik dokusu tarafından üretilen bir enzime bakan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Assessment of liver and bile duct function, bone tissue status, part of a general biochemical work-up', 'Procjena rada jetre i žučnih puteva, stanja koštanog tkiva, dio opšteg biohemijskog pregleda', 'Процјена рада јетре и жучних путева, стања коштаног ткива, дио општег биохемијског прегледа', 'Оценка работы печени и желчевыводящих путей, состояния костной ткани, часть общего биохимического обследования', 'Beurteilung der Leber- und Gallenwegsfunktion, des Zustands des Knochengewebes, Teil einer allgemeinen biochemischen Untersuchung', 'Karaciğer ve safra yolları işlevinin, kemik dokusu durumunun değerlendirilmesi, genel biyokimyasal incelemenin bir parçası', 'Preferably fasting', 'Poželjno natašte', 'Пожељно наташте', 'Желательно натощак', 'Vorzugsweise nüchtern', 'Tercihen aç karnına', 'Changes in the level may be related to processes in the liver, bile ducts, or bone tissue. The cause and significance of the result are determined by a doctor.', 'Promjene nivoa mogu biti povezane sa procesima u jetri, žučnim putevima ili koštanom tkivu. Uzrok i značaj rezultata određuje ljekar.', 'Промјене нивоа могу бити повезане са процесима у јетри, жучним путевима или коштаном ткиву. Узрок и значај резултата одређује љекар.', 'Изменения уровня могут быть связаны с процессами в печени, желчевыводящих путях или костной ткани. Причину и значимость результата определяет врач', 'Veränderungen des Werts können mit Vorgängen in der Leber, den Gallenwegen oder im Knochengewebe zusammenhängen. Ursache und Bedeutung des Ergebnisses werden vom Arzt bestimmt.', 'Değerdeki değişiklikler karaciğerde, safra yollarında veya kemik dokusundaki süreçlerle ilişkili olabilir. Nedeni ve sonucun önemini hekim belirler.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'uric-acid'), 'Blood test for the end product of purine metabolism', 'Analiza krvi na krajnji proizvod metabolizma purina', 'Анализа крви на крајњи производ метаболизма пурина', 'Анализ крови на конечный продукт обмена пуринов', 'Bluttest auf das Endprodukt des Purinstoffwechsels', 'Pürin metabolizmasının son ürününe bakan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Assessment of metabolism, joint complaints, monitoring in urolithiasis (kidney stones), monitoring during certain treatments', 'Procjena metabolizma, tegobe u zglobovima, praćenje kod bubrežnih kamenaca, kontrola tokom pojedinih vrsta liječenja', 'Процјена метаболизма, тегобе у зглобовима, праћење код бубрежних каменаца, контрола током појединих врста лијечења', 'Оценка обмена веществ, суставные жалобы, наблюдение при мочекаменной болезни, контроль на фоне некоторых видов лечения', 'Beurteilung des Stoffwechsels, Gelenkbeschwerden, Überwachung bei Nierensteinen (Urolithiasis), Kontrolle im Rahmen bestimmter Behandlungen', 'Metabolizmanın değerlendirilmesi, eklem şikayetleri, böbrek taşı hastalığında izleme, bazı tedaviler sırasında kontrol', 'Preferably fasting; avoid alcohol and heavy meat consumption the day before', 'Poželjno natašte; dan ranije izbjegavati alkohol i obilnu mesnu hranu', 'Пожељно наташте; дан раније избјегавати алкохол и обилну месну храну', 'Желательно натощак; накануне избегать алкоголя и обильной мясной пищи', 'Vorzugsweise nüchtern; am Vortag auf Alkohol und reichhaltige Fleischmahlzeiten verzichten', 'Tercihen aç karnına; bir önceki gün alkolden ve ağır et yemeklerinden kaçınılmalı', 'An elevated level may be related to disorders of purine metabolism, dietary factors, or other processes in the body. The exact cause and significance of the result are determined by a doctor.', 'Povećanje može biti povezano sa poremećajem metabolizma purina, navikama u ishrani ili drugim procesima u organizmu. Tačan uzrok i značaj rezultata određuje ljekar.', 'Повећање може бити повезано са поремећајем метаболизма пурина, навикама у исхрани или другим процесима у организму. Тачан узрок и значај резултата одређује љекар.', 'Повышение может быть связано с нарушением обмена пуринов, особенностями питания или другими процессами в организме. Точную причину и значение результата определяет врач', 'Ein erhöhter Wert kann mit einer Störung des Purinstoffwechsels, Ernährungsgewohnheiten oder anderen Vorgängen im Körper zusammenhängen. Die genaue Ursache und Bedeutung des Ergebnisses werden vom Arzt bestimmt.', 'Yükselme, pürin metabolizması bozukluğu, beslenme alışkanlıkları veya vücuttaki başka süreçlerle ilişkili olabilir. Kesin nedeni ve sonucun anlamını hekim belirler.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'iron'), 'Blood test measuring serum iron levels', 'Analiza krvi na nivo gvožđa u serumu', 'Анализа крви на ниво гвожђа у серуму', 'Анализ крови на содержание железа в сыворотке', 'Bluttest zur Bestimmung des Serumeisenspiegels', 'Serumdaki demir düzeyini ölçen kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Assessment of iron metabolism, investigating the causes of anemia, or monitoring its progress', 'Procjena metabolizma gvožđa, traženje uzroka anemije ili praćenje njenog toka', 'Процјена метаболизма гвожђа, тражење узрока анемије или праћење њеног тока', 'Оценка обмена железа, поиск причин анемии или контроль её динамики', 'Beurteilung des Eisenstoffwechsels, Abklärung der Ursachen einer Anämie oder Verlaufskontrolle', 'Demir metabolizmasının değerlendirilmesi, anemi nedenlerinin araştırılması veya seyrinin izlenmesi', 'Strictly fasting, in the morning; iron supplements should be taken before the test only after consulting a doctor', 'Strogo natašte, ujutru; preparate gvožđa prije analize uzimati samo uz dogovor sa ljekarom', 'Строго наташте, ујутру; препарате гвожђа прије анализе узимати само уз договор са љекаром', 'Строго натощак, утром; препараты железа перед анализом принимать только по согласованию с врачом', 'Streng nüchtern, morgens; Eisenpräparate vor dem Test nur nach Rücksprache mit dem Arzt einnehmen', 'Sabah, kesinlikle aç karnına; demir preparatları test öncesinde ancak hekime danışılarak alınmalıdır', 'Abnormal results may be related to iron deficiency or excess in the body, dietary factors, or other processes. The cause is determined by a doctor.', 'Odstupanja mogu biti povezana sa nedostatkom ili viškom gvožđa u organizmu, navikama u ishrani ili drugim procesima. Uzrok određuje ljekar.', 'Одступања могу бити повезана са недостатком или вишком гвожђа у организму, навикама у исхрани или другим процесима. Узрок одређује љекар.', 'Отклонения могут быть связаны с недостатком или избытком железа в организме, особенностями питания или другими процессами. Причину определяет врач', 'Abweichungen können mit einem Eisenmangel oder -überschuss im Körper, Ernährungsgewohnheiten oder anderen Vorgängen zusammenhängen. Die Ursache wird vom Arzt bestimmt.', 'Sapmalar, vücuttaki demir eksikliği veya fazlalığı, beslenme alışkanlıkları ya da başka süreçlerle ilişkili olabilir. Nedeni hekim belirler.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'complete-blood-count'), 'A basic blood test showing the number and condition of the main blood cells — red blood cells, white blood cells, platelets — and the hemoglobin level', 'Osnovna analiza krvi koja pokazuje broj i stanje glavnih krvnih ćelija — eritrocita, leukocita, trombocita — i nivo hemoglobina', 'Основна анализа крви која показује број и стање главних крвних ћелија — еритроцита, леукоцита, тромбоцита — и ниво хемоглобина', 'Базовый анализ крови, отражающий количество и состояние основных клеток крови — эритроцитов, лейкоцитов, тромбоцитов и уровень гемоглобина', 'Ein grundlegender Bluttest, der die Anzahl und den Zustand der wichtigsten Blutzellen zeigt — rote Blutkörperchen, weiße Blutkörperchen, Blutplättchen — sowie den Hämoglobinwert', 'Kanın temel hücrelerinin — alyuvarlar, akyuvarlar, trombositler — sayısını ve durumunu ile hemoglobin düzeyini gösteren temel kan testi', 'Venous or capillary blood draw', 'Uzimanje venske ili kapilarne krvi', 'Узимање венске или капиларне крви', 'Забор венозной или капиллярной крови', 'Entnahme von venösem oder kapillarem Blut', 'Venöz veya kapiller kan alımı', 'General check-up, health monitoring, monitoring during treatment, work-up for a wide range of complaints', 'Opšti pregled, kontrola zdravstvenog stanja, praćenje tokom liječenja, obrada širokog spektra tegoba', 'Општи преглед, контрола здравственог стања, праћење током лијечења, обрада широког спектра тегоба', 'Общее обследование, контроль состояния здоровья, наблюдение в ходе лечения, обследование при широком круге жалоб', 'Allgemeine Untersuchung, Gesundheitskontrolle, Verlaufskontrolle während einer Behandlung, Abklärung bei einem breiten Spektrum von Beschwerden', 'Genel kontrol, sağlık durumunun izlenmesi, tedavi sırasında takip, geniş bir şikayet yelpazesinde inceleme', 'No special preparation required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerektirmez', 'Abnormal results may be related to infection, inflammation, anemia, blood-forming disorders, or other processes. The result is interpreted by a doctor.', 'Odstupanja pokazatelja mogu biti povezana sa infekcijom, upalom, anemijom, posebnostima stvaranja krvi ili drugim procesima. Tumačenje rezultata vrši ljekar.', 'Одступања показатеља могу бити повезана са инфекцијом, упалом, анемијом, посебностима стварања крви или другим процесима. Тумачење резултата врши љекар.', 'Отклонения показателей могут быть связаны с инфекцией, воспалением, анемией, особенностями кроветворения и другими процессами. Интерпретацию результата проводит врач', 'Abweichende Werte können mit einer Infektion, Entzündung, Anämie, Besonderheiten der Blutbildung oder anderen Vorgängen zusammenhängen. Die Interpretation des Ergebnisses erfolgt durch den Arzt.', 'Değerlerdeki sapmalar enfeksiyon, iltihap, anemi, kan yapımına özgü durumlar veya başka süreçlerle ilişkili olabilir. Sonucun yorumlanması hekim tarafından yapılır.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'erythrocyte-sedimentation-rate'), 'A blood test measuring the erythrocyte sedimentation rate — a non-specific marker of inflammatory processes', 'Analiza krvi koja pokazuje brzinu sedimentacije eritrocita — nespecifičan pokazatelj upalnih procesa', 'Анализа крви која показује брзину седиментације еритроцита — неспецифичан показатељ упалних процеса', 'Анализ крови, отражающий скорость оседания эритроцитов — неспецифический показатель воспалительных процессов', 'Ein Bluttest, der die Blutkörperchensenkungsgeschwindigkeit misst — ein unspezifischer Marker für Entzündungsprozesse', 'Eritrosit çökme hızını gösteren, iltihabi süreçler için özgül olmayan bir belirteç olan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Suspected inflammatory process, monitoring treatment progress, part of a general work-up', 'Sumnja na upalni proces, praćenje toka liječenja, dio opšteg pregleda', 'Сумња на упални процес, праћење тока лијечења, дио општег прегледа', 'Подозрение на воспалительный процесс, контроль динамики лечения, часть общего обследования', 'Verdacht auf einen Entzündungsprozess, Verlaufskontrolle einer Behandlung, Teil einer allgemeinen Untersuchung', 'İltihabi süreç şüphesi, tedavi seyrinin izlenmesi, genel incelemenin bir parçası', 'No special preparation required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerektirmez', 'An elevated result may be related to inflammation, infection, or other processes in the body. The marker is non-specific — the cause is established by a doctor.', 'Povećanje može biti povezano sa upalom, infekcijom ili drugim procesima u organizmu. Pokazatelj je nespecifičan — uzrok utvrđuje ljekar.', 'Повећање може бити повезано са упалом, инфекцијом или другим процесима у организму. Показатељ је неспецифичан — узрок утврђује љекар.', 'Повышение может быть связано с воспалением, инфекцией или другими процессами в организме. Показатель неспецифичен — причину устанавливает врач', 'Ein erhöhter Wert kann mit einer Entzündung, Infektion oder anderen Vorgängen im Körper zusammenhängen. Der Wert ist unspezifisch — die Ursache wird vom Arzt festgestellt.', 'Yükselme, vücuttaki iltihap, enfeksiyon veya başka süreçlerle ilişkili olabilir. Belirteç özgül değildir — nedeni hekim tarafından belirlenir.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'fibrinogen'), 'Blood test for a protein involved in blood clotting', 'Analiza krvi na protein koji učestvuje u zgrušavanju krvi', 'Анализа крви на протеин који учествује у згрушавању крви', 'Анализ крови на белок, участвующий в свёртывании крови', 'Bluttest auf ein Protein, das an der Blutgerinnung beteiligt ist', 'Kan pıhtılaşmasında rol oynayan bir proteine bakan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Assessment of the blood clotting system, pre-operative work-up, monitoring during inflammatory processes', 'Procjena sistema zgrušavanja krvi, pregled prije operacije, kontrola tokom upalnih procesa', 'Процјена система згрушавања крви, преглед прије операције, контрола током упалних процеса', 'Оценка свёртывающей системы крови, обследование перед операцией, контроль при воспалительных процессах', 'Beurteilung des Blutgerinnungssystems, Untersuchung vor einer Operation, Kontrolle bei Entzündungsprozessen', 'Kan pıhtılaşma sisteminin değerlendirilmesi, ameliyat öncesi inceleme, iltihabi süreçlerde kontrol', 'No special preparation required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerektirmez', 'Changes in the level may be related to an inflammatory process, blood clotting disorders, or other factors. The significance of the result is determined by a doctor.', 'Promjene nivoa mogu biti povezane sa upalnim procesom, poremećajima zgrušavanja krvi ili drugim faktorima. Značaj rezultata određuje ljekar.', 'Промјене нивоа могу бити повезане са упалним процесом, поремећајима згрушавања крви или другим факторима. Значај резултата одређује љекар.', 'Изменения уровня могут быть связаны с воспалительным процессом, нарушениями свёртывания крови или другими факторами. Значение результата определяет врач', 'Veränderungen des Werts können mit einem Entzündungsprozess, Blutgerinnungsstörungen oder anderen Faktoren zusammenhängen. Die Bedeutung des Ergebnisses wird vom Arzt bestimmt.', 'Değerdeki değişiklikler iltihabi bir süreç, kan pıhtılaşma bozuklukları veya başka faktörlerle ilişkili olabilir. Sonucun anlamını hekim belirler.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'prothrombin-time-pt-inr'), 'A blood test evaluating one of the indicators of the blood clotting system', 'Analiza krvi koja procjenjuje jedan od pokazatelja sistema zgrušavanja krvi', 'Анализа крви која процјењује један од показатеља система згрушавања крви', 'Анализ крови, оценивающий один из показателей свёртывающей системы крови', 'Ein Bluttest zur Beurteilung eines der Indikatoren des Blutgerinnungssystems', 'Kan pıhtılaşma sisteminin göstergelerinden birini değerlendiren kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Pre-operative work-up, monitoring during anticoagulant therapy, assessment of liver function', 'Pregled prije operacije, kontrola tokom uzimanja antikoagulanasa, procjena funkcije jetre', 'Преглед прије операције, контрола током узимања антикоагуланаса, процјена функције јетре', 'Обследование перед операцией, контроль при приёме антикоагулянтов, оценка функции печени', 'Untersuchung vor einer Operation, Kontrolle bei Einnahme von Antikoagulanzien, Beurteilung der Leberfunktion', 'Ameliyat öncesi inceleme, antikoagülan tedavisi sırasında kontrol, karaciğer fonksiyonunun değerlendirilmesi', 'No special preparation required; the doctor should be informed about any medications being taken', 'Nije potrebna posebna priprema; ljekara je potrebno obavijestiti o lijekovima koje pacijent uzima', 'Није потребна посебна припрема; љекара је потребно обавијестити о лијековима које пацијент узима', 'Специальной подготовки не требуется; врача необходимо предупредить о принимаемых препаратах', 'Keine besondere Vorbereitung erforderlich; der Arzt sollte über eingenommene Medikamente informiert werden', 'Özel bir hazırlık gerektirmez; kullanılan ilaçlar hakkında hekim bilgilendirilmelidir', 'Abnormal results may be related to anticoagulant use, impaired liver function, or other clotting factors. Interpretation is carried out by the treating doctor.', 'Odstupanja mogu biti povezana sa uzimanjem antikoagulanasa, poremećajem rada jetre ili drugim faktorima zgrušavanja. Tumačenje vrši ljekar koji vodi liječenje.', 'Одступања могу бити повезана са узимањем антикоагуланаса, поремећајем рада јетре или другим факторима згрушавања. Тумачење врши љекар који води лијечење.', 'Отклонения могут быть связаны с приёмом антикоагулянтов, нарушением работы печени или другими факторами свёртывания. Интерпретацию проводит лечащий врач', 'Abweichungen können mit der Einnahme von Antikoagulanzien, einer eingeschränkten Leberfunktion oder anderen Gerinnungsfaktoren zusammenhängen. Die Interpretation erfolgt durch den behandelnden Arzt.', 'Sapmalar, antikoagülan kullanımı, karaciğer işlev bozukluğu veya diğer pıhtılaşma faktörleriyle ilişkili olabilir. Yorumlama tedaviyi yürüten hekim tarafından yapılır.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'activated-partial-thromboplastin-time'), 'A blood test evaluating one of the indicators of the blood clotting system', 'Analiza krvi koja procjenjuje jedan od pokazatelja sistema zgrušavanja krvi', 'Анализа крви која процјењује један од показатеља система згрушавања крви', 'Анализ крови, оценивающий один из показателей свёртывающей системы крови', 'Ein Bluttest zur Beurteilung eines der Indikatoren des Blutgerinnungssystems', 'Kan pıhtılaşma sisteminin göstergelerinden birini değerlendiren kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Pre-operative work-up, monitoring during anticoagulant therapy, assessment of the blood clotting system', 'Pregled prije operacije, kontrola tokom antikoagulantne terapije, procjena sistema zgrušavanja krvi', 'Преглед прије операције, контрола током антикоагулантне терапије, процјена система згрушавања крви', 'Обследование перед операцией, контроль при антикоагулянтной терапии, оценка свёртывающей системы крови', 'Untersuchung vor einer Operation, Kontrolle bei einer Therapie mit Antikoagulanzien, Beurteilung des Blutgerinnungssystems', 'Ameliyat öncesi inceleme, antikoagülan tedavisi sırasında kontrol, kan pıhtılaşma sisteminin değerlendirilmesi', 'No special preparation required; the doctor should be informed about any medications being taken', 'Nije potrebna posebna priprema; ljekara je potrebno obavijestiti o lijekovima koje pacijent uzima', 'Није потребна посебна припрема; љекара је потребно обавијестити о лијековима које пацијент узима', 'Специальной подготовки не требуется; врача необходимо предупредить о принимаемых препаратах', 'Keine besondere Vorbereitung erforderlich; der Arzt sollte über eingenommene Medikamente informiert werden', 'Özel bir hazırlık gerektirmez; kullanılan ilaçlar hakkında hekim bilgilendirilmelidir', 'Abnormal results may be related to medications affecting blood clotting or other factors. The cause is determined by a doctor.', 'Odstupanja mogu biti povezana sa uzimanjem lijekova koji utiču na zgrušavanje krvi ili drugim faktorima. Uzrok određuje ljekar.', 'Одступања могу бити повезана са узимањем лијекова који утичу на згрушавање крви или другим факторима. Узрок одређује љекар.', 'Отклонения могут быть связаны с приёмом препаратов, влияющих на свёртывание крови, или другими факторами. Причину определяет врач', 'Abweichungen können mit Medikamenten, die die Blutgerinnung beeinflussen, oder anderen Faktoren zusammenhängen. Die Ursache wird vom Arzt bestimmt.', 'Sapmalar, kan pıhtılaşmasını etkileyen ilaçlar veya başka faktörlerle ilişkili olabilir. Nedeni hekim belirler.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'd-dimer'), 'A blood test for a marker related to blood clot formation and breakdown processes', 'Analiza krvi na pokazatelj povezan sa procesima zgrušavanja i razgrađivanja krvnih ugrušaka', 'Анализа крви на показатељ повезан са процесима згрушавања и разграђивања крвних угрушака', 'Анализ крови на показатель, связанный с процессами свёртывания и растворения тромбов', 'Ein Bluttest auf einen Marker, der mit der Bildung und dem Abbau von Blutgerinnseln zusammenhängt', 'Kan pıhtısı oluşumu ve çözülmesi süreçleriyle ilişkili bir belirtece bakan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Ordered by a doctor when an acute condition related to blood clot formation is suspected, as well as in a number of other situations at the doctor''s discretion', 'Ordinira ljekar kod sumnje na akutno stanje povezano sa stvaranjem krvnih ugrušaka, kao i u nizu drugih situacija po odluci ljekara', 'Ординира љекар код сумње на акутно стање повезано са стварањем крвних угрушака, као и у низу других ситуација по одлуци љекара', 'Назначается врачом при подозрении на острое состояние, связанное с тромбообразованием, а также в ряде других ситуаций по решению врача', 'Wird vom Arzt bei Verdacht auf einen akuten Zustand im Zusammenhang mit Blutgerinnselbildung sowie in einer Reihe anderer Situationen nach ärztlichem Ermessen angeordnet', 'Kan pıhtısı oluşumuyla ilişkili akut bir durumdan şüphelenildiğinde ve hekimin kararına bağlı olarak diğer bazı durumlarda hekim tarafından istenir', 'No special preparation required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerektirmez', 'An elevated result may be related to various conditions, including blood clotting processes, inflammation, recent surgery, or injury. The evaluation of the result and further management are determined by a doctor, often in an emergency care setting.', 'Povećanje može biti povezano sa različitim stanjima, uključujući procese zgrušavanja krvi, upalu, nedavnu operaciju ili povredu. Procjenu rezultata i dalju taktiku određuje ljekar, često u uslovima hitne pomoći.', 'Повећање може бити повезано са различитим стањима, укључујући процесе згрушавања крви, упалу, недавну операцију или повреду. Процјену резултата и даљу тактику одређује љекар, често у условима хитне помоћи.', 'Повышение может быть связано с разными состояниями, включая процессы свёртывания крови, воспаление, недавнюю операцию или травму. Оценку результата и дальнейшую тактику определяет врач, часто в условиях неотложной помощи', 'Ein erhöhter Wert kann mit verschiedenen Zuständen zusammenhängen, einschließlich Blutgerinnungsprozessen, Entzündungen, einer kürzlichen Operation oder Verletzung. Die Bewertung des Ergebnisses und das weitere Vorgehen werden vom Arzt bestimmt, häufig im Rahmen der Notfallversorgung.', 'Yükselme, kan pıhtılaşma süreçleri, iltihap, yakın zamanda geçirilen ameliyat veya yaralanma dahil olmak üzere çeşitli durumlarla ilişkili olabilir. Sonucun değerlendirilmesi ve sonraki yaklaşım, çoğu zaman acil bakım koşullarında, hekim tarafından belirlenir.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'troponin-t-hs'), 'A blood test for a high-sensitivity marker reflecting the condition of the heart muscle', 'Analiza krvi na visokoosjetljivi pokazatelj koji odražava stanje srčanog mišića', 'Анализа крви на високоосјетљиви показатељ који одражава стање срчаног мишића', 'Анализ крови на высокочувствительный маркер, отражающий состояние сердечной мышцы', 'Ein Bluttest auf einen hochsensitiven Marker, der den Zustand des Herzmuskels widerspiegelt', 'Kalp kasının durumunu yansıtan yüksek duyarlılıklı bir belirtece bakan kan testi', 'Venous blood draw, repeated if necessary at an interval determined by the doctor', 'Uzimanje venske krvi, po potrebi se ponavlja u intervalu koji određuje ljekar', 'Узимање венске крви, по потреби се понавља у интервалу који одређује љекар', 'Забор венозной крови, при необходимости выполняется повторно с интервалом по решению врача', 'Entnahme von venösem Blut, bei Bedarf in einem vom Arzt festgelegten Intervall wiederholt', 'Venöz kan alımı; gerekirse hekimin belirlediği aralıkla tekrarlanır', 'Ordered by a doctor when an acute cardiac condition is suspected, often in an emergency care setting', 'Ordinira ljekar kod sumnje na akutno stanje sa strane srca, često u uslovima hitne pomoći', 'Ординира љекар код сумње на акутно стање са стране срца, често у условима хитне помоћи', 'Назначается врачом при подозрении на острое состояние со стороны сердца, часто в условиях неотложной помощи', 'Wird vom Arzt bei Verdacht auf einen akuten Herzzustand angeordnet, häufig im Rahmen der Notfallversorgung', 'Akut bir kalp durumundan şüphelenildiğinde, çoğu zaman acil bakım koşullarında hekim tarafından istenir', 'No special preparation required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerektirmez', 'An elevated result may be related to damage to the heart muscle or other conditions. Interpretation of the result requires urgent evaluation by a doctor, taking the clinical picture into account.', 'Povećanje može biti povezano sa oštećenjem srčanog mišića ili drugim stanjima. Tumačenje rezultata zahtijeva hitnu procjenu ljekara uz uvid u kliničku sliku.', 'Повећање може бити повезано са оштећењем срчаног мишића или другим стањима. Тумачење резултата захтијева хитну процјену љекара уз увид у клиничку слику.', 'Повышение может быть связано с повреждением сердечной мышцы или другими состояниями. Интерпретация результата требует срочной оценки врача с учётом клинической картины', 'Ein erhöhter Wert kann mit einer Schädigung des Herzmuskels oder anderen Zuständen zusammenhängen. Die Interpretation des Ergebnisses erfordert eine dringende ärztliche Beurteilung unter Berücksichtigung des klinischen Bildes.', 'Yükselme, kalp kasında hasar veya başka durumlarla ilişkili olabilir. Sonucun yorumlanması, klinik tablo dikkate alınarak hekim tarafından acil değerlendirme gerektirir.')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'nt-probnp'), 'A blood test for a marker reflecting strain on the heart muscle', 'Analiza krvi na pokazatelj koji odražava opterećenje srčanog mišića', 'Анализа крви на показатељ који одражава оптерећење срчаног мишића', 'Анализ крови на маркер, отражающий нагрузку на сердечную мышцу', 'Ein Bluttest auf einen Marker, der die Belastung des Herzmuskels widerspiegelt', 'Kalp kasındaki yüke işaret eden bir belirtece bakan kan testi', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Venöz kan alımı', 'Ordered by a doctor when heart failure is suspected or to assess cardiac strain, often in an emergency care setting', 'Ordinira ljekar kod sumnje na srčanu insuficijenciju ili radi procjene opterećenja srca, često u uslovima hitne pomoći', 'Ординира љекар код сумње на срчану инсуфицијенцију или ради процјене оптерећења срца, често у условима хитне помоћи', 'Назначается врачом при подозрении на сердечную недостаточность или для оценки нагрузки на сердце, часто в условиях неотложной помощи', 'Wird vom Arzt bei Verdacht auf Herzinsuffizienz oder zur Beurteilung der Herzbelastung angeordnet, häufig im Rahmen der Notfallversorgung', 'Kalp yetmezliğinden şüphelenildiğinde veya kalp üzerindeki yükü değerlendirmek amacıyla, çoğu zaman acil bakım koşullarında hekim tarafından istenir', 'No special preparation required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerektirmez', 'An elevated result may be related to cardiac strain and a number of other conditions. Interpretation of the result and further management are determined by a doctor.', 'Povećanje može biti povezano sa opterećenjem srca i nizom drugih stanja. Tumačenje rezultata i dalju taktiku određuje ljekar.', 'Повећање може бити повезано са оптерећењем срца и низом других стања. Тумачење резултата и даљу тактику одређује љекар.', 'Повышение может быть связано с нагрузкой на сердце и рядом других состояний. Интерпретацию результата и дальнейшую тактику определяет врач', 'Ein erhöhter Wert kann mit einer Herzbelastung und einer Reihe anderer Zustände zusammenhängen. Die Interpretation des Ergebnisses und das weitere Vorgehen werden vom Arzt bestimmt.', 'Yükselme, kalp üzerindeki yük ve bir dizi başka durumla ilişkili olabilir. Sonucun yorumlanması ve sonraki yaklaşım hekim tarafından belirlenir.')
