INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'procalcitonin'), 'Blood test for a protein whose level rises during bacterial infections', 'Analiza krvi na protein čiji nivo raste kod bakterijskih infekcija', 'Анализа крви на протеин чији ниво расте код бактеријских инфекција', 'Анализ крови на белок, уровень которого повышается при бактериальных инфекциях', 'Bluttest auf ein Protein, dessen Wert bei bakteriellen Infektionen ansteigt', 'Bakteriyel enfeksiyonlarda düzeyi yükselen bir protein için kan testi', 'Venous blood draw, takes a few minutes', 'Uzimanje venske krvi, traje nekoliko minuta', 'Узимање венске крви, траје неколико минута', 'Забор венозной крови, занимает несколько минут', 'Entnahme von venösem Blut, dauert einige Minuten', 'Venöz kan alımı, birkaç dakika sürer', 'Assessing the likelihood of a bacterial infection, monitoring during antibiotic therapy, observation during hospital stay', 'Procjena vjerovatnoće bakterijske infekcije, kontrola tokom antibiotske terapije, praćenje tokom bolničkog liječenja', 'Процјена вјероватноће бактеријске инфекције, контрола током антибиотске терапије, праћење током болничког лијечења', 'Оценка вероятности бактериальной инфекции, контроль на фоне антибактериальной терапии, наблюдение в стационаре', 'Einschätzung der Wahrscheinlichkeit einer bakteriellen Infektion, Verlaufskontrolle unter Antibiotikatherapie, Überwachung während eines Krankenhausaufenthalts', 'Bakteriyel enfeksiyon olasılığının değerlendirilmesi, antibiyotik tedavisi sırasında takip, hastanede yatış sırasında izlem', 'No special preparation is required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Es ist keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Changes may be related to an inflammatory process, infection, or other conditions affecting the body. The exact cause and clinical significance of the result are determined by a doctor', 'Promjene mogu biti povezane sa upalnim procesom, infekcijom ili drugim stanjima koja utiču na organizam. Tačan uzrok i klinički značaj rezultata određuje ljekar', 'Промјене могу бити повезане са упалним процесом, инфекцијом или другим стањима која утичу на организам. Тачан узрок и клинички значај резултата одређује љекар', 'Изменения могут быть связаны с воспалительным процессом, инфекцией или другими состояниями, влияющими на организм. Точную причину и клиническое значение результата определяет врач', 'Veränderungen können mit einem Entzündungsprozess, einer Infektion oder anderen den Körper betreffenden Zuständen zusammenhängen. Die genaue Ursache und die klinische Bedeutung des Ergebnisses werden vom Arzt bestimmt', 'Değişiklikler, iltihabi bir süreç, enfeksiyon veya vücudu etkileyen başka durumlarla ilişkili olabilir. Sonucun kesin nedenini ve klinik önemini hekim değerlendirir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'tsh'), 'Blood test for the hormone that regulates thyroid function', 'Analiza krvi na hormon koji reguliše rad štitne žlijezde', 'Анализа крви на хормон који регулише рад штитне жлијезде', 'Анализ крови на гормон, регулирующий работу щитовидной железы', 'Bluttest auf das Hormon, das die Schilddrüsenfunktion reguliert', 'Tiroid bezinin çalışmasını düzenleyen hormon için kan testi', 'Venous blood draw, takes a few minutes', 'Uzimanje venske krvi, traje nekoliko minuta', 'Узимање венске крви, траје неколико минута', 'Забор венозной крови, занимает несколько минут', 'Entnahme von venösem Blut, dauert einige Minuten', 'Venöz kan alımı, birkaç dakika sürer', 'Assessing thyroid function, routine health check-ups, monitoring during hormone therapy, in case of complaints such as weight changes, fatigue, or mood swings', 'Procjena rada štitne žlijezde, redovni sistematski pregledi, kontrola tokom uzimanja hormonske terapije, kod tegoba poput promjene tjelesne težine, umora, promjena raspoloženja', 'Процјена рада штитне жлијезде, редовни систематски прегледи, контрола током узимања хормонске терапије, код тегоба попут промјене тјелесне тежине, умора, промјена расположења', 'Оценка работы щитовидной железы, диспансеризация, контроль на фоне приёма гормональных препаратов, при жалобах на изменения веса, утомляемость, перепады настроения', 'Beurteilung der Schilddrüsenfunktion, Vorsorgeuntersuchungen, Verlaufskontrolle unter Hormontherapie, bei Beschwerden wie Gewichtsveränderungen, Müdigkeit oder Stimmungsschwankungen', 'Tiroid fonksiyonunun değerlendirilmesi, rutin sağlık kontrolleri, hormon tedavisi sırasında izlem, kilo değişiklikleri, yorgunluk veya ruh hali dalgalanmaları gibi şikayetlerde', 'Usually taken on an empty stomach in the morning; specific preparation recommendations should be confirmed with the referring doctor', 'Obično se uzima ujutru našte; konkretne preporuke za pripremu daje ljekar koji je uputio na analizu', 'Обично се узима ујутру наште; конкретне препоруке за припрему даје љекар који је упутио на анализу', 'Обычно сдаётся натощак утром; конкретные рекомендации по подготовке уточняет направивший врач', 'Wird meist morgens nüchtern durchgeführt; konkrete Vorbereitungsempfehlungen gibt der überweisende Arzt', 'Genellikle sabah aç karnına yapılır; hazırlıkla ilgili ayrıntılı öneriler için yönlendiren hekime danışılmalıdır', 'Changes may be related to thyroid function, certain medications, or temporary physiological fluctuations. Interpretation is done by a doctor considering the overall clinical picture', 'Promjene mogu biti povezane sa radom štitne žlijezde, uzimanjem određenih lijekova ili privremenim fiziološkim kolebanjima. Tumačenje vrši ljekar uzimajući u obzir kliničku sliku', 'Промјене могу бити повезане са радом штитне жлијезде, узимањем одређених лијекова или привременим физиолошким колебањима. Тумачење врши љекар узимајући у обзир клиничку слику', 'Изменения могут быть связаны с работой щитовидной железы, приёмом некоторых препаратов или временными физиологическими колебаниями. Интерпретирует врач с учётом клинической картины', 'Veränderungen können mit der Schilddrüsenfunktion, der Einnahme bestimmter Medikamente oder vorübergehenden physiologischen Schwankungen zusammenhängen. Die Interpretation erfolgt durch den Arzt unter Berücksichtigung des klinischen Gesamtbildes', 'Değişiklikler, tiroid bezinin çalışmasıyla, bazı ilaçların kullanımıyla veya geçici fizyolojik dalgalanmalarla ilişkili olabilir. Sonucu klinik tabloyu dikkate alarak hekim yorumlar')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

