INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'cortisol'), 'Blood test for a hormone produced by the adrenal glands that is linked to the body''s stress response', 'Analiza krvi na hormon koji proizvode nadbubrežne žlijezde i koji je povezan sa reakcijom organizma na stres', 'Анализа крви на хормон који производе надбубрежне жлијезде и који је повезан са реакцијом организма на стрес', 'Анализ крови на гормон, вырабатываемый надпочечниками и связанный с реакцией организма на стресс', 'Bluttest auf ein Hormon, das von den Nebennieren produziert wird und mit der Stressreaktion des Körpers zusammenhängt', 'Böbreküstü bezleri tarafından üretilen ve vücudun strese verdiği tepkiyle ilişkili bir hormon için kan testi', 'Venous blood draw, takes a few minutes', 'Uzimanje venske krvi, traje nekoliko minuta', 'Узимање венске крви, траје неколико минута', 'Забор венозной крови, занимает несколько минут', 'Entnahme von venösem Blut, dauert einige Minuten', 'Venöz kan alımı, birkaç dakika sürer', 'Assessing adrenal gland function, in case of suspected metabolic disorders, unexplained weakness, or weight changes', 'Procjena rada nadbubrežnih žlijezda, kod sumnje na poremećaje metabolizma, neobjašnjive slabosti ili promjene tjelesne težine', 'Процјена рада надбубрежних жлијезда, код сумње на поремећаје метаболизма, необјашњиве слабости или промјене тјелесне тежине', 'Оценка работы надпочечников, при подозрении на нарушения обмена веществ, необъяснимой слабости или изменениях веса', 'Beurteilung der Nebennierenfunktion, bei Verdacht auf Stoffwechselstörungen, unerklärlicher Schwäche oder Gewichtsveränderungen', 'Böbreküstü bezi fonksiyonunun değerlendirilmesi, metabolizma bozukluğu şüphesi, açıklanamayan halsizlik veya kilo değişikliklerinde', 'Usually taken in the morning at specific hours, as hormone levels change throughout the day; it is advisable to avoid physical and emotional strain the day before', 'Obično se uzima ujutru u određeno vrijeme, jer se nivo hormona mijenja tokom dana; poželjno je izbjegavati fizičko i emocionalno naprezanje dan ranije', 'Обично се узима ујутру у одређено вријеме, јер се ниво хормона мијења током дана; пожељно је избјегавати физичко и емоционално напрезање дан раније', 'Обычно сдаётся утром в определённые часы, так как уровень гормона меняется в течение суток; желательно избегать физического и эмоционального напряжения накануне', 'Wird meist morgens zu bestimmten Zeiten abgenommen, da der Hormonspiegel im Tagesverlauf schwankt; körperliche und emotionale Belastung am Vortag sollte möglichst vermieden werden', 'Hormon düzeyi gün içinde değiştiği için genellikle sabah belirli saatlerde alınır; bir önceki gün fiziksel ve duygusal gerginlikten kaçınılması önerilir', 'Changes may be related to adrenal gland function, stress levels, the time of day the sample was taken, or certain medications. The exact cause is determined by a doctor', 'Promjene mogu biti povezane sa radom nadbubrežnih žlijezda, nivoom stresa, dobom dana kada je uzet uzorak ili uzimanjem određenih lijekova. Tačan uzrok određuje ljekar', 'Промјене могу бити повезане са радом надбубрежних жлијезда, нивоом стреса, добом дана када је узет узорак или узимањем одређених лијекова. Тачан узрок одређује љекар', 'Изменения могут быть связаны с работой надпочечников, уровнем стресса, временем суток забора или приёмом некоторых препаратов. Точную причину определяет врач', 'Veränderungen können mit der Nebennierenfunktion, dem Stresslevel, der Tageszeit der Entnahme oder der Einnahme bestimmter Medikamente zusammenhängen. Die genaue Ursache wird vom Arzt bestimmt', 'Değişiklikler, böbreküstü bezi fonksiyonuyla, stres düzeyiyle, örneğin alındığı gün saatiyle veya bazı ilaçların kullanımıyla ilişkili olabilir. Kesin nedeni hekim belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'prolactin'), 'Blood test for a pituitary hormone involved in regulating reproductive function', 'Analiza krvi na hormon hipofize koji učestvuje u regulaciji reproduktivne funkcije', 'Анализа крви на хормон хипофизе који учествује у регулацији репродуктивне функције', 'Анализ крови на гормон гипофиза, участвующий в регуляции репродуктивной функции', 'Bluttest auf ein Hypophysenhormon, das an der Regulation der Fortpflanzungsfunktion beteiligt ist', 'Üreme fonksiyonunun düzenlenmesinde rol oynayan bir hipofiz hormonu için kan testi', 'Venous blood draw, takes a few minutes', 'Uzimanje venske krvi, traje nekoliko minuta', 'Узимање венске крви, траје неколико минута', 'Забор венозной крови, занимает несколько минут', 'Entnahme von venösem Blut, dauert einige Minuten', 'Venöz kan alımı, birkaç dakika sürer', 'Assessing causes of menstrual cycle disorders, fertility problems, or complaints related to the breasts', 'Procjena uzroka poremećaja menstrualnog ciklusa, problema sa začećem, kod tegoba u vezi sa dojkama', 'Процјена узрока поремећаја менструалног циклуса, проблема са зачећем, код тегоба у вези са дојкама', 'Оценка причин нарушений менструального цикла, проблем с зачатием, при жалобах со стороны молочных желёз', 'Abklärung von Ursachen für Menstruationsstörungen, Fruchtbarkeitsproblemen oder Beschwerden im Brustbereich', 'Adet döngüsü bozukluklarının, gebe kalma sorunlarının nedenlerinin değerlendirilmesi, meme ile ilgili şikayetlerde', 'It is recommended to avoid physical exertion, sexual intercourse, and stress the day before; the sample is usually taken in a calm state some time after waking up', 'Preporučuje se izbjegavati fizičko naprezanje, seksualni odnos i stres dan ranije; uzorak se obično uzima u mirnom stanju izvjesno vrijeme nakon buđenja', 'Препоручује се избјегавати физичко напрезање, сексуални однос и стрес дан раније; узорак се обично узима у мирном стању извјесно вријеме након буђења', 'Рекомендуется избегать физической нагрузки, полового контакта и стресса накануне; забор обычно проводится в спокойном состоянии через некоторое время после пробуждения', 'Es wird empfohlen, körperliche Anstrengung, Geschlechtsverkehr und Stress am Vortag zu vermeiden; die Probe wird meist in Ruhe einige Zeit nach dem Aufwachen entnommen', 'Bir önceki gün fiziksel efor, cinsel ilişki ve stresten kaçınılması önerilir; örnek genellikle uyandıktan bir süre sonra sakin bir durumda alınır', 'Changes may be related to stress, certain medications, physical exertion before the test, or pituitary function. Interpretation is done by a doctor considering the circumstances of the test', 'Promjene mogu biti povezane sa stresom, uzimanjem određenih lijekova, fizičkim naprezanjem prije uzimanja uzorka ili radom hipofize. Tumačenje vrši ljekar uzimajući u obzir okolnosti u kojima je analiza urađena', 'Промјене могу бити повезане са стресом, узимањем одређених лијекова, физичким напрезањем прије узимања узорка или радом хипофизе. Тумачење врши љекар узимајући у обзир околности у којима је анализа урађена', 'Изменения могут быть связаны со стрессом, приёмом некоторых препаратов, физической нагрузкой перед забором или работой гипофиза. Интерпретирует врач с учётом обстоятельств сдачи анализа', 'Veränderungen können mit Stress, der Einnahme bestimmter Medikamente, körperlicher Anstrengung vor der Blutabnahme oder der Hypophysenfunktion zusammenhängen. Die Interpretation erfolgt durch den Arzt unter Berücksichtigung der Umstände der Testdurchführung', 'Değişiklikler stresle, bazı ilaçların kullanımıyla, örnek alınmadan önceki fiziksel eforla veya hipofiz bezinin çalışmasıyla ilişkili olabilir. Sonucu, testin yapıldığı koşulları dikkate alarak hekim yorumlar')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'testosterone'), 'Blood test for the main male sex hormone', 'Analiza krvi na osnovni muški polni hormon', 'Анализа крви на основни мушки полни хормон', 'Анализ крови на основной мужской половой гормон', 'Bluttest auf das wichtigste männliche Sexualhormon', 'Ana erkek cinsiyet hormonu için kan testi', 'Venous blood draw, takes a few minutes', 'Uzimanje venske krvi, traje nekoliko minuta', 'Узимање венске крви, траје неколико минута', 'Забор венозной крови, занимает несколько минут', 'Entnahme von venösem Blut, dauert einige Minuten', 'Venöz kan alımı, birkaç dakika sürer', 'Assessing hormonal status in cases of reduced libido or fatigue, in men and women with suspected hormonal disorders', 'Procjena hormonskog statusa kod smanjenog libida, umora, kod muškaraca i žena pri sumnji na hormonske poremećaje', 'Процјена хормонског статуса код смањеног либида, умора, код мушкараца и жена при сумњи на хормонске поремећаје', 'Оценка гормонального фона при снижении либидо, утомляемости, у мужчин и женщин при подозрении на гормональные нарушения', 'Beurteilung des Hormonstatus bei vermindertem Libido oder Müdigkeit, bei Männern und Frauen mit Verdacht auf hormonelle Störungen', 'Libido azalması, yorgunluk durumunda hormonal durumun değerlendirilmesi, kadın ve erkeklerde hormonal bozukluk şüphesinde', 'Usually taken in the morning, as hormone levels change throughout the day; specific recommendations should be confirmed with a doctor', 'Obično se uzima ujutru, jer se nivo hormona mijenja tokom dana; konkretne preporuke daje ljekar', 'Обично се узима ујутру, јер се ниво хормона мијења током дана; конкретне препоруке даје љекар', 'Обычно сдаётся утром, так как уровень гормона меняется в течение суток; конкретные рекомендации уточняет врач', 'Wird meist morgens abgenommen, da der Hormonspiegel im Tagesverlauf schwankt; konkrete Empfehlungen gibt der Arzt', 'Hormon düzeyi gün içinde değiştiği için genellikle sabah alınır; ayrıntılı öneriler için hekime danışılmalıdır', 'Changes may be related to hormonal status, age, physical exertion, or certain medications. The exact interpretation is provided by a doctor', 'Promjene mogu biti povezane sa hormonskim statusom, godinama, fizičkim naprezanjem ili uzimanjem određenih lijekova. Tačno tumačenje daje ljekar', 'Промјене могу бити повезане са хормонским статусом, годинама, физичким напрезањем или узимањем одређених лијекова. Тачно тумачење даје љекар', 'Изменения могут быть связаны с гормональным фоном, возрастом, физической нагрузкой или приёмом некоторых препаратов. Точную интерпретацию даёт врач', 'Veränderungen können mit dem Hormonstatus, dem Alter, körperlicher Anstrengung oder der Einnahme bestimmter Medikamente zusammenhängen. Die genaue Interpretation erfolgt durch den Arzt', 'Değişiklikler hormonal durumla, yaşla, fiziksel eforla veya bazı ilaçların kullanımıyla ilişkili olabilir. Kesin yorumu hekim yapar')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'estradiol'), 'Blood test for one of the main female sex hormones', 'Analiza krvi na jedan od osnovnih ženskih polnih hormona', 'Анализа крви на један од основних женских полних хормона', 'Анализ крови на один из основных женских половых гормонов', 'Bluttest auf eines der wichtigsten weiblichen Sexualhormone', 'Ana kadın cinsiyet hormonlarından biri için kan testi', 'Venous blood draw, takes a few minutes', 'Uzimanje venske krvi, traje nekoliko minuta', 'Узимање венске крви, траје неколико минута', 'Забор венозной крови, занимает несколько минут', 'Entnahme von venösem Blut, dauert einige Minuten', 'Venöz kan alımı, birkaç dakika sürer', 'Assessing hormonal status and ovarian function, in cases of menstrual cycle disorders, when planning pregnancy', 'Procjena hormonskog statusa, rada jajnika, kod poremećaja menstrualnog ciklusa, planiranja trudnoće', 'Процјена хормонског статуса, рада јајника, код поремећаја менструалног циклуса, планирања трудноће', 'Оценка гормонального фона, работы яичников, при нарушениях менструального цикла, планировании беременности', 'Beurteilung des Hormonstatus und der Eierstockfunktion, bei Menstruationsstörungen, bei Kinderwunsch', 'Hormonal durumun, yumurtalık fonksiyonunun değerlendirilmesi, adet döngüsü bozukluklarında, hamilelik planlamasında', 'For women of reproductive age, the doctor determines the day of the cycle for the test; otherwise, no special preparation is usually required', 'Kod žena reproduktivne dobi dan ciklusa za uzimanje analize određuje ljekar; osim toga, obično nije potrebna posebna priprema', 'Код жена репродуктивне доби дан циклуса за узимање анализе одређује љекар; осим тога, обично није потребна посебна припрема', 'У женщин репродуктивного возраста день цикла для сдачи анализа определяет врач; помимо этого специальной подготовки обычно не требуется', 'Bei Frauen im gebärfähigen Alter legt der Arzt den Zyklustag für die Untersuchung fest; ansonsten ist in der Regel keine besondere Vorbereitung erforderlich', 'Üreme çağındaki kadınlarda testin yapılacağı döngü günü hekim tarafından belirlenir; bunun dışında genellikle özel bir hazırlık gerekmez', 'Changes may be related to the phase of the menstrual cycle, ovarian function, or the use of hormonal medications. Interpretation is done by a doctor considering age and cycle phase', 'Promjene mogu biti povezane sa fazom menstrualnog ciklusa, radom jajnika ili uzimanjem hormonske terapije. Tumačenje vrši ljekar uzimajući u obzir godine i fazu ciklusa', 'Промјене могу бити повезане са фазом менструалног циклуса, радом јајника или узимањем хормонске терапије. Тумачење врши љекар узимајући у обзир године и фазу циклуса', 'Изменения могут быть связаны с фазой менструального цикла, работой яичников или приёмом гормональных препаратов. Интерпретирует врач с учётом возраста и фазы цикла', 'Veränderungen können mit der Phase des Menstruationszyklus, der Eierstockfunktion oder der Einnahme hormoneller Medikamente zusammenhängen. Die Interpretation erfolgt durch den Arzt unter Berücksichtigung von Alter und Zyklusphase', 'Değişiklikler adet döngüsünün evresiyle, yumurtalık fonksiyonuyla veya hormonal ilaç kullanımıyla ilişkili olabilir. Sonucu, yaş ve döngü evresini dikkate alarak hekim yorumlar')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'vitamin-d-25-oh'), 'Blood test reflecting the body''s vitamin D stores', 'Analiza krvi koja pokazuje zalihe vitamina D u organizmu', 'Анализа крви која показује залихе витамина Д у организму', 'Анализ крови, отражающий запасы витамина D в организме', 'Bluttest, der die Vitamin-D-Speicher des Körpers widerspiegelt', 'Vücuttaki D vitamini depolarını yansıtan kan testi', 'Venous blood draw, takes a few minutes', 'Uzimanje venske krvi, traje nekoliko minuta', 'Узимање венске крви, траје неколико минута', 'Забор венозной крови, занимает несколько минут', 'Entnahme von venösem Blut, dauert einige Minuten', 'Venöz kan alımı, birkaç dakika sürer', 'Assessing vitamin D status, in case of complaints such as bone weakness, hair loss, frequent colds, or routine health check-ups', 'Procjena obezbjeđenosti vitaminom D, kod tegoba poput slabosti koštanog tkiva, opadanja kose, čestih prehlada, redovni sistematski pregledi', 'Процјена обезбјеђености витамином Д, код тегоба попут слабости коштаног ткива, опадања косе, честих прехлада, редовни систематски прегледи', 'Оценка обеспеченности витамином D, при жалобах на слабость костной ткани, выпадение волос, частые простуды, диспансеризация', 'Beurteilung der Vitamin-D-Versorgung, bei Beschwerden wie Knochenschwäche, Haarausfall, häufigen Erkältungen, Vorsorgeuntersuchungen', 'D vitamini düzeyinin değerlendirilmesi, kemik zayıflığı, saç dökülmesi, sık soğuk algınlığı şikayetlerinde, rutin sağlık kontrolleri', 'No special preparation is required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Es ist keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Changes may be related to diet, lack of sunlight exposure, supplement use, or individual absorption factors. The exact cause and the need for any correction are determined by a doctor', 'Promjene mogu biti povezane sa ishranom, nedostatkom sunčeve svjetlosti, uzimanjem dodataka ishrani ili posebnostima usvajanja. Tačan uzrok i potrebu za korekcijom određuje ljekar', 'Промјене могу бити повезане са исхраном, недостатком сунчеве свјетлости, узимањем додатака исхрани или посебностима усвајања. Тачан узрок и потребу за корекцијом одређује љекар', 'Изменения могут быть связаны с питанием, недостатком солнечного света, приёмом добавок или особенностями усвоения. Точную причину и необходимость коррекции определяет врач', 'Veränderungen können mit der Ernährung, mangelnder Sonnenlichtexposition, der Einnahme von Nahrungsergänzungsmitteln oder individuellen Resorptionsfaktoren zusammenhängen. Die genaue Ursache und die Notwendigkeit einer Korrektur werden vom Arzt bestimmt', 'Değişiklikler beslenmeyle, güneş ışığı yetersizliğiyle, takviye kullanımıyla veya emilime ilişkin bireysel özelliklerle ilişkili olabilir. Kesin nedeni ve düzeltme gerekip gerekmediğini hekim belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'vitamin-b12'), 'Blood test for a vitamin essential for blood formation and nervous system function', 'Analiza krvi na vitamin neophodan za stvaranje krvi i rad nervnog sistema', 'Анализа крви на витамин неопходан за стварање крви и рад нервног система', 'Анализ крови на витамин, необходимый для кроветворения и работы нервной системы', 'Bluttest auf ein Vitamin, das für die Blutbildung und die Funktion des Nervensystems notwendig ist', 'Kan yapımı ve sinir sistemi işlevi için gerekli bir vitamin için kan testi', 'Venous blood draw, takes a few minutes', 'Uzimanje venske krvi, traje nekoliko minuta', 'Узимање венске крви, траје неколико минута', 'Забор венозной крови, занимает несколько минут', 'Entnahme von venösem Blut, dauert einige Minuten', 'Venöz kan alımı, birkaç dakika sürer', 'Assessing causes of anemia, increased fatigue, neurological symptoms, or in cases of vegetarian or vegan diets', 'Procjena uzroka anemije, pojačanog umora, neuroloških simptoma, kod vegetarijanske ili veganske ishrane', 'Процјена узрока анемије, појачаног умора, неуролошких симптома, код вегетаријанске или веганске исхране', 'Оценка причин анемии, повышенной утомляемости, неврологических симптомов, при вегетарианском или веганском питании', 'Abklärung von Ursachen für Anämie, erhöhte Müdigkeit, neurologische Symptome, bei vegetarischer oder veganer Ernährung', 'Anemi, artan yorgunluk, nörolojik semptomların nedenlerinin değerlendirilmesi, vejetaryen veya vegan beslenmede', 'It is preferable to take the test on an empty stomach; otherwise, no special preparation is usually required', 'Poželjno je uzimati analizu našte; osim toga, obično nije potrebna posebna priprema', 'Пожељно је узимати анализу наште; осим тога, обично није потребна посебна припрема', 'Желательно сдавать натощак; помимо этого специальной подготовки обычно не требуется', 'Es ist ratsam, die Probe nüchtern abzugeben; ansonsten ist in der Regel keine besondere Vorbereitung erforderlich', 'Testin aç karnına yapılması tercih edilir; bunun dışında genellikle özel bir hazırlık gerekmez', 'Changes may be related to diet, intestinal absorption of the vitamin, certain medications, or the condition of the blood-forming system. The exact cause is determined by a doctor', 'Promjene mogu biti povezane sa ishranom, usvajanjem vitamina u crijevima, uzimanjem određenih lijekova ili stanjem sistema za stvaranje krvi. Tačan uzrok određuje ljekar', 'Промјене могу бити повезане са исхраном, усвајањем витамина у цријевима, узимањем одређених лијекова или стањем система за стварање крви. Тачан узрок одређује љекар', 'Изменения могут быть связаны с питанием, усвоением витамина в кишечнике, приёмом некоторых препаратов или состоянием кроветворной системы. Точную причину определяет врач', 'Veränderungen können mit der Ernährung, der Aufnahme des Vitamins im Darm, der Einnahme bestimmter Medikamente oder dem Zustand des blutbildenden Systems zusammenhängen. Die genaue Ursache wird vom Arzt bestimmt', 'Değişiklikler beslenmeyle, vitaminin bağırsaktan emilimiyle, bazı ilaçların kullanımıyla veya kan yapım sisteminin durumuyla ilişkili olabilir. Kesin nedeni hekim belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

