INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'folic-acid'), 'Blood test measuring serum folic acid (vitamin B9) levels', 'Analiza krvi na nivo folne kiseline (vitamina B9) u serumu', 'Анализа крви на ниво фолне киселине (витамина Б9) у серуму', 'Анализ крови на уровень фолиевой кислоты (витамина B9) в сыворотке', 'Bluttest zur Bestimmung des Folsäurespiegels (Vitamin B9) im Serum', 'Serumdaki folik asit (B9 vitamini) düzeyini ölçen kan testi', 'Blood draw from a vein, takes a few minutes', 'Uzimanje venske krvi iz vene, traje nekoliko minuta', 'Узимање венске крви из вене, траје неколико минута', 'Забор венозной крови из вены, занимает несколько минут', 'Blutentnahme aus einer Vene, dauert wenige Minuten', 'Damardan kan alınması, birkaç dakika sürer', 'Pregnancy planning, anemia, poor or unbalanced diet, monitoring during medication treatment', 'Planiranje trudnoće, anemija, oskudna ili neuravnotežena ishrana, kontrola tokom uzimanja lijekova', 'Планирање трудноће, анемија, оскудна или неуравнотежена исхрана, контрола током узимања лијекова', 'Планирование беременности, анемия, скудное или несбалансированное питание, контроль на фоне приёма препаратов', 'Schwangerschaftsplanung, Anämie, unzureichende oder unausgewogene Ernährung, Kontrolle während einer Medikamenteneinnahme', 'Gebelik planlaması, anemi, yetersiz veya dengesiz beslenme, ilaç tedavisi sırasında takip', 'Fasting for 4–6 hours; the day before, in agreement with your doctor, folic acid supplements should be avoided', 'Natašte 4–6 sati; dan ranije, uz dogovor sa ljekarom, trebalo bi izbjegavati vitaminske dodatke sa folnom kiselinom', 'Наташте 4–6 сати; дан раније, уз договор са љекаром, требало би избјегавати витаминске додатке са фолном киселином', 'Натощак 4–6 часов; за сутки по согласованию с врачом стоит воздержаться от приёма витаминных добавок с фолиевой кислотой', 'Nüchtern seit 4–6 Stunden; am Vortag sollten nach Rücksprache mit dem Arzt keine Folsäure-Präparate eingenommen werden', '4-6 saat aç karnına; testten bir gün önce doktora danışarak folik asit içeren vitamin takviyelerinden kaçınılması önerilir', 'Changes in the level may be related to dietary habits, intestinal absorption, or certain medications. The doctor evaluates the result and decides whether correction is needed', 'Promjene nivoa mogu biti povezane sa navikama u ishrani, apsorpcijom u crijevima ili uzimanjem određenih lijekova. Procjenu rezultata i potrebu za korekcijom određuje ljekar', 'Промјене нивоа могу бити повезане са навикама у исхрани, апсорпцијом у цријевима или узимањем одређених лијекова. Процјену резултата и потребу за корекцијом одређује љекар', 'Изменения уровня могут быть связаны с особенностями питания, всасыванием в кишечнике или приёмом некоторых препаратов. Оценку результата и необходимость коррекции определяет врач', 'Veränderungen des Spiegels können mit Ernährungsgewohnheiten, der Aufnahme im Darm oder bestimmten Medikamenten zusammenhängen. Die Beurteilung des Ergebnisses und die Notwendigkeit einer Korrektur bestimmt der Arzt', 'Düzeydeki değişiklikler beslenme alışkanlıkları, bağırsakta emilim veya bazı ilaçlarla ilişkili olabilir. Sonucun değerlendirilmesi ve düzeltme gerekip gerekmediğine doktor karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

