INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'rheumatoid-factor'), 'Blood test for rheumatoid factor — antibodies checked when evaluating joint conditions', 'Analiza krvi na reumatoidni faktor — antitijela koja se određuju pri pregledu zglobova', 'Анализа крви на реуматоидни фактор — антитијела која се одређују при прегледу зглобова', 'Анализ крови на ревматоидный фактор — антитела, которые определяют при обследовании суставов', 'Bluttest auf den Rheumafaktor — Antikörper, die bei der Untersuchung der Gelenke bestimmt werden', 'Eklemlerin değerlendirilmesinde bakılan romatoid faktör antikorları için kan testi', 'Blood draw from a vein, takes a few minutes', 'Uzimanje venske krvi iz vene, traje nekoliko minuta', 'Узимање венске крви из вене, траје неколико минута', 'Забор венозной крови из вены, занимает несколько минут', 'Blutentnahme aus einer Vene, dauert wenige Minuten', 'Damardan kan alınması, birkaç dakika sürer', 'Joint pain and swelling, morning stiffness, evaluation when an autoimmune condition is suspected', 'Bolovi i otok zglobova, jutarnja ukočenost, pregled pri sumnji na autoimune bolesti', 'Болови и оток зглобова, јутарња укоченост, преглед при сумњи на аутоимуне болести', 'Боли и припухлость суставов, утренняя скованность, обследование при подозрении на аутоиммунные заболевания', 'Gelenkschmerzen und -schwellungen, Morgensteifigkeit, Untersuchung bei Verdacht auf Autoimmunerkrankungen', 'Eklem ağrısı ve şişliği, sabah tutukluğu, otoimmün hastalık şüphesinde değerlendirme', 'No special preparation required; fasting is recommended', 'Nije potrebna posebna priprema, poželjno je doći natašte', 'Није потребна посебна припрема, пожељно је доћи наташте', 'Специальной подготовки не требуется, желательно сдавать натощак', 'Keine besondere Vorbereitung erforderlich, nüchtern wird empfohlen', 'Özel bir hazırlık gerekmez, aç karnına yaptırılması önerilir', 'Changes in the level may be related to autoimmune joint diseases, though they can sometimes occur with other conditions as well. The doctor interprets the result together with the clinical picture', 'Promjene nivoa mogu biti povezane sa autoimunim bolestima zglobova, a ponekad se javljaju i kod drugih stanja. Tumačenje zajedno sa kliničkom slikom vrši ljekar', 'Промјене нивоа могу бити повезане са аутоимуним болестима зглобова, а понекад се јављају и код других стања. Тумачење заједно са клиничком сликом врши љекар', 'Изменения уровня могут быть связаны с аутоиммунными заболеваниями суставов, а иногда встречаются и при других состояниях. Интерпретацию вместе с клинической картиной проводит врач', 'Veränderungen des Spiegels können mit Autoimmunerkrankungen der Gelenke zusammenhängen, treten aber gelegentlich auch bei anderen Zuständen auf. Die Interpretation zusammen mit dem klinischen Bild erfolgt durch den Arzt', 'Düzeydeki değişiklikler eklemlerin otoimmün hastalıklarıyla ilişkili olabilir, bazen başka durumlarda da görülebilir. Klinik tabloyla birlikte yorumlanması doktor tarafından yapılır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'anti-tpo'), 'Blood test for antibodies to thyroid peroxidase (Anti-TPO) — a marker used when evaluating the thyroid gland', 'Analiza krvi na antitijela na tireoperoksidazu (Anti-TPO) — marker koji se koristi pri pregledu štitne žlijezde', 'Анализа крви на антитијела на тиреопероксидазу (Анти-ТПО) — маркер који се користи при прегледу штитне жлијезде', 'Анализ крови на антитела к тиреопероксидазе (Anti-TPO) — маркер, используемый при обследовании щитовидной железы', 'Bluttest auf Antikörper gegen Thyreoperoxidase (Anti-TPO) — ein Marker zur Untersuchung der Schilddrüse', 'Tiroid bezinin değerlendirilmesinde kullanılan tiroid peroksidaz antikorları (Anti-TPO) için kan testi', 'Blood draw from a vein, takes a few minutes', 'Uzimanje venske krvi iz vene, traje nekoliko minuta', 'Узимање венске крви из вене, траје неколико минута', 'Забор венозной крови из вены, занимает несколько минут', 'Blutentnahme aus einer Vene, dauert wenige Minuten', 'Damardan kan alınması, birkaç dakika sürer', 'Evaluation of an enlarged thyroid, changes in hormone levels, pregnancy planning', 'Pregled pri uvećanju štitne žlijezde, promjenama hormonskog statusa, planiranju trudnoće', 'Преглед при увећању штитне жлијезде, промјенама хормонског статуса, планирању трудноће', 'Обследование при увеличении щитовидной железы, изменениях гормонального фона, планировании беременности', 'Untersuchung bei vergrößerter Schilddrüse, Veränderungen des Hormonstatus, Schwangerschaftsplanung', 'Tiroid büyümesi, hormon düzeylerindeki değişiklikler, gebelik planlaması durumunda değerlendirme', 'No special preparation required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'An increased antibody level may be related to autoimmune thyroid involvement. The endocrinologist evaluates the result together with hormone levels and ultrasound', 'Povećanje nivoa antitijela može biti povezano sa autoimunim oštećenjem štitne žlijezde. Procjenu rezultata zajedno sa hormonima i ultrazvukom vrši endokrinolog', 'Повећање нивоа антитијела може бити повезано са аутоимуним оштећењем штитне жлијезде. Процјену резултата заједно са хормонима и ултразвуком врши ендокринолог', 'Повышение уровня антител может быть связано с аутоиммунным поражением щитовидной железы. Оценку результата вместе с гормонами и УЗИ проводит эндокринолог', 'Ein erhöhter Antikörperspiegel kann mit einer Autoimmunerkrankung der Schilddrüse zusammenhängen. Die Beurteilung des Ergebnisses zusammen mit den Hormonwerten und dem Ultraschall erfolgt durch den Endokrinologen', 'Antikor düzeyindeki artış tiroid bezinin otoimmün tutulumuyla ilişkili olabilir. Sonucun hormon düzeyleri ve ultrason ile birlikte değerlendirilmesi endokrinolog tarafından yapılır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'psa'), 'Blood test for prostate-specific antigen (PSA) — an indicator used when evaluating the prostate gland in men', 'Analiza krvi na prostata-specifični antigen (PSA) — pokazatelj koji se koristi pri pregledu prostate kod muškaraca', 'Анализа крви на простата-специфични антиген (PSA) — показатељ који се користи при прегледу простате код мушкараца', 'Анализ крови на простат-специфический антиген (PSA) — показатель, используемый при обследовании простаты у мужчин', 'Bluttest auf prostataspezifisches Antigen (PSA) — ein Wert zur Untersuchung der Prostata bei Männern', 'Erkeklerde prostat bezinin değerlendirilmesinde kullanılan prostata özgü antijen (PSA) için kan testi', 'Blood draw from a vein, takes a few minutes', 'Uzimanje venske krvi iz vene, traje nekoliko minuta', 'Узимање венске крви из вене, траје неколико минута', 'Забор венозной крови из вены, занимает несколько минут', 'Blutentnahme aus einer Vene, dauert wenige Minuten', 'Damardan kan alınması, birkaç dakika sürer', 'Preventive check-up for older men, routine visit to a urologist', 'Preventivni pregled muškaraca starije životne dobi, redovna posjeta urologu', 'Превентивни преглед мушкараца старије животне доби, редовна посјета урологу', 'Профилактическое обследование мужчин старшего возраста, плановый визит к урологу', 'Vorsorgeuntersuchung bei älteren Männern, routinemäßiger Besuch beim Urologen', 'İleri yaştaki erkeklerde koruyucu kontrol, ürolog ile rutin muayene', 'It is recommended to avoid ejaculation and intense physical activity for 24–48 hours beforehand; the sample should be taken before a digital rectal exam or a few days after it', 'Preporučuje se uzdržavanje od ejakulacije i intenzivnog fizičkog napora 24–48 sati ranije; uzorak treba uzeti prije digitorektalnog pregleda ili nekoliko dana poslije njega', 'Препоручује се уздржавање од ејакулације и интензивног физичког напора 24–48 сати раније; узорак треба узети прије дигиторекталног прегледа или неколико дана послије њега', 'Рекомендуется воздержаться от эякуляции и интенсивной физической нагрузки за 24–48 часов; сдавать до пальцевого ректального осмотра или через несколько дней после него', 'Es wird empfohlen, 24–48 Stunden vorher auf Ejakulation und intensive körperliche Belastung zu verzichten; die Blutentnahme sollte vor einer digital-rektalen Untersuchung oder einige Tage danach erfolgen', 'Testten 24-48 saat önce ejakülasyondan ve yoğun fiziksel aktiviteden kaçınılması önerilir; numunenin parmakla rektal muayeneden önce veya birkaç gün sonra alınması gerekir', 'An increase may be related to various conditions of the prostate, including benign ones — the urologist decides on further evaluation', 'Povećanje može biti povezano sa različitim stanjima prostate, uključujući benigna — pitanje daljeg pregleda rješava urolog', 'Повећање може бити повезано са различитим стањима простате, укључујући бенигна — питање даљег прегледа рјешава уролог', 'Повышение может быть связано с разными состояниями простаты, включая доброкачественные — вопрос дальнейшего обследования решает уролог', 'Ein Anstieg kann mit verschiedenen Erkrankungen der Prostata zusammenhängen, einschließlich gutartiger — über die weitere Untersuchung entscheidet der Urologe', 'Yükselme, iyi huylu olanlar dahil olmak üzere prostatın çeşitli durumlarıyla ilişkili olabilir — ileri değerlendirme gerekip gerekmediğine ürolog karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'beta-hcg'), 'Blood test for the beta subunit of human chorionic gonadotropin (Beta hCG) — a hormone produced during pregnancy', 'Analiza krvi na beta-podjedinicu humanog horionskog gonadotropina (Beta HCG) — hormon koji se stvara tokom trudnoće', 'Анализа крви на бета-подјединицу хуманог хорионског гонадотропина (Бета HCG) — хормон који се ствара током трудноће', 'Анализ крови на бета-субъединицу хорионического гонадотропина человека (Beta HCG) — гормон, вырабатываемый при беременности', 'Bluttest auf die Beta-Untereinheit des humanen Choriongonadotropins (Beta-hCG) — ein während der Schwangerschaft gebildetes Hormon', 'Gebelik sırasında üretilen bir hormon olan insan koryonik gonadotropininin beta alt birimi (Beta hCG) için kan testi', 'Blood draw from a vein, takes a few minutes', 'Uzimanje venske krvi iz vene, traje nekoliko minuta', 'Узимање венске крви из вене, траје неколико минута', 'Забор венозной крови из вены, занимает несколько минут', 'Blutentnahme aus einer Vene, dauert wenige Minuten', 'Damardan kan alınması, birkaç dakika sürer', 'Early pregnancy diagnosis, monitoring during the first trimester', 'Dijagnostika rane trudnoće, kontrola u prvom trimestru', 'Дијагностика ране трудноће, контрола у првом триместру', 'Диагностика ранней беременности, контроль в первом триместре', 'Diagnose einer frühen Schwangerschaft, Kontrolle im ersten Trimester', 'Erken gebelik tanısı, ilk trimesterde takip', 'No special preparation required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'The result is interpreted by the doctor over time together with an ultrasound — interpreting a single value on its own does not give the full picture', 'Rezultat tumači ljekar u dinamici zajedno sa ultrazvukom — samostalno tumačenje jedne vrijednosti ne odražava potpunu sliku', 'Резултат тумачи љекар у динамици заједно са ултразвуком — самостално тумачење једне вриједности не одражава потпуну слику', 'Результат интерпретируется врачом в динамике вместе с УЗИ — самостоятельная трактовка одного значения не отражает полной картины', 'Das Ergebnis wird vom Arzt im Verlauf zusammen mit dem Ultraschall interpretiert — die eigenständige Deutung eines einzelnen Werts ergibt kein vollständiges Bild', 'Sonuç, doktor tarafından zaman içindeki seyriyle ve ultrason ile birlikte yorumlanır — tek bir değerin kendi başına yorumlanması tam tabloyu yansıtmaz')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'helicobacter-pylori-antigen-in-feces'), 'Stool test for Helicobacter pylori antigen', 'Test stolice na antigen bakterije Helicobacter pylori', 'Тест столице на антиген бактерије Хелицобацтер пyлори', 'Тест кала на антиген бактерии Helicobacter pylori', 'Stuhltest auf Helicobacter-pylori-Antigen', 'Helicobacter pylori bakterisi antijeni için dışkı testi', 'Collecting a small stool sample in a container at home, then delivering it to the laboratory', 'Uzimanje malog uzorka stolice u kontejner kod kuće, uz naknadnu dostavu u laboratoriju', 'Узимање малог узорка столице у контејнер код куће, уз накнадну доставу у лабораторију', 'Сбор небольшого образца кала в контейнер в домашних условиях с последующей доставкой в лабораторию', 'Zu Hause wird eine kleine Stuhlprobe in einem Behälter gesammelt und anschließend ins Labor gebracht', 'Evde küçük bir dışkı örneğinin kaba alınması ve ardından laboratuvara ulaştırılması', 'Stomach pain, heartburn, evaluation for gastritis or peptic ulcer disease, follow-up after treatment', 'Bolovi u stomaku, žgaravica, pregled pri gastritisu ili čirevima, kontrola poslije liječenja', 'Болови у стомаку, жгаравица, преглед при гастритису или чиревима, контрола послије лијечења', 'Боли в желудке, изжога, обследование при гастрите или язвенной болезни, контроль после лечения', 'Magenschmerzen, Sodbrennen, Untersuchung bei Gastritis oder Magengeschwür, Kontrolle nach der Behandlung', 'Mide ağrısı, mide ekşimesi, gastrit veya peptik ülser değerlendirmesi, tedavi sonrası kontrol', 'Two weeks before the test, in agreement with your doctor, stop antibiotics and acid-suppressing medications; the sample should not contain any traces of urine', 'Dvije sedmice prije testa, uz dogovor sa ljekarom, prekinuti uzimanje antibiotika i lijekova koji smanjuju kiselost; uzorak ne smije sadržati primjese urina', 'Двије седмице прије теста, уз договор са љекаром, прекинути узимање антибиотика и лијекова који смањују киселост; узорак не смије садржати примјесе урина', 'За 2 недели до теста по согласованию с врачом отменить антибиотики и препараты, подавляющие кислотность; образец не должен содержать примесей мочи', 'Zwei Wochen vor dem Test sollten nach Rücksprache mit dem Arzt Antibiotika und säurehemmende Medikamente abgesetzt werden; die Probe darf keine Urinbeimengungen enthalten', 'Testten 2 hafta önce doktora danışarak antibiyotikler ve asit baskılayıcı ilaçların kesilmesi gerekir; numune idrar bulaşığı içermemelidir', 'A positive result may indicate the presence of an infection in the stomach lining. The gastroenterologist determines the further course of action', 'Pozitivan rezultat može biti povezan sa prisustvom infekcije na sluzokoži stomaka. Dalju taktiku određuje ljekar-gastroenterolog', 'Позитиван резултат може бити повезан са присуством инфекције на слузокожи стомака. Даљу тактику одређује љекар-гастроентеролог', 'Положительный результат может быть связан с наличием инфекции в слизистой желудка. Дальнейшую тактику определяет врач-гастроэнтеролог', 'Ein positives Ergebnis kann auf eine Infektion der Magenschleimhaut hinweisen. Das weitere Vorgehen bestimmt der Gastroenterologe', 'Pozitif sonuç, mide mukozasında enfeksiyon varlığıyla ilişkili olabilir. İleri yaklaşımı gastroenterolog belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'papp-a'), 'Pregnancy-associated plasma protein A (PAPP-A) — one of the biochemical markers used in first-trimester prenatal screening', 'Protein plazme povezan sa trudnoćom (PAPP-A) — jedan od biohemijskih markera prenatalnog skrininga prvog trimestra', 'Протеин плазме повезан са трудноћом (ПАПП-А) — један од биохемијских маркера пренаталног скрининга првог триместра', 'Белок плазмы, ассоциированный с беременностью (PAPP-A) — один из биохимических маркеров пренатального скрининга первого триместра', 'Schwangerschaftsassoziiertes Plasmaprotein A (PAPP-A) — einer der biochemischen Marker des pränatalen Screenings im ersten Trimester', 'Gebelikle ilişkili plazma proteini A (PAPP-A) — birinci trimester prenatal taramasının biyokimyasal göstergelerinden biri', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Toplardamardan kan alınması', 'Combined first-trimester screening (usually 11–13 weeks of pregnancy), together with an ultrasound and other markers', 'Kombinovani skrining prvog trimestra trudnoće (obično 11–13 nedjelja), zajedno sa ultrazvukom i drugim pokazateljima', 'Комбиновани скрининг првог триместра трудноће (обично 11–13 недјеља), заједно са ултразвуком и другим показатељима', 'Комбинированный скрининг первого триместра беременности (обычно 11–13 недель) вместе с УЗИ и другими показателями', 'Kombiniertes Ersttrimester-Screening (in der Regel 11.–13. Schwangerschaftswoche), zusammen mit Ultraschall und weiteren Markern', 'Birinci trimester kombine tarama (genellikle 11–13. gebelik haftaları), ultrason ve diğer göstergelerle birlikte', 'No special preparation is usually required', 'Posebna priprema obično nije potrebna', 'Посебна припрема обично није потребна', 'Специальной подготовки обычно не требуется', 'In der Regel keine besondere Vorbereitung erforderlich', 'Genellikle özel bir hazırlık gerekmez', 'The value is assessed by a doctor only together with ultrasound markers, the free beta-hCG level, and gestational age; this test''s result does not diagnose anything on its own and should not be interpreted separately from the other screening markers', 'Vrijednost procjenjuje ljekar isključivo zajedno sa ultrazvučnim markerima, nivoom slobodnog beta-HCG i gestacijskom starošću; rezultat ovog testa sam po sebi ništa ne dijagnostikuje i ne treba ga tumačiti odvojeno od ostalih pokazatelja skrininga', 'Вриједност процјењује љекар искључиво заједно са ултразвучним маркерима, нивоом слободног бета-HCG и гестацијском старошћу; резултат овог теста сам по себи ништа не дијагностикује и не треба га тумачити одвојено од осталих показатеља скрининга', 'Значение оценивается врачом только в комплексе с УЗИ-маркерами, уровнем свободного бета-ХГЧ и сроком беременности; результат этого теста сам по себе ничего не диагностирует и не должен интерпретироваться отдельно от остальных показателей скрининга', 'Der Wert wird vom Arzt nur zusammen mit den Ultraschallmarkern, dem freien Beta-hCG-Spiegel und dem Schwangerschaftsalter beurteilt; das Ergebnis dieses Tests allein diagnostiziert nichts und sollte nicht getrennt von den übrigen Screening-Werten interpretiert werden', 'Değer, yalnızca ultrason bulguları, serbest beta-hCG düzeyi ve gebelik haftası ile birlikte hekim tarafından değerlendirilir; bu testin sonucu tek başına hiçbir şeyi teşhis etmez ve diğer tarama göstergelerinden ayrı yorumlanmamalıdır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO lab_test_reference_info (lab_test_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM lab_tests WHERE slug = 'free-beta-hcg'), 'Free beta subunit of human chorionic gonadotropin — one of the biochemical markers used in first-trimester prenatal screening', 'Slobodna beta-podjedinica humanog horionskog gonadotropina (slobodni beta-HCG) — jedan od biohemijskih markera prenatalnog skrininga prvog trimestra', 'Слободна бета-подјединица хуманог хорионског гонадотропина (слободни бета-HCG) — један од биохемијских маркера пренаталног скрининга првог триместра', 'Свободная бета-субъединица хорионического гонадотропина человека — один из биохимических маркеров пренатального скрининга первого триместра', 'Freie Beta-Untereinheit des humanen Choriongonadotropins — einer der biochemischen Marker des pränatalen Screenings im ersten Trimester', 'İnsan koryonik gonadotropininin serbest beta alt birimi — birinci trimester prenatal taramasının biyokimyasal göstergelerinden biri', 'Venous blood draw', 'Uzimanje venske krvi', 'Узимање венске крви', 'Забор венозной крови', 'Entnahme von venösem Blut', 'Toplardamardan kan alınması', 'Combined first-trimester screening, together with PAPP-A, an ultrasound, and other markers', 'Kombinovani skrining prvog trimestra trudnoće, zajedno sa PAPP-A, ultrazvukom i drugim pokazateljima', 'Комбиновани скрининг првог триместра трудноће, заједно са ПАПП-А, ултразвуком и другим показатељима', 'Комбинированный скрининг первого триместра беременности вместе с PAPP-A, УЗИ и другими показателями', 'Kombiniertes Ersttrimester-Screening, zusammen mit PAPP-A, Ultraschall und weiteren Markern', 'PAPP-A, ultrason ve diğer göstergelerle birlikte birinci trimester kombine tarama', 'No special preparation is usually required', 'Posebna priprema obično nije potrebna', 'Посебна припрема обично није потребна', 'Специальной подготовки обычно не требуется', 'In der Regel keine besondere Vorbereitung erforderlich', 'Genellikle özel bir hazırlık gerekmez', 'The value is assessed by a doctor only together with the other screening markers (PAPP-A, ultrasound findings, gestational age); this test''s result does not diagnose anything on its own', 'Vrijednost procjenjuje ljekar isključivo zajedno sa ostalim pokazateljima skrininga (PAPP-A, ultrazvučni markeri, gestacijska starost); rezultat ovog testa sam po sebi ništa ne dijagnostikuje', 'Вриједност процјењује љекар искључиво заједно са осталим показатељима скрининга (ПАПП-А, ултразвучни маркери, гестацијска старост); резултат овог теста сам по себи ништа не дијагностикује', 'Значение оценивается врачом только в комплексе с остальными показателями скрининга (PAPP-A, УЗИ-маркеры, срок беременности); результат этого теста сам по себе ничего не диагностирует', 'Der Wert wird vom Arzt nur zusammen mit den übrigen Screening-Werten (PAPP-A, Ultraschallbefunde, Schwangerschaftsalter) beurteilt; das Ergebnis dieses Tests allein diagnostiziert nichts', 'Değer, yalnızca diğer tarama göstergeleri (PAPP-A, ultrason bulguları, gebelik haftası) ile birlikte hekim tarafından değerlendirilir; bu testin sonucu tek başına hiçbir şeyi teşhis etmez')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'ecg'), 'A non-invasive recording of the heart''s electrical activity', 'Neinvazivni zapis električne aktivnosti srca', 'Неинвазивни запис електричне активности срца', 'Неинвазивная запись электрической активности сердца', 'Eine nicht-invasive Aufzeichnung der elektrischen Herzaktivität', 'Kalbin elektriksel aktivitesinin invazif olmayan bir şekilde kaydedilmesi', 'The patient lies down, electrodes are attached to the chest and limbs, the recording takes a few minutes and is painless', 'Pacijent leži, na grudi i ekstremitete se postavljaju elektrode, snimanje traje nekoliko minuta i bezbolno je', 'Пацијент лежи, на груди и екстремитете се постављају електроде, снимање траје неколико минута и безболно је', 'Пациент лежит, на грудь и конечности крепятся электроды, запись занимает несколько минут, безболезненно', 'Der Patient liegt, Elektroden werden an Brust und Gliedmaßen angebracht, die Aufzeichnung dauert wenige Minuten und ist schmerzfrei', 'Hasta yatar, göğüs ve uzuvlara elektrotlar takılır, kayıt birkaç dakika sürer ve ağrısızdır', 'Preventive check-up, chest pain/shortness of breath/palpitations, before surgery, routine health screening, sports medicine', 'Preventivni pregled, bol u grudima/otežano disanje/lupanje srca, prije operacija, sistematski pregled, sportska medicina', 'Превентивни преглед, бол у грудима/отежано дисање/лупање срца, прије операција, систематски преглед, спортска медицина', 'Профилактический осмотр, боль в груди/одышка/сердцебиение, перед операциями, диспансеризация, спортивная медицина', 'Vorsorgeuntersuchung, Brustschmerzen/Atemnot/Herzklopfen, vor Operationen, Vorsorgeuntersuchung, Sportmedizin', 'Rutin kontrol, göğüs ağrısı/nefes darlığı/çarpıntı, ameliyat öncesi, genel sağlık kontrolü, spor hekimliği', 'Not required; it is best to arrive in a calm state, without cream on the chest', 'Nije potrebna; poželjno je doći smireno, bez kreme na grudima', 'Није потребна; пожељно је доћи смирено, без креме на грудима', 'Не требуется; желательно прийти в спокойном состоянии, без крема на груди', 'Keine Vorbereitung erforderlich; am besten in Ruhe erscheinen, ohne Creme auf der Brust', 'Özel bir hazırlık gerekmez; sakin bir şekilde ve göğüste krem olmadan gelinmesi önerilir', 'Changes may reflect rhythm or conduction disturbances, or temporary factors (stress, electrode placement). The conclusion and diagnosis are given by a cardiologist', 'Promjene mogu odražavati poremećaje ritma, provodljivosti ili privremene faktore (stres, položaj elektroda). Zaključak i dijagnozu daje ljekar kardiolog', 'Промјене могу одражавати поремећаје ритма, проводљивости или привремене факторе (стрес, положај електрода). Закључак и дијагнозу даје љекар кардиолог', 'Изменения могут отражать нарушения ритма, проводимости или временные факторы (стресс, положение электродов). Заключение и диагноз даёт врач-кардиолог', 'Veränderungen können Rhythmus- oder Erregungsleitungsstörungen oder vorübergehende Faktoren (Stress, Elektrodenposition) widerspiegeln. Die Beurteilung und Diagnose gibt ein Facharzt für Kardiologie', 'Değişiklikler ritim veya ileti bozukluklarını ya da geçici etkenleri (stres, elektrot konumu) yansıtabilir. Değerlendirme ve tanı kardiyoloji uzmanı tarafından konur')
