INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'abdomen-ultrasound'), 'Imaging of the abdominal organs (liver, gallbladder, pancreas, spleen, sometimes kidneys) using ultrasound', 'Prikaz organa trbušne duplje (jetra, žučna kesa, pankreas, slezina, ponekad bubrezi) pomoću ultrazvuka', 'Приказ органа трбушне дупље (јетра, жучна кеса, панкреас, слезина, понекад бубрези) помоћу ултразвука', 'Визуализация органов брюшной полости (печень, желчный пузырь, поджелудочная железа, селезёнка, иногда почки) с помощью ультразвука', 'Bildgebende Darstellung der Bauchorgane (Leber, Gallenblase, Bauchspeicheldrüse, Milz, manchmal Nieren) mittels Ultraschall', 'Ultrason ile karın organlarının (karaciğer, safra kesesi, pankreas, dalak, bazen böbrekler) görüntülenmesi', 'The patient lies down, gel is applied to the skin, the doctor moves the probe over the abdomen; 15–30 minutes, painless', 'Pacijent leži, gel se nanosi na kožu, ljekar pomjera sondu po stomaku; 15–30 minuta, bezbolno', 'Пацијент лежи, гел се наноси на кожу, љекар помјера сонду по стомаку; 15–30 минута, безболно', 'Пациент лежит, на кожу наносится гель, врач перемещает датчик по животу; 15–30 минут, безболезненно', 'Der Patient liegt, Gel wird auf die Haut aufgetragen, der Arzt führt den Schallkopf über den Bauch; 15–30 Minuten, schmerzfrei', 'Hasta yatar, cilde jel uygulanır, doktor probu karın üzerinde gezdirir; 15–30 dakika sürer, ağrısızdır', 'Abdominal pain, preventive check-up, monitoring of chronic gastrointestinal conditions, preparation for surgery', 'Bolovi u stomaku, preventivni pregled, kontrola hroničnih bolesti probavnog trakta, priprema za operaciju', 'Болови у стомаку, превентивни преглед, контрола хроничних болести пробавног тракта, припрема за операцију', 'Боли в животе, профилактический осмотр, контроль хронических заболеваний ЖКТ, подготовка к операции', 'Bauchschmerzen, Vorsorgeuntersuchung, Kontrolle chronischer Magen-Darm-Erkrankungen, Vorbereitung auf eine Operation', 'Karın ağrısı, rutin kontrol, kronik sindirim sistemi hastalıklarının takibi, ameliyat öncesi hazırlık', 'Fasting for 6–8 hours; for 2–3 days beforehand limit foods that cause bloating', 'Natašte 6–8 sati; 2–3 dana ranije ograničiti namirnice koje izazivaju nadutost', 'Наташте 6–8 сати; 2–3 дана раније ограничити намирнице које изазивају надутост', 'Натощак 6–8 часов; за 2–3 дня ограничить продукты, вызывающие газообразование', '6–8 Stunden nüchtern; 2–3 Tage vorher Nahrungsmittel einschränken, die Blähungen verursachen', '6–8 saat aç karnına; işlemden 2–3 gün önce gaz yapan yiyecekler sınırlandırılmalı', 'Findings may reflect structural changes in the organs that require further clarification. The final interpretation and diagnosis are given by a doctor based on the clinical picture', 'Nalazi mogu odražavati strukturne promjene organa koje zahtijevaju dodatno pojašnjenje. Konačnu interpretaciju i dijagnozu daje ljekar uz uvid u kliničku sliku', 'Налази могу одражавати структурне промјене органа које захтијевају додатно појашњење. Коначну интерпретацију и дијагнозу даје љекар уз увид у клиничку слику', 'Находки могут отражать структурные изменения органов, требующие уточнения. Итоговую интерпретацию и диагноз даёт врач с учётом клинической картины', 'Die Befunde können strukturelle Veränderungen der Organe widerspiegeln, die weiter abgeklärt werden müssen. Die endgültige Interpretation und Diagnose gibt der Arzt unter Berücksichtigung des klinischen Bilds', 'Bulgular, organlarda ileri değerlendirme gerektiren yapısal değişikliklere işaret edebilir. Kesin yorum ve tanıyı doktor klinik tabloyu dikkate alarak verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'thyroid-ultrasound'), 'Imaging of the thyroid gland and surrounding neck tissues using ultrasound', 'Prikaz štitne žlijezde i okolnih tkiva vrata pomoću ultrazvuka', 'Приказ штитне жлијезде и околних ткива врата помоћу ултразвука', 'Визуализация щитовидной железы и тканей шеи с помощью ультразвука', 'Bildgebende Darstellung der Schilddrüse und der umliegenden Halsgewebe mittels Ultraschall', 'Ultrason ile tiroid bezinin ve çevresindeki boyun dokularının görüntülenmesi', 'The patient lies with the head tilted back, gel is applied to the neck, the probe is used for 10–15 minutes, painless', 'Pacijent leži sa zabačenom glavom, gel se nanosi na vrat, sonda se koristi 10–15 minuta, bezbolno', 'Пацијент лежи са забаченом главом, гел се наноси на врат, сонда се користи 10–15 минута, безболно', 'Пациент лежит с запрокинутой головой, гель на шею, датчик; 10–15 минут, безболезненно', 'Der Patient liegt mit zurückgelegtem Kopf, Gel wird auf den Hals aufgetragen, der Schallkopf wird 10–15 Minuten verwendet, schmerzfrei', 'Hasta başı geriye yaslanmış şekilde yatar, boyuna jel uygulanır, prob 10–15 dakika kullanılır, ağrısızdır', 'Preventive check-up, palpable nodules, monitoring of previously detected changes, symptoms (weight changes, fatigue)', 'Preventivni pregled, opipljivi čvorovi, kontrola ranije uočenih promjena, simptomi (promjena tjelesne težine, umor)', 'Превентивни преглед, опипљиви чворови, контрола раније уочених промјена, симптоми (промјена тјелесне тежине, умор)', 'Профилактический осмотр, пальпируемые узлы, контроль ранее выявленных изменений, симптомы (изменение веса, утомляемость)', 'Vorsorgeuntersuchung, tastbare Knoten, Kontrolle zuvor festgestellter Veränderungen, Symptome (Gewichtsveränderungen, Müdigkeit)', 'Rutin kontrol, ele gelen nodüller, daha önce saptanan değişikliklerin takibi, semptomlar (kilo değişikliği, yorgunluk)', 'Not required', 'Nije potrebna', 'Није потребна', 'Не требуется', 'Keine Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings (nodules, structural changes) may be benign or require further monitoring. Interpretation and further steps are handled by an endocrinologist', 'Nalazi (čvorovi, promjena strukture) mogu biti benigni ili zahtijevati dalje praćenje. Interpretaciju i taktiku daje ljekar endokrinolog', 'Налази (чворови, промјена структуре) могу бити бенигни или захтијевати даље праћење. Интерпретацију и тактику даје љекар ендокринолог', 'Находки (узлы, изменение структуры) могут быть доброкачественными или требовать дальнейшего наблюдения. Интерпретация и тактика — за врачом-эндокринологом', 'Befunde (Knoten, strukturelle Veränderungen) können gutartig sein oder eine weitere Beobachtung erfordern. Die Interpretation und das weitere Vorgehen legt ein Facharzt für Endokrinologie fest', 'Bulgular (nodüller, yapısal değişiklikler) iyi huylu olabilir veya ileri takip gerektirebilir. Değerlendirme ve sonraki adımlara endokrinolog karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'complete-dental-cleaning'), 'Removal of dental plaque and tartar with polishing of the tooth surface', 'Uklanjanje zubnog plaka i kamenca uz poliranje površine zuba', 'Уклањање зубног плака и каменца уз полирање површине зуба', 'Удаление зубного налёта и камня с полировкой поверхности зубов', 'Entfernung von Zahnbelag und Zahnstein mit Politur der Zahnoberfläche', 'Diş plağının ve taşının temizlenmesi ve diş yüzeyinin parlatılması', 'Ultrasonic/mechanical cleaning, paste polishing, fluoride treatment if needed; 30–60 minutes', 'Ultrazvučno/mehaničko čišćenje, poliranje pastom, po potrebi fluoridacija; 30–60 minuta', 'Ултразвучно/механичко чишћење, полирање пастом, по потреби флуоридација; 30–60 минута', 'Ультразвуковая/механическая чистка, полировка пастой, при необходимости фторирование; 30–60 минут', 'Ultraschall-/mechanische Reinigung, Politur mit Paste, bei Bedarf Fluoridierung; 30–60 Minuten', 'Ultrasonik/mekanik temizlik, macunla parlatma, gerekirse florür uygulaması; 30–60 dakika', 'Prevention (usually 1–2 times a year), preparation for prosthetics/implants, tartar buildup, gum inflammation', 'Prevencija (obično 1–2 puta godišnje), priprema za protetiku/implantaciju, zubni kamenac, upala desni', 'Превенција (обично 1–2 пута годишње), припрема за протетику/имплантацију, зубни каменац, упала десни', 'Профилактика (обычно 1–2 раза в год), подготовка к протезированию/имплантации, зубной камень, воспаление дёсен', 'Vorbeugung (in der Regel 1–2 Mal jährlich), Vorbereitung auf Zahnersatz/Implantate, Zahnstein, Zahnfleischentzündung', 'Önleme (genellikle yılda 1-2 kez), protez/implant hazırlığı, diş taşı, diş eti iltihabı', 'Not required; mention any tooth sensitivity or gum disease', 'Nije potrebna; napomenuti povećanu osjetljivost zuba ili bolesti desni', 'Није потребна; напоменути повећану осјетљивост зуба или болести десни', 'Не требуется; сообщить о повышенной чувствительности зубов или заболеваниях дёсен', 'Keine Vorbereitung erforderlich; erhöhte Zahnempfindlichkeit oder Zahnfleischerkrankungen sollten angegeben werden', 'Özel bir hazırlık gerekmez; diş hassasiyeti veya diş eti hastalığı varsa belirtilmeli', 'Gum bleeding during the procedure may indicate inflammation (gingivitis) — the dentist will give care recommendations', 'Krvarenje desni tokom procedure može ukazivati na upalu (gingivitis) — stomatolog će dati preporuke za njegu', 'Крварење десни током процедуре може указивати на упалу (гингивитис) — стоматолог ће дати препоруке за његу', 'Кровоточивость дёсен во время процедуры может указывать на воспаление (гингивит) — стоматолог даст рекомендации по уходу', 'Zahnfleischbluten während der Behandlung kann auf eine Entzündung (Gingivitis) hinweisen — der Zahnarzt gibt Pflegeempfehlungen', 'İşlem sırasında diş eti kanaması iltihaba (gingivit) işaret edebilir — diş hekimi bakım önerileri verecektir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'spirometry'), 'A lung function test measuring the volume and speed of airflow during breathing', 'Funkcionalni test pluća — mjeri obim i brzinu protoka vazduha pri disanju', 'Функционални тест плућа — мјери обим и брзину протока ваздуха при дисању', 'Функциональный тест лёгких — измеряет объём и скорость воздушного потока при дыхании', 'Ein Lungenfunktionstest, der Volumen und Geschwindigkeit des Luftstroms beim Atmen misst', 'Nefes alıp verirken hava akışının hacmini ve hızını ölçen bir akciğer fonksiyon testi', 'The patient breathes through a mouthpiece into a device following instructions (deep breath, forced exhale), several attempts; 10–15 minutes', 'Pacijent diše kroz usnik u aparat po uputstvu (dubok udah, forsirani izdah), nekoliko pokušaja; 10–15 minuta', 'Пацијент дише кроз усник у апарат по упутству (дубок удах, форсирани издах), неколико покушаја; 10–15 минута', 'Пациент дышит через мундштук в прибор по инструкции (глубокий вдох, форсированный выдох), несколько попыток; 10–15 минут', 'Der Patient atmet nach Anleitung durch ein Mundstück in ein Gerät (tiefes Einatmen, forciertes Ausatmen), mehrere Versuche; 10–15 Minuten', 'Hasta talimatlara uyarak bir ağızlıktan cihaza nefes verir (derin nefes alma, zorlu nefes verme), birkaç deneme yapılır; 10–15 dakika sürer', 'Diagnosis and monitoring of bronchial asthma, COPD, cough/shortness of breath of unclear origin, occupational screening (smokers, hazardous work)', 'Dijagnostika i kontrola bronhijalne astme, HOBP, kašalj/otežano disanje nejasnog porijekla, profesionalni pregled (pušači, štetna proizvodnja)', 'Дијагностика и контрола бронхијалне астме, ХОБП, кашаљ/отежано дисање нејасног поријекла, професионални преглед (пушачи, штетна производња)', 'Диагностика и контроль бронхиальной астмы, ХОБЛ, кашель/одышка неясного происхождения, профосмотр (курильщики, вредное производство)', 'Diagnose und Kontrolle von Asthma bronchiale, COPD, Husten/Atemnot unklarer Ursache, arbeitsmedizinische Untersuchung (Raucher, gefährdende Tätigkeiten)', 'Bronşiyal astım, KOAH tanısı ve takibi, nedeni belirsiz öksürük/nefes darlığı, meslek taraması (sigara içenler, zararlı iş kolları)', 'Do not smoke or use bronchodilators for several hours before the test (as agreed with the doctor); do not eat a heavy meal beforehand; wear loose clothing', 'Ne pušiti i ne koristiti bronhodilatatore nekoliko sati prije testa (uz dogovor sa ljekarom); ne prejesti se prije procedure; nositi udobnu odjeću', 'Не пушити и не користити бронходилататоре неколико сати прије теста (уз договор са љекаром); не прејести се прије процедуре; носити удобну одјећу', 'Не курить и не использовать бронхорасширяющие препараты за несколько часов до теста (по согласованию с врачом); не наедаться перед процедурой; свободная одежда', 'Einige Stunden vor dem Test nicht rauchen und keine Bronchodilatatoren verwenden (nach Absprache mit dem Arzt); vorher keine schwere Mahlzeit einnehmen; lockere Kleidung tragen', 'Testten birkaç saat önce sigara içilmemeli ve bronkodilatör kullanılmamalı (doktora danışılarak); işlemden önce ağır yemek yenmemeli; rahat kıyafet giyilmeli', 'Reduced values may be related to obstructive or restrictive processes in the lungs. The exact diagnosis is made by a pulmonologist based on the test results and clinical picture', 'Smanjene vrijednosti mogu biti povezane sa opstruktivnim ili restriktivnim procesima u plućima. Tačnu dijagnozu postavlja ljekar pulmolog na osnovu rezultata testa i kliničke slike', 'Смањене вриједности могу бити повезане са опструктивним или рестриктивним процесима у плућима. Тачну дијагнозу поставља љекар пулмолог на основу резултата теста и клиничке слике', 'Сниженные показатели могут быть связаны с обструктивными или рестриктивными процессами в лёгких. Точный диагноз ставит врач-пульмонолог по результатам теста и клинической картине', 'Verringerte Werte können mit obstruktiven oder restriktiven Prozessen in der Lunge zusammenhängen. Die genaue Diagnose stellt ein Facharzt für Pneumologie anhand der Testergebnisse und des klinischen Bilds', 'Düşük değerler akciğerdeki obstrüktif veya restriktif süreçlerle ilişkili olabilir. Kesin tanı, test sonuçlarına ve klinik tabloya göre göğüs hastalıkları uzmanı tarafından konur')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'breast-ultrasound'), 'Imaging of breast tissue using ultrasound', 'Prikaz tkiva dojke pomoću ultrazvuka', 'Приказ ткива дојке помоћу ултразвука', 'Визуализация тканей молочной железы с помощью ультразвука', 'Bildgebende Darstellung des Brustgewebes mittels Ultraschall', 'Ultrason ile meme dokusunun görüntülenmesi', 'The patient lies on her back with the arm raised, gel is applied to the skin, the probe is moved over the breast and armpit area; 15–20 minutes, painless', 'Pacijentkinja leži na leđima sa podignutom rukom, gel se nanosi na kožu, sonda se pomjera preko dojke i pazušne regije; 15–20 minuta, bezbolno', 'Пацијенткиња лежи на леђима са подигнутом руком, гел се наноси на кожу, сонда се помјера преко дојке и пазушне регије; 15–20 минута, безболно', 'Пациентка лежит на спине с поднятой рукой, гель на кожу, датчик перемещают по железе и подмышечной области; 15–20 минут, безболезненно', 'Die Patientin liegt auf dem Rücken mit erhobenem Arm, Gel wird auf die Haut aufgetragen, der Schallkopf wird über die Brust und die Achselregion geführt; 15–20 Minuten, schmerzfrei', 'Hasta sırtüstü yatar, kolu yukarı kaldırılır, cilde jel uygulanır, prob meme ve koltuk altı bölgesi üzerinde gezdirilir; 15–20 dakika sürer, ağrısızdır', 'Preventive screening, palpable lumps, complement to mammography, follow-up of previously detected changes, in young women with dense breast tissue', 'Preventivni pregled, opipljivi čvorovi, dopuna mamografiji, kontrola ranije uočenih promjena, kod mladih žena sa gustim tkivom dojke', 'Превентивни преглед, опипљиви чворови, допуна мамографији, контрола раније уочених промјена, код младих жена са густим ткивом дојке', 'Профилактический осмотр, пальпируемые уплотнения, дополнение к маммографии, контроль ранее выявленных изменений, у молодых женщин с плотной тканью железы', 'Vorsorgeuntersuchung, tastbare Knoten, Ergänzung zur Mammographie, Kontrolle zuvor festgestellter Veränderungen, bei jungen Frauen mit dichtem Brustgewebe', 'Rutin kontrol, ele gelen kitleler, mamografiye ek olarak, daha önce saptanan değişikliklerin takibi, meme dokusu yoğun olan genç kadınlarda', 'Not required; best performed in the first half of the menstrual cycle (for women of reproductive age)', 'Nije potrebna; poželjno je uraditi u prvoj polovini menstrualnog ciklusa (za žene reproduktivne dobi)', 'Није потребна; пожељно је урадити у првој половини менструалног циклуса (за жене репродуктивне доби)', 'Не требуется; желательно проводить в первую половину менструального цикла (для женщин репродуктивного возраста)', 'Keine Vorbereitung erforderlich; idealerweise in der ersten Zyklushälfte (bei Frauen im gebärfähigen Alter)', 'Özel bir hazırlık gerekmez; üreme çağındaki kadınlarda adet döngüsünün ilk yarısında yapılması tercih edilir', 'Findings (cysts, nodules) may be benign or require further evaluation. Interpretation and further steps are determined by a breast specialist (mammologist) or oncologist', 'Nalazi (ciste, čvorovi) mogu biti benigni ili zahtijevati dalju obradu. Tumačenje i dalji koraci su u nadležnosti ljekara mamologa ili onkologa', 'Налази (цисте, чворови) могу бити бенигни или захтијевати даљу обраду. Тумачење и даљи кораци су у надлежности љекара мамолога или онколога', 'Находки (кисты, узловые образования) могут быть доброкачественными или требовать дальнейшего обследования. Интерпретация и тактика — за врачом-маммологом или онкологом', 'Befunde (Zysten, Knoten) können gutartig sein oder eine weitere Abklärung erfordern. Die Beurteilung und das weitere Vorgehen legt ein Facharzt für Brusterkrankungen (Mammologe) oder Onkologe fest', 'Bulgular (kistler, nodüller) iyi huylu olabilir veya ileri inceleme gerektirebilir. Değerlendirme ve sonraki adımlara meme hastalıkları uzmanı veya onkolog karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'soft-tissue-ultrasound'), 'Imaging of soft tissues (skin, subcutaneous fat, muscles) using ultrasound', 'Prikaz mekih tkiva (koža, potkožno tkivo, mišići) pomoću ultrazvuka', 'Приказ меких ткива (кожа, поткожно ткиво, мишићи) помоћу ултразвука', 'Визуализация мягких тканей (кожа, подкожная клетчатка, мышцы) с помощью ультразвука', 'Bildgebende Darstellung von Weichteilen (Haut, Unterhautgewebe, Muskeln) mittels Ultraschall', 'Ultrason ile yumuşak dokuların (cilt, ciltaltı doku, kaslar) görüntülenmesi', 'Gel is applied to the area being examined, the probe is moved over the skin above the lump; 10–20 minutes, painless', 'Gel se nanosi na područje pregleda, sonda se pomjera preko kože iznad tvorevine; 10–20 minuta, bezbolno', 'Гел се наноси на подручје прегледа, сонда се помјера преко коже изнад творевине; 10–20 минута, безболно', 'Гель наносится на область осмотра, датчик перемещают по коже над образованием; 10–20 минут, безболезненно', 'Gel wird auf den zu untersuchenden Bereich aufgetragen, der Schallkopf wird über die Haut oberhalb der Veränderung geführt; 10–20 Minuten, schmerzfrei', 'Muayene edilecek bölgeye jel uygulanır, prob kitlenin üzerindeki ciltte gezdirilir; 10–20 dakika sürer, ağrısızdır', 'Palpable lump or mass under the skin, assessment of size and structure (e.g. suspected lipoma or cyst), follow-up over time', 'Opipljivi čvor ili tvorevina ispod kože, procjena veličine i strukture (na primjer kod sumnje na lipom ili cistu), kontrola u vremenu', 'Опипљиви чвор или творевина испод коже, процјена величине и структуре (на примјер код сумње на липом или цисту), контрола у времену', 'Пальпируемое уплотнение или образование под кожей, оценка размера и структуры (например, при подозрении на липому или кисту), контроль в динамике', 'Tastbarer Knoten oder Schwellung unter der Haut, Beurteilung von Größe und Struktur (z. B. bei Verdacht auf Lipom oder Zyste), Verlaufskontrolle', 'Cilt altında ele gelen kitle veya şişlik, boyut ve yapının değerlendirilmesi (örneğin lipom veya kist şüphesinde), zaman içinde takip', 'Not required', 'Nije potrebna', 'Није потребна', 'Не требуется', 'Keine Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings may correspond to benign formations (lipoma, cyst, atheroma) or require further clarification. Conclusion and further steps are determined by a surgeon', 'Nalazi mogu odgovarati benignim tvorevinama (lipom, cista, ateroma) ili zahtijevati dodatno pojašnjenje. Zaključak i dalji koraci su u nadležnosti ljekara hirurga', 'Налази могу одговарати бенигним творевинама (липом, циста, атерома) или захтијевати додатно појашњење. Закључак и даљи кораци су у надлежности љекара хирурга', 'Находки могут соответствовать доброкачественным образованиям (липома, киста, атерома) или требовать уточнения. Заключение и дальнейшую тактику определяет врач-хирург', 'Befunde können gutartigen Veränderungen entsprechen (Lipom, Zyste, Atherom) oder eine weitere Abklärung erfordern. Die Beurteilung und das weitere Vorgehen legt ein Facharzt für Chirurgie fest', 'Bulgular iyi huylu oluşumlara (lipom, kist, aterom) karşılık gelebilir veya ek inceleme gerektirebilir. Değerlendirme ve sonraki adımlara genel cerrahi uzmanı karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'doppler-neck-blood-vessels'), 'Ultrasound examination of the neck blood vessels (carotid and vertebral arteries) with blood flow assessment', 'Ultrazvučni pregled krvnih sudova vrata (karotidnih i vertebralnih arterija) sa procjenom protoka krvi', 'Ултразвучни преглед крвних судова врата (каротидних и вертебралних артерија) са процјеном протока крви', 'Ультразвуковое исследование сосудов шеи (сонных и позвоночных артерий) с оценкой кровотока', 'Ultraschalluntersuchung der Halsgefäße (Karotis- und Vertebralarterien) mit Beurteilung des Blutflusses', 'Boyun kan damarlarının (karotis ve vertebral arterler) kan akışı değerlendirmesiyle birlikte ultrason incelemesi', 'The patient lies with the head slightly tilted back, gel is applied to the neck, the probe is moved along the vessels; 20–30 minutes, painless', 'Pacijent leži sa glavom blago zabačenom unazad, gel se nanosi na vrat, sonda se pomjera duž sudova; 20–30 minuta, bezbolno', 'Пацијент лежи са главом благо забаченом уназад, гел се наноси на врат, сонда се помјера дуж судова; 20–30 минута, безболно', 'Пациент лежит с слегка запрокинутой головой, гель на шею, датчик перемещают вдоль сосудов; 20–30 минут, безболезненно', 'Der Patient liegt mit leicht nach hinten geneigtem Kopf, Gel wird auf den Hals aufgetragen, der Schallkopf wird entlang der Gefäße geführt; 20–30 Minuten, schmerzfrei', 'Hasta başı hafifçe geriye yaslanmış şekilde yatar, boyuna jel uygulanır, prob damarlar boyunca gezdirilir; 20–30 dakika sürer, ağrısızdır', 'Dizziness, tinnitus, suspected vessel narrowing, preventive screening for risk factors (smoking, high cholesterol, age), before certain surgeries', 'Vrtoglavica, zujanje u ušima, sumnja na suženje sudova, preventivni pregled kod faktora rizika (pušenje, povišen holesterol, starost), prije određenih operacija', 'Вртоглавица, зујање у ушима, сумња на сужење судова, превентивни преглед код фактора ризика (пушење, повишен холестерол, старост), прије одређених операција', 'Головокружения, шум в ушах, подозрение на сужение сосудов, профилактический осмотр при факторах риска (курение, повышенный холестерин, возраст), перед некоторыми операциями', 'Schwindel, Ohrgeräusche, Verdacht auf Gefäßverengung, Vorsorgeuntersuchung bei Risikofaktoren (Rauchen, erhöhtes Cholesterin, Alter), vor bestimmten Operationen', 'Baş dönmesi, kulak çınlaması, damar darlığı şüphesi, risk faktörleri (sigara, yüksek kolesterol, yaş) nedeniyle rutin kontrol, bazı ameliyatlar öncesi', 'Not required', 'Nije potrebna', 'Није потребна', 'Не требуется', 'Keine Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings (narrowing of the lumen, changes in blood flow velocity, atherosclerotic plaques) may indicate vessel wall changes of varying severity. Evaluation and recommendations are given by a neurologist or vascular surgeon', 'Nalazi (suženje lumena, promjena brzine protoka krvi, aterosklerotski plakovi) mogu ukazivati na promjene zida krvnog suda različitog stepena. Procjenu i preporuke daje ljekar neurolog ili vaskularni hirurg', 'Налази (сужење лумена, промјена брзине протока крви, атеросклеротски плакови) могу указивати на промјене зида крвног суда различитог степена. Процјену и препоруке даје љекар неуролог или васкуларни хирург', 'Находки (сужение просвета, изменение скорости кровотока, атеросклеротические бляшки) могут указывать на изменения сосудистой стенки разной степени выраженности. Оценку и рекомендации даёт врач-невролог или сосудистый хирург', 'Befunde (Verengung des Gefäßlumens, veränderte Blutflussgeschwindigkeit, arteriosklerotische Plaques) können auf unterschiedlich ausgeprägte Veränderungen der Gefäßwand hinweisen. Die Beurteilung und Empfehlungen gibt ein Facharzt für Neurologie oder Gefäßchirurgie', 'Bulgular (lümen daralması, kan akış hızında değişiklik, aterosklerotik plaklar) damar duvarında farklı derecelerde değişikliklere işaret edebilir. Değerlendirme ve öneriler nörolog veya damar cerrahisi uzmanı tarafından yapılır')
