INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'gynecological-ultrasound'), 'Imaging of the female pelvic organs (uterus, ovaries) using ultrasound', 'Prikaz organa male karlice kod žena (materica, jajnici) pomoću ultrazvuka', 'Приказ органа мале карлице код жена (материца, јајници) помоћу ултразвука', 'Визуализация органов малого таза у женщин (матка, яичники) с помощью ультразвука', 'Bildgebende Darstellung der weiblichen Beckenorgane (Gebärmutter, Eierstöcke) mittels Ultraschall', 'Ultrason ile kadın pelvik organlarının (rahim, yumurtalıklar) görüntülenmesi', 'The examination is performed through the abdominal wall and/or with a transvaginal probe as directed by the doctor; 10–20 minutes, usually painless', 'Pregled se izvodi kroz prednji trbušni zid i/ili transvaginalnom sondom po nalogu ljekara; 10–20 minuta, obično bezbolno', 'Преглед се изводи кроз предњи трбушни зид и/или трансвагиналном сондом по налогу љекара; 10–20 минута, обично безболно', 'Исследование проводится через переднюю брюшную стенку и/или трансвагинальным датчиком по назначению врача; 10–20 минут, обычно безболезненно', 'Die Untersuchung erfolgt durch die Bauchdecke und/oder mit einer transvaginalen Sonde nach ärztlicher Anweisung; 10–20 Minuten, in der Regel schmerzfrei', 'İnceleme, doktorun yönlendirmesine göre karın duvarından ve/veya transvajinal prob ile yapılır; 10–20 dakika sürer, genellikle ağrısızdır', 'Preventive screening, menstrual cycle irregularities, lower abdominal pain, early pregnancy monitoring, pregnancy planning', 'Preventivni pregled, poremećaji menstrualnog ciklusa, bolovi u donjem dijelu trbuha, kontrola trudnoće u ranoj fazi, planiranje trudnoće', 'Превентивни преглед, поремећаји менструалног циклуса, болови у доњем дијелу трбуха, контрола трудноће у раној фази, планирање трудноће', 'Профилактический осмотр, нарушения менструального цикла, боли внизу живота, контроль беременности на ранних сроках, планирование беременности', 'Vorsorgeuntersuchung, Zyklusstörungen, Unterbauchschmerzen, Kontrolle einer Frühschwangerschaft, Schwangerschaftsplanung', 'Rutin kontrol, adet düzensizlikleri, alt karın ağrısı, erken gebelik takibi, gebelik planlaması', 'For abdominal ultrasound – a full bladder; for transvaginal – an empty bladder; specific requirements are best confirmed with the clinic when booking', 'Za abdominalni ultrazvuk potrebna je puna bešika; za transvaginalni prazna bešika; konkretne uslove je najbolje provjeriti u klinici prilikom zakazivanja', 'За абдоминални ултразвук потребна је пуна бешика; за трансвагинални празна бешика; конкретне услове је најбоље провјерити у клиници приликом заказивања', 'Для абдоминального УЗИ — наполненный мочевой пузырь; для трансвагинального — опорожнённый мочевой пузырь; конкретные условия лучше уточнить в клинике при записи', 'Für die abdominale Untersuchung ist eine gefüllte Blase erforderlich; für die transvaginale eine entleerte Blase; die genauen Vorgaben sollten bei der Terminvereinbarung in der Klinik erfragt werden', 'Abdominal ultrason için mesanenin dolu olması gerekir; transvajinal için mesanenin boş olması gerekir; kesin koşullar randevu sırasında klinikle teyit edilmelidir', 'Findings (cysts, fibroids, endometrial changes) may vary in clinical significance. Interpretation and further steps are determined by a gynecologist', 'Nalazi (ciste, miomi, promjene endometrijuma) mogu imati različit klinički značaj. Tumačenje i dalje korake određuje ljekar ginekolog', 'Налази (цисте, миоми, промјене ендометријума) могу имати различит клинички значај. Тумачење и даље кораке одређује љекар гинеколог', 'Находки (кисты, миомы, изменения эндометрия) могут иметь разную клиническую значимость. Интерпретацию и дальнейшую тактику определяет врач-гинеколог', 'Befunde (Zysten, Myome, Veränderungen der Gebärmutterschleimhaut) können unterschiedliche klinische Bedeutung haben. Die Beurteilung und das weitere Vorgehen legt ein Facharzt für Gynäkologie fest', 'Bulgular (kistler, miyomlar, endometriyal değişiklikler) farklı klinik önem taşıyabilir. Değerlendirme ve sonraki adımlara kadın hastalıkları ve doğum uzmanı (jinekolog) karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'doppler-lower-extremity-blood-vessels'), 'Ultrasound examination of the leg veins and/or arteries with blood flow assessment', 'Ultrazvučni pregled vena i/ili arterija nogu sa procjenom protoka krvi', 'Ултразвучни преглед вена и/или артерија ногу са процјеном протока крви', 'Ультразвуковое исследование вен и/или артерий ног с оценкой кровотока', 'Ultraschalluntersuchung der Bein-Venen und/oder -Arterien mit Beurteilung des Blutflusses', 'Bacak venlerinin ve/veya arterlerinin kan akışı değerlendirmesiyle birlikte ultrason incelemesi', 'The patient lies down (sometimes stands – for veins), gel is applied to the skin, the probe is moved along the leg vessels; 20–30 minutes, painless', 'Pacijent leži (ponekad stoji – za vene), gel se nanosi na kožu, sonda se pomjera duž sudova noge; 20–30 minuta, bezbolno', 'Пацијент лежи (понекад стоји – за вене), гел се наноси на кожу, сонда се помјера дуж судова ноге; 20–30 минута, безболно', 'Пациент лежит (иногда стоя — для вен), гель на кожу, датчик перемещают вдоль сосудов ноги; 20–30 минут, безболезненно', 'Der Patient liegt (bei Venen manchmal steht er), Gel wird auf die Haut aufgetragen, der Schallkopf wird entlang der Beingefäße geführt; 20–30 Minuten, schmerzfrei', 'Hasta yatar pozisyonda (venler için bazen ayakta), cilde jel uygulanır, prob bacak damarları boyunca gezdirilir; 20–30 dakika sürer, ağrısızdır', 'Swelling, heaviness and pain in the legs, varicose veins, suspected thrombosis, intermittent claudication, monitoring before/after vascular procedures', 'Otoci, težina i bolovi u nogama, proširene vene, sumnja na trombozu, povremeno šepanje (klaudikacija), kontrola prije/poslije vaskularnih zahvata', 'Отоци, тежина и болови у ногама, проширене вене, сумња на тромбозу, повремено шепање (клаудикација), контрола прије/послије васкуларних захвата', 'Отёки, тяжесть и боли в ногах, варикозное расширение вен, подозрение на тромбоз, перемежающаяся хромота, контроль перед/после сосудистых вмешательств', 'Schwellungen, Schwere- und Schmerzgefühl in den Beinen, Krampfadern, Verdacht auf Thrombose, Schaufensterkrankheit (Claudicatio), Kontrolle vor/nach Gefäßeingriffen', 'Şişlik, bacaklarda ağırlık ve ağrı hissi, varis, tromboz şüphesi, aralıklı topallama (klodikasyo), damar girişimleri öncesi/sonrası kontrol', 'Not required', 'Nije potrebna', 'Није потребна', 'Не требуется', 'Keine Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings (blood clots, valve insufficiency, arterial narrowing) require evaluation in the context of symptoms. Conclusion and further steps are determined by a phlebologist or vascular surgeon', 'Nalazi (trombi, insuficijencija zalistaka, suženje arterija) zahtijevaju procjenu u kontekstu simptoma. Zaključak i dalje korake određuje ljekar flebolog ili vaskularni hirurg', 'Налази (тромби, инсуфицијенција залистака, сужење артерија) захтијевају процјену у контексту симптома. Закључак и даље кораке одређује љекар флеболог или васкуларни хирург', 'Находки (тромбы, клапанная недостаточность, сужение артерий) требуют оценки в контексте симптомов. Заключение и тактику определяет врач-флеболог или сосудистый хирург', 'Befunde (Blutgerinnsel, Klappeninsuffizienz, Arterienverengung) müssen im Zusammenhang mit den Symptomen bewertet werden. Die Beurteilung und das weitere Vorgehen legt ein Facharzt für Phlebologie oder Gefäßchirurgie fest', 'Bulgular (pıhtılar, kapak yetmezliği, arter darlığı) semptomlar bağlamında değerlendirilmelidir. Değerlendirme ve sonraki adımlara fleboloji veya damar cerrahisi uzmanı karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'echocardiography-heart-ultrasound'), 'Imaging of the heart''s structures and function using ultrasound', 'Prikaz struktura i rada srca pomoću ultrazvuka', 'Приказ структура и рада срца помоћу ултразвука', 'Визуализация структур и работы сердца с помощью ультразвука', 'Bildgebende Darstellung der Herzstrukturen und der Herzfunktion mittels Ultraschall', 'Ultrason ile kalp yapılarının ve fonksiyonunun görüntülenmesi', 'The patient lies on the left side, gel is applied to the chest, the probe is placed on the chest in several positions; 20–40 minutes, painless', 'Pacijent leži na lijevom boku, gel se nanosi na grudi, sonda se postavlja na grudni koš u nekoliko položaja; 20–40 minuta, bezbolno', 'Пацијент лежи на лијевом боку, гел се наноси на груди, сонда се поставља на грудни кош у неколико положаја; 20–40 минута, безболно', 'Пациент лежит на левом боку, гель на грудь, датчик прикладывают к грудной клетке в нескольких позициях; 20–40 минут, безболезненно', 'Der Patient liegt auf der linken Seite, Gel wird auf die Brust aufgetragen, der Schallkopf wird in mehreren Positionen auf den Brustkorb aufgesetzt; 20–40 Minuten, schmerzfrei', 'Hasta sol tarafına yatar, göğse jel uygulanır, prob göğüs kafesi üzerinde birkaç farklı konumda tutulur; 20–40 dakika sürer, ağrısızdır', 'Shortness of breath, chest pain, heart murmurs, high blood pressure, monitoring of known heart conditions, preventive screening', 'Otežano disanje, bolovi u grudima, šumovi na srcu, povišen pritisak, kontrola poznatih srčanih oboljenja, preventivni pregled', 'Отежано дисање, болови у грудима, шумови на срцу, повишен притисак, контрола познатих срчаних обољења, превентивни преглед', 'Одышка, боли в груди, шумы в сердце, повышенное давление, контроль известных заболеваний сердца, профилактический осмотр', 'Atemnot, Brustschmerzen, Herzgeräusche, erhöhter Blutdruck, Kontrolle bekannter Herzerkrankungen, Vorsorgeuntersuchung', 'Nefes darlığı, göğüs ağrısı, kalp üfürümü, yüksek tansiyon, bilinen kalp hastalıklarının takibi, rutin kontrol', 'Not required', 'Nije potrebna', 'Није потребна', 'Не требуется', 'Keine Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings (valve changes, chamber size, contractility) may vary in clinical significance. Conclusion and diagnosis are given by a cardiologist', 'Nalazi (promjene na zaliscima, veličina šupljina srca, kontraktilnost) mogu imati različit klinički značaj. Zaključak i dijagnozu daje ljekar kardiolog', 'Налази (промјене на залисцима, величина шупљина срца, контрактилност) могу имати различит клинички значај. Закључак и дијагнозу даје љекар кардиолог', 'Находки (изменения клапанов, размеров камер сердца, сократимости) могут иметь разную клиническую значимость. Заключение и диагноз даёт врач-кардиолог', 'Befunde (Veränderungen der Herzklappen, der Herzkammergröße, der Kontraktilität) können unterschiedliche klinische Bedeutung haben. Die Beurteilung und Diagnose gibt ein Facharzt für Kardiologie', 'Bulgular (kapak değişiklikleri, kalp boşluklarının boyutu, kasılma gücü) farklı klinik önem taşıyabilir. Değerlendirme ve tanı kardiyoloji uzmanı tarafından konur')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'urinary-tract-ultrasound'), 'Imaging of the kidneys and bladder (sometimes the ureters) using ultrasound', 'Prikaz bubrega i bešike (ponekad i mokraćovoda) pomoću ultrazvuka', 'Приказ бубрега и бешике (понекад и мокраћовода) помоћу ултразвука', 'Визуализация почек и мочевого пузыря (иногда мочеточников) с помощью ультразвука', 'Bildgebende Darstellung der Nieren und der Harnblase (manchmal auch der Harnleiter) mittels Ultraschall', 'Ultrason ile böbreklerin ve mesanenin (bazen üreterlerin de) görüntülenmesi', 'The patient lies on the back and/or side, gel is applied to the skin, the probe is moved over the lower back and lower abdomen; 15–20 minutes, painless', 'Pacijent leži na leđima i/ili na boku, gel se nanosi na kožu, sonda se pomjera preko slabinskog predjela i donjeg dijela trbuha; 15–20 minuta, bezbolno', 'Пацијент лежи на леђима и/или на боку, гел се наноси на кожу, сонда се помјера преко слабинског предјела и доњег дијела трбуха; 15–20 минута, безболно', 'Пациент лежит на спине и/или боку, гель на кожу, датчик перемещают по пояснице и низу живота; 15–20 минут, безболезненно', 'Der Patient liegt auf dem Rücken und/oder der Seite, Gel wird auf die Haut aufgetragen, der Schallkopf wird über den unteren Rücken und den Unterbauch geführt; 15–20 Minuten, schmerzfrei', 'Hasta sırtüstü ve/veya yan yatar, cilde jel uygulanır, prob bel ve alt karın bölgesi üzerinde gezdirilir; 15–20 dakika sürer, ağrısızdır', 'Lower back pain, urination disorders, suspected kidney stones, preventive screening, monitoring of chronic kidney conditions', 'Bolovi u slabinama, poremećaji mokrenja, sumnja na bubrežne kamence, preventivni pregled, kontrola hroničnih bubrežnih oboljenja', 'Болови у слабинама, поремећаји мокрења, сумња на бубрежне каменце, превентивни преглед, контрола хроничних бубрежних обољења', 'Боли в пояснице, нарушения мочеиспускания, подозрение на камни в почках, профилактический осмотр, контроль хронических заболеваний почек', 'Rückenschmerzen im unteren Bereich, Miktionsstörungen, Verdacht auf Nierensteine, Vorsorgeuntersuchung, Kontrolle chronischer Nierenerkrankungen', 'Bel ağrısı, idrar yapma bozuklukları, böbrek taşı şüphesi, rutin kontrol, kronik böbrek hastalıklarının takibi', 'For bladder assessment – a full bladder (avoid urinating for 1–2 hours before the procedure)', 'Za procjenu bešike potrebna je puna bešika (ne mokriti 1–2 sata prije pregleda)', 'За процјену бешике потребна је пуна бешика (не мокрити 1–2 сата прије прегледа)', 'Для оценки мочевого пузыря — наполненный мочевой пузырь (не мочиться за 1–2 часа до процедуры)', 'Für die Beurteilung der Blase ist eine gefüllte Blase erforderlich (1–2 Stunden vor der Untersuchung nicht urinieren)', 'Mesane değerlendirmesi için mesanenin dolu olması gerekir (işlemden 1–2 saat önce idrar yapılmamalı)', 'Findings (stones, dilation of the renal collecting system, structural changes) require further clarification. Interpretation and further steps are determined by a urologist or nephrologist', 'Nalazi (kamenci, proširenje sabirnog sistema bubrega, strukturne promjene) zahtijevaju dodatno pojašnjenje. Tumačenje i dalje korake određuje ljekar urolog ili nefrolog', 'Налази (каменци, проширење сабирног система бубрега, структурне промјене) захтијевају додатно појашњење. Тумачење и даље кораке одређује љекар уролог или нефролог', 'Находки (камни, расширение чашечно-лоханочной системы, структурные изменения) требуют уточнения. Интерпретацию и тактику определяет врач-уролог или нефролог', 'Befunde (Steine, Erweiterung des Nierenbeckenkelchsystems, strukturelle Veränderungen) erfordern eine weitere Abklärung. Die Beurteilung und das weitere Vorgehen legt ein Facharzt für Urologie oder Nephrologie fest', 'Bulgular (taşlar, böbrek toplayıcı sisteminde genişleme, yapısal değişiklikler) ek inceleme gerektirir. Değerlendirme ve sonraki adımlara üroloji veya nefroloji uzmanı karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'testicular-ultrasound'), 'Imaging of the scrotum and its organs (testicles, epididymis) using ultrasound', 'Prikaz mošnica i njihovih organa (testisa, pripojaka) pomoću ultrazvuka', 'Приказ мошница и њихових органа (тестиса, припојака) помоћу ултразвука', 'Визуализация мошонки и её органов (яички, придатки) с помощью ультразвука', 'Bildgebende Darstellung des Hodensacks und seiner Organe (Hoden, Nebenhoden) mittels Ultraschall', 'Ultrason ile skrotum ve organlarının (testisler, epididim) görüntülenmesi', 'The patient lies down, gel is applied to the scrotal area, the probe is moved over the surface; 10–15 minutes, painless', 'Pacijent leži, gel se nanosi na predio mošnica, sonda se pomjera po površini; 10–15 minuta, bezbolno', 'Пацијент лежи, гел се наноси на предио мошница, сонда се помјера по површини; 10–15 минута, безболно', 'Пациент лежит, гель наносится на область мошонки, датчик перемещают по поверхности; 10–15 минут, безболезненно', 'Der Patient liegt, Gel wird auf den Hodensackbereich aufgetragen, der Schallkopf wird über die Oberfläche geführt; 10–15 Minuten, schmerzfrei', 'Hasta yatar pozisyonda, skrotum bölgesine jel uygulanır, prob yüzey üzerinde gezdirilir; 10–15 dakika sürer, ağrısızdır', 'Pain or lumps in the scrotum, injury, preventive screening, infertility evaluation, monitoring of previously detected changes', 'Bolovi ili čvorovi u mošnicama, povreda, preventivni pregled, dijagnostika neplodnosti, kontrola ranije uočenih promjena', 'Болови или чворови у мошницама, повреда, превентивни преглед, дијагностика неплодности, контрола раније уочених промјена', 'Боли или уплотнения в мошонке, травма, профилактический осмотр, диагностика бесплодия, контроль ранее выявленных изменений', 'Schmerzen oder Knoten im Hodensack, Verletzung, Vorsorgeuntersuchung, Abklärung bei Unfruchtbarkeit, Kontrolle zuvor festgestellter Veränderungen', 'Skrotumda ağrı veya kitle, travma, rutin kontrol, kısırlık değerlendirmesi, daha önce saptanan değişikliklerin takibi', 'Not required', 'Nije potrebna', 'Није потребна', 'Не требуется', 'Keine Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings (cysts, structural changes, varicocele) may vary in clinical significance. Conclusion and further steps are determined by a urologist', 'Nalazi (ciste, strukturne promjene, varikokela) mogu imati različit klinički značaj. Zaključak i dalje korake određuje ljekar urolog', 'Налази (цисте, структурне промјене, варикокела) могу имати различит клинички значај. Закључак и даље кораке одређује љекар уролог', 'Находки (кисты, изменения структуры, варикоцеле) могут иметь разную клиническую значимость. Заключение и тактику определяет врач-уролог', 'Befunde (Zysten, strukturelle Veränderungen, Varikozele) können unterschiedliche klinische Bedeutung haben. Die Beurteilung und das weitere Vorgehen legt ein Facharzt für Urologie fest', 'Bulgular (kistler, yapısal değişiklikler, varikosel) farklı klinik önem taşıyabilir. Değerlendirme ve sonraki adımlara üroloji uzmanı karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'neck-ultrasound'), 'Imaging of the neck''s soft tissues (lymph nodes, salivary glands and other structures besides the thyroid) using ultrasound', 'Prikaz mekih tkiva vrata (limfni čvorovi, pljuvačne žlijezde i druge strukture osim štitne žlijezde) pomoću ultrazvuka', 'Приказ меких ткива врата (лимфни чворови, пљувачне жлијезде и друге структуре осим штитне жлијезде) помоћу ултразвука', 'Визуализация мягких тканей шеи (лимфоузлы, слюнные железы и другие структуры помимо щитовидной железы) с помощью ультразвука', 'Bildgebende Darstellung der Halsweichteile (Lymphknoten, Speicheldrüsen und andere Strukturen außer der Schilddrüse) mittels Ultraschall', 'Ultrason ile boyun yumuşak dokularının (lenf düğümleri, tükürük bezleri ve tiroid dışındaki diğer yapılar) görüntülenmesi', 'The patient lies with the head slightly tilted back, gel is applied to the neck skin, the probe is moved over the area being examined; 15–20 minutes, painless', 'Pacijent leži sa glavom blago zabačenom unazad, gel se nanosi na kožu vrata, sonda se pomjera preko područja koje se pregleda; 15–20 minuta, bezbolno', 'Пацијент лежи са главом благо забаченом уназад, гел се наноси на кожу врата, сонда се помјера преко подручја које се прегледа; 15–20 минута, безболно', 'Пациент лежит с слегка запрокинутой головой, гель на кожу шеи, датчик перемещают по исследуемой области; 15–20 минут, безболезненно', 'Der Patient liegt mit leicht nach hinten geneigtem Kopf, Gel wird auf die Halshaut aufgetragen, der Schallkopf wird über den zu untersuchenden Bereich geführt; 15–20 Minuten, schmerzfrei', 'Hasta başı hafifçe geriye yaslanmış şekilde yatar, boyun cildine jel uygulanır, prob incelenen bölge üzerinde gezdirilir; 15–20 dakika sürer, ağrısızdır', 'Enlarged or palpable lymph nodes, lumps in the neck, salivary gland inflammation, monitoring of changes over time', 'Uvećani ili opipljivi limfni čvorovi, čvorovi na vratu, upala pljuvačnih žlijezda, kontrola promjena u vremenu', 'Увећани или опипљиви лимфни чворови, чворови на врату, упала пљувачних жлијезда, контрола промјена у времену', 'Увеличенные или пальпируемые лимфоузлы, уплотнения на шее, воспаление слюнных желёз, контроль изменений в динамике', 'Vergrößerte oder tastbare Lymphknoten, Schwellungen am Hals, Entzündung der Speicheldrüsen, Verlaufskontrolle', 'Büyümüş veya ele gelen lenf düğümleri, boyunda şişlikler, tükürük bezi iltihabı, zaman içinde değişikliklerin takibi', 'Not required', 'Nije potrebna', 'Није потребна', 'Не требуется', 'Keine Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings (enlarged lymph nodes, tissue structure changes) may be related to inflammatory or other processes. Conclusion is given by the relevant specialist (surgeon, ENT specialist) based on the clinical picture', 'Nalazi (uvećanje limfnih čvorova, promjena strukture tkiva) mogu biti povezani sa upalnim ili drugim procesima. Zaključak daje ljekar odgovarajuće specijalnosti (hirurg, otorinolaringolog) na osnovu kliničke slike', 'Налази (увећање лимфних чворова, промјена структуре ткива) могу бити повезани са упалним или другим процесима. Закључак даје љекар одговарајуће специјалности (хирург, оториноларинголог) на основу клиничке слике', 'Находки (увеличение лимфоузлов, изменение структуры тканей) могут быть связаны с воспалительными или иными процессами. Заключение даёт врач по профилю (хирург, отоларинголог) с учётом клинической картины', 'Befunde (vergrößerte Lymphknoten, veränderte Gewebestruktur) können mit entzündlichen oder anderen Prozessen zusammenhängen. Die Beurteilung gibt der zuständige Facharzt (Chirurg, HNO-Arzt) unter Berücksichtigung des klinischen Bildes', 'Bulgular (lenf düğümü büyümesi, doku yapısında değişiklik) iltihabi veya başka süreçlerle ilişkili olabilir. Değerlendirme, klinik tabloya göre ilgili uzman hekim (genel cerrah, KBB uzmanı) tarafından yapılır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'musculoskeletal-ultrasound'), 'Imaging of muscles, tendons, ligaments and joints using ultrasound', 'Prikaz mišića, tetiva, ligamenata i zglobova pomoću ultrazvuka', 'Приказ мишића, тетива, лигамената и зглобова помоћу ултразвука', 'Визуализация мышц, сухожилий, связок и суставов с помощью ультразвука', 'Bildgebende Darstellung von Muskeln, Sehnen, Bändern und Gelenken mittels Ultraschall', 'Ultrason ile kasların, tendonların, bağların ve eklemlerin görüntülenmesi', 'Gel is applied to the area being examined, the probe is moved over the skin above the joint or muscle, sometimes with movement of the limb; 15–30 minutes, painless', 'Gel se nanosi na područje pregleda, sonda se pomjera po koži iznad zgloba ili mišića, ponekad uz pokret ekstremiteta; 15–30 minuta, bezbolno', 'Гел се наноси на подручје прегледа, сонда се помјера по кожи изнад зглоба или мишића, понекад уз покрет екстремитета; 15–30 минута, безболно', 'Гель наносится на область осмотра, датчик перемещают по коже над суставом или мышцей, иногда с движением конечности; 15–30 минут, безболезненно', 'Gel wird auf den zu untersuchenden Bereich aufgetragen, der Schallkopf wird über die Haut oberhalb des Gelenks oder Muskels geführt, manchmal mit Bewegung der Gliedmaße; 15–30 Minuten, schmerzfrei', 'Muayene edilecek bölgeye jel uygulanır, prob eklem veya kas üzerindeki ciltte gezdirilir, bazen uzuv hareket ettirilerek; 15–30 dakika sürer, ağrısızdır', 'Joint or muscle pain, injuries, tendon inflammation, monitoring after injury or surgery, sports medicine', 'Bolovi u zglobovima ili mišićima, povrede, upala tetiva, kontrola nakon povrede ili operacije, sportska medicina', 'Болови у зглобовима или мишићима, повреде, упала тетива, контрола након повреде или операције, спортска медицина', 'Боли в суставах или мышцах, травмы, воспаление сухожилий, контроль после травмы или операции, спортивная медицина', 'Gelenk- oder Muskelschmerzen, Verletzungen, Sehnenentzündungen, Kontrolle nach Verletzung oder Operation, Sportmedizin', 'Eklem veya kas ağrısı, travmalar, tendon iltihabı, travma veya ameliyat sonrası takip, spor hekimliği', 'Not required', 'Nije potrebna', 'Није потребна', 'Не требуется', 'Keine Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings (inflammation, tears, fluid accumulation) require correlation with symptoms. Conclusion and further steps are determined by an orthopedist or trauma specialist', 'Nalazi (upala, rupture, nakupljanje tečnosti) zahtijevaju upoređivanje sa simptomima. Zaključak i dalje korake određuje ljekar ortoped ili traumatolog', 'Налази (упала, руптуре, накупљање течности) захтијевају упоређивање са симптомима. Закључак и даље кораке одређује љекар ортопед или трауматолог', 'Находки (воспаление, разрывы, скопление жидкости) требуют сопоставления с симптомами. Заключение и тактику определяет врач-ортопед или травматолог', 'Befunde (Entzündungen, Risse, Flüssigkeitsansammlungen) müssen mit den Symptomen abgeglichen werden. Die Beurteilung und das weitere Vorgehen legt ein Facharzt für Orthopädie oder Unfallchirurgie fest', 'Bulgular (iltihap, yırtıklar, sıvı birikimi) semptomlarla karşılaştırılarak değerlendirilmelidir. Değerlendirme ve sonraki adımlara ortopedi veya travmatoloji uzmanı karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'holter-ecg-24h'), '24-hour recording of the heart''s electrical activity using a portable device', 'Dvadesetčetvoročasovni zapis električne aktivnosti srca prenosivim uređajem', 'Двадесетчетворочасовни запис електричне активности срца преносивим уређајем', 'Суточная запись электрической активности сердца портативным прибором', '24-Stunden-Aufzeichnung der elektrischen Herzaktivität mittels tragbarem Gerät', 'Taşınabilir bir cihazla kalbin elektriksel aktivitesinin 24 saat boyunca kaydedilmesi', 'Electrodes connected to a small recorder are attached to the chest; the patient wears the device for 24 hours (sometimes longer) during their normal daily routine, noting activity and symptoms in a diary', 'Na grudi se postavljaju elektrode povezane sa malim uređajem za snimanje koji pacijent nosi 24 sata (ponekad i duže) tokom uobičajenih dnevnih aktivnosti, bilježeći aktivnosti i simptome u dnevnik', 'На груди се постављају електроде повезане са малим уређајем за снимање који пацијент носи 24 сата (понекад и дуже) током уобичајених дневних активности, биљежећи активности и симптоме у дневник', 'На грудь крепятся электроды, подключённые к небольшому регистратору, который пациент носит на себе 24 часа (иногда дольше) в обычном режиме дня, отмечая активность и симптомы в дневнике', 'Elektroden, die mit einem kleinen Aufzeichnungsgerät verbunden sind, werden auf die Brust geklebt; der Patient trägt das Gerät 24 Stunden (manchmal länger) während seines gewohnten Tagesablaufs und notiert Aktivitäten und Symptome in einem Tagebuch', 'Küçük bir kayıt cihazına bağlı elektrotlar göğse yerleştirilir; hasta cihazı normal günlük yaşamı sırasında 24 saat (bazen daha uzun) takar ve aktivitelerini/semptomlarını bir günlüğe not eder', 'Episodic palpitations or irregular heartbeat, unexplained fainting or dizziness, monitoring the effectiveness of arrhythmia treatment', 'Povremeno lupanje srca ili nepravilan rad srca, neobjašnjiva nesvjestica ili vrtoglavica, kontrola djelotvornosti liječenja poremećaja ritma', 'Повремено лупање срца или неправилан рад срца, необјашњива несвјестица или вртоглавица, контрола дјелотворности лијечења поремећаја ритма', 'Периодическое сердцебиение или перебои в работе сердца, необъяснимые обмороки или головокружения, контроль эффективности лечения нарушений ритма', 'Episodisches Herzklopfen oder unregelmäßiger Herzschlag, unerklärliche Ohnmacht oder Schwindel, Kontrolle der Wirksamkeit einer Behandlung von Rhythmusstörungen', 'Aralıklı çarpıntı veya düzensiz kalp atışı, açıklanamayan bayılma veya baş dönmesi, ritim bozukluğu tedavisinin etkinliğinin takibi', 'Not required; it is advisable to shower before the device is fitted, as the electrodes must not get wet while worn', 'Nije potrebna; poželjno je istuširati se prije postavljanja uređaja, jer se elektrode ne smiju kvasiti tokom nošenja', 'Није потребна; пожељно је истуширати се прије постављања уређаја, јер се електроде не смију квасити током ношења', 'Не требуется; желательно принять душ перед установкой прибора, так как мочить электроды во время ношения нельзя', 'Keine Vorbereitung erforderlich; es empfiehlt sich, vor dem Anlegen des Geräts zu duschen, da die Elektroden während des Tragens nicht nass werden dürfen', 'Özel bir hazırlık gerekmez; cihaz takılmadan önce duş almak faydalıdır, çünkü elektrotlar takılı olduğu sürece ıslatılmamalıdır', 'Recorded episodes of rhythm or conduction disturbances are assessed against the symptom diary. Conclusion and diagnosis are given by a cardiologist', 'Zabilježene epizode poremećaja ritma ili provođenja procjenjuju se u odnosu na dnevnik simptoma. Zaključak i dijagnozu daje ljekar kardiolog', 'Забиљежене епизоде поремећаја ритма или провођења процјењују се у односу на дневник симптома. Закључак и дијагнозу даје љекар кардиолог', 'Записанные эпизоды нарушений ритма или проводимости оцениваются в сопоставлении с дневником симптомов. Заключение и диагноз даёт врач-кардиолог', 'Aufgezeichnete Episoden von Rhythmus- oder Erregungsleitungsstörungen werden im Abgleich mit dem Symptomtagebuch bewertet. Die Beurteilung und Diagnose gibt ein Facharzt für Kardiologie', 'Kaydedilen ritim veya ileti bozukluğu epizodları semptom günlüğüyle karşılaştırılarak değerlendirilir. Değerlendirme ve tanı kardiyoloji uzmanı tarafından konur')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'holter-blood-pressure-24h'), '24-hour blood pressure monitoring using a portable device', 'Dvadesetčetvoročasovno praćenje krvnog pritiska prenosivim uređajem', 'Двадесетчетворочасовно праћење крвног притиска преносивим уређајем', 'Суточный мониторинг артериального давления портативным прибором', '24-Stunden-Überwachung des Blutdrucks mittels tragbarem Gerät', 'Taşınabilir bir cihazla 24 saatlik kan basıncı takibi', 'A cuff is placed on the upper arm, connected to a small recorder worn on a belt, which automatically measures blood pressure at set intervals (usually 15–30 minutes) over 24 hours', 'Na nadlakticu se postavlja manžetna povezana sa malim uređajem za snimanje na pojasu, koji automatski mjeri pritisak u zadatim intervalima (obično 15–30 minuta) tokom 24 sata', 'На надлактицу се поставља манжетна повезана са малим уређајем за снимање на појасу, који аутоматски мјери притисак у задатим интервалима (обично 15–30 минута) током 24 сата', 'На плечо надевается манжета, соединённая с небольшим регистратором на поясе, который автоматически измеряет давление через заданные интервалы (обычно 15–30 минут) в течение 24 часов', 'Eine Manschette wird am Oberarm angelegt und mit einem kleinen, am Gürtel getragenen Aufzeichnungsgerät verbunden, das den Blutdruck automatisch in festgelegten Abständen (meist 15–30 Minuten) über 24 Stunden misst', 'Üst kola bir manşet takılır ve belde taşınan küçük bir kayıt cihazına bağlanır; bu cihaz 24 saat boyunca belirli aralıklarla (genellikle 15–30 dakika) otomatik olarak tansiyonu ölçer', 'Suspected arterial hypertension, evaluation of blood pressure treatment effectiveness, significant blood pressure fluctuations, clarifying diagnosis when home and office readings differ', 'Sumnja na arterijsku hipertenziju, procjena djelotvornosti liječenja povišenog pritiska, značajne oscilacije pritiska, pojašnjenje dijagnoze kod razlike u vrijednostima izmjerenim kod kuće i kod ljekara', 'Сумња на артеријску хипертензију, процјена дјелотворности лијечења повишеног притиска, значајне осцилације притиска, појашњење дијагнозе код разлике у вриједностима измјереним код куће и код љекара', 'Подозрение на артериальную гипертензию, оценка эффективности лечения давления, значительные колебания давления, уточнение диагноза при разнице показаний дома и на приёме у врача', 'Verdacht auf Bluthochdruck, Beurteilung der Wirksamkeit einer Blutdruckbehandlung, deutliche Blutdruckschwankungen, Klärung der Diagnose bei abweichenden Werten zwischen Messungen zu Hause und beim Arzt', 'Hipertansiyon şüphesi, tansiyon tedavisinin etkinliğinin değerlendirilmesi, belirgin tansiyon dalgalanmaları, evde ve muayenehanede ölçülen değerler arasında fark olduğunda tanının netleştirilmesi', 'Not required; normal daily activities should continue while wearing the device, except for water-related activities (shower, pool) with the device on', 'Nije potrebna; tokom nošenja uređaja treba voditi uobičajen način života, osim vodenih procedura (tuširanje, bazen) sa uređajem', 'Није потребна; током ношења уређаја треба водити уобичајен начин живота, осим водених процедура (туширање, базен) са уређајем', 'Не требуется; в день ношения прибора нужно вести обычный образ жизни, кроме водных процедур (душ, бассейн) с прибором', 'Keine Vorbereitung erforderlich; während der Tragezeit sollte der gewohnte Alltag fortgeführt werden, mit Ausnahme von Wasseraktivitäten (Duschen, Schwimmbad) mit dem Gerät', 'Özel bir hazırlık gerekmez; cihazı takarken normal günlük yaşam sürdürülmeli, ancak cihazla birlikte suyla temas gerektiren aktivitelerden (duş, havuz) kaçınılmalıdır', 'Deviations from typical daily readings may indicate disturbances in blood pressure regulation. Interpretation and treatment adjustment are carried out by a cardiologist or general practitioner', 'Odstupanja od tipičnih dnevnih vrijednosti mogu ukazivati na poremećaje regulacije pritiska. Tumačenje i korekciju liječenja sprovodi ljekar kardiolog ili ljekar opšte prakse', 'Одступања од типичних дневних вриједности могу указивати на поремећаје регулације притиска. Тумачење и корекцију лијечења спроводи љекар кардиолог или љекар опште праксе', 'Отклонения от типичных суточных показателей могут указывать на нарушения регуляции давления. Интерпретацию и коррекцию лечения проводит врач-кардиолог или терапевт', 'Abweichungen von den typischen Tageswerten können auf Störungen der Blutdruckregulation hinweisen. Die Beurteilung und Anpassung der Behandlung erfolgt durch einen Facharzt für Kardiologie oder einen Allgemeinmediziner', 'Tipik günlük değerlerden sapmalar, tansiyon düzenlenmesinde bozukluklara işaret edebilir. Değerlendirme ve tedavi düzenlemesi kardiyoloji uzmanı veya pratisyen hekim tarafından yapılır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'cardiologist-examination-with-ecg'), 'Cardiologist consultation with electrocardiogram recording', 'Pregled kod ljekara kardiologa sa snimanjem elektrokardiograma', 'Преглед код љекара кардиолога са снимањем електрокардиограма', 'Приём врача-кардиолога с записью электрокардиограммы', 'Kardiologische Untersuchung mit Aufzeichnung eines Elektrokardiogramms', 'Elektrokardiyogram kaydıyla birlikte kardiyoloji muayenesi', 'The doctor interviews the patient, performs an examination (heart auscultation, blood pressure measurement), then an ECG is recorded; the appointment takes 20–40 minutes', 'Ljekar razgovara sa pacijentom, obavlja pregled (auskultacija srca, mjerenje pritiska), a zatim se snima EKG; pregled traje 20–40 minuta', 'Љекар разговара са пацијентом, обавља преглед (аускултација срца, мјерење притиска), а затим се снима ЕКГ; преглед траје 20–40 минута', 'Врач опрашивает пациента, проводит осмотр (аускультация сердца, измерение давления), затем снимается ЭКГ; приём занимает 20–40 минут', 'Der Arzt befragt den Patienten, führt eine Untersuchung durch (Herzauskultation, Blutdruckmessung) und lässt anschließend ein EKG aufzeichnen; der Termin dauert 20–40 Minuten', 'Doktor hastayı sorgular, muayene yapar (kalp oskültasyonu, tansiyon ölçümü), ardından EKG çekilir; randevu 20–40 dakika sürer', 'Preventive screening, chest pain, shortness of breath, high blood pressure, referral from another doctor, routine health check', 'Preventivni pregled, bolovi u grudima, otežano disanje, povišen pritisak, uputnica od drugog ljekara, sistematski pregled', 'Превентивни преглед, болови у грудима, отежано дисање, повишен притисак, упутница од другог љекара, систематски преглед', 'Профилактический осмотр, боли в груди, одышка, повышенное давление, направление от другого врача, диспансеризация', 'Vorsorgeuntersuchung, Brustschmerzen, Atemnot, erhöhter Blutdruck, Überweisung durch einen anderen Arzt, allgemeine Gesundheitsuntersuchung', 'Rutin kontrol, göğüs ağrısı, nefes darlığı, yüksek tansiyon, başka bir doktordan sevk, genel sağlık kontrolü', 'Not required; it is advisable to bring the results of previous heart examinations, if available', 'Nije potrebna; poželjno je ponijeti rezultate ranijih pregleda srca, ako ih ima', 'Није потребна; пожељно је понијети резултате ранијих прегледа срца, ако их има', 'Не требуется; желательно принести результаты предыдущих обследований сердца, если они есть', 'Keine Vorbereitung erforderlich; es empfiehlt sich, Ergebnisse früherer Herzuntersuchungen mitzubringen, falls vorhanden', 'Özel bir hazırlık gerekmez; varsa önceki kalp muayenelerinin sonuçlarını getirmek faydalıdır', 'Based on the examination and ECG, the doctor may order additional tests or give recommendations. Diagnosis and follow-up plan are determined by a cardiologist', 'Na osnovu pregleda i EKG-a ljekar može zatražiti dodatne pretrage ili dati preporuke. Dijagnozu i plan praćenja određuje ljekar kardiolog', 'На основу прегледа и ЕКГ-а љекар може затражити додатне претраге или дати препоруке. Дијагнозу и план праћења одређује љекар кардиолог', 'По итогам осмотра и ЭКГ врач может назначить дополнительные обследования или дать рекомендации. Диагноз и план наблюдения определяет врач-кардиолог', 'Auf Grundlage der Untersuchung und des EKGs kann der Arzt weitere Untersuchungen anordnen oder Empfehlungen geben. Diagnose und Nachsorgeplan legt ein Facharzt für Kardiologie fest', 'Muayene ve EKG sonuçlarına göre doktor ek tetkikler isteyebilir veya öneriler verebilir. Tanı ve takip planı kardiyoloji uzmanı tarafından belirlenir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'stress-echocardiography'), 'Ultrasound examination of the heart performed before and after physical or pharmacological stress', 'Ultrazvučni pregled srca koji se izvodi prije i poslije fizičkog ili medikamentoznog opterećenja', 'Ултразвучни преглед срца који се изводи прије и послије физичког или медикаментозног оптерећења', 'Ультразвуковое исследование сердца, выполняемое до и после физической или медикаментозной нагрузки', 'Ultraschalluntersuchung des Herzens vor und nach körperlicher oder medikamentöser Belastung', 'Fiziksel veya ilaçla oluşturulan efor öncesi ve sonrasında yapılan kalp ultrasonu', 'A resting heart ultrasound is recorded first, then the patient performs a stress test (stationary bike, treadmill, or a medication that increases heart rate), after which the examination is repeated under the doctor''s supervision; 30–60 minutes total', 'Prvo se snima ultrazvuk srca u mirovanju, zatim pacijent obavlja opterećenje (bicikl ergometar, traka za trčanje ili lijek koji povećava srčanu frekvenciju), nakon čega se pregled ponavlja pod nadzorom ljekara; ukupno 30–60 minuta', 'Прво се снима ултразвук срца у мировању, затим пацијент обавља оптерећење (бицикл ергометар, трака за трчање или лијек који повећава срчану фреквенцију), након чега се преглед понавља под надзором љекара; укупно 30–60 минута', 'Сначала записывается УЗИ сердца в покое, затем пациент выполняет нагрузку (велоэргометр, тредмил или препарат, повышающий частоту сердечных сокращений), после чего исследование повторяют под контролем врача; всего 30–60 минут', 'Zunächst wird eine Herzultraschalluntersuchung in Ruhe durchgeführt, dann absolviert der Patient eine Belastung (Fahrradergometer, Laufband oder ein die Herzfrequenz steigerndes Medikament), wonach die Untersuchung unter ärztlicher Aufsicht wiederholt wird; insgesamt 30–60 Minuten', 'Önce dinlenme halinde kalp ultrasonu kaydedilir, ardından hasta efor testi yapar (bisiklet ergometresi, koşu bandı veya kalp hızını artıran bir ilaç), sonrasında inceleme doktor gözetiminde tekrarlanır; toplamda 30–60 dakika sürer', 'Assessment of heart blood supply under stress, chest pain of unclear origin, pre-surgery evaluation, assessment of heart function in known conditions', 'Procjena snabdjevenosti srca krvlju pod opterećenjem, bolovi u grudima nejasnog porijekla, kontrola prije operacija, procjena funkcije srca kod poznatih oboljenja', 'Процјена снабдјевености срца крвљу под оптерећењем, болови у грудима нејасног поријекла, контрола прије операција, процјена функције срца код познатих обољења', 'Оценка кровоснабжения сердца при нагрузке, боли в груди неясного происхождения, контроль перед операциями, оценка функции сердца при известных заболеваниях', 'Beurteilung der Herzdurchblutung unter Belastung, Brustschmerzen unklarer Ursache, Kontrolle vor Operationen, Beurteilung der Herzfunktion bei bekannten Erkrankungen', 'Efor sırasında kalbin kan akışının değerlendirilmesi, nedeni belirsiz göğüs ağrısı, ameliyat öncesi kontrol, bilinen hastalıklarda kalp fonksiyonunun değerlendirilmesi', 'Light clothing and shoes suitable for exercise; in agreement with the doctor – discontinuation of certain medications and avoiding food/caffeine for a few hours before the test', 'Lagana odjeća i obuća za opterećenje; u dogovoru sa ljekarom – obustava određenih lijekova i izbjegavanje hrane/kofeina nekoliko sati prije testa', 'Лагана одјећа и обућа за оптерећење; у договору са љекаром – обустава одређених лијекова и избјегавање хране/кофеина неколико сати прије теста', 'Лёгкая одежда и обувь для нагрузки; по согласованию с врачом — отмена некоторых препаратов и отказ от еды/кофеина за несколько часов до теста', 'Leichte Kleidung und für die Belastung geeignetes Schuhwerk; nach Absprache mit dem Arzt – Absetzen bestimmter Medikamente und Verzicht auf Essen/Koffein einige Stunden vor dem Test', 'Efor için hafif kıyafet ve uygun ayakkabı; doktorla görüşülerek bazı ilaçların kesilmesi ve testten birkaç saat önce yiyecek/kafeinden kaçınılması', 'Changes in heart contractility during stress may indicate reduced blood supply to certain areas. Conclusion and further steps are determined by a cardiologist', 'Promjene kontraktilnosti srca tokom opterećenja mogu ukazivati na smanjenu snabdjevenost krvlju pojedinih područja. Zaključak i dalje korake određuje ljekar kardiolog', 'Промјене контрактилности срца током оптерећења могу указивати на смањену снабдјевеност крвљу појединих подручја. Закључак и даље кораке одређује љекар кардиолог', 'Изменения сократимости сердца при нагрузке могут указывать на снижение кровоснабжения отдельных участков. Заключение и дальнейшую тактику определяет врач-кардиолог', 'Veränderungen der Herzkontraktilität unter Belastung können auf eine verminderte Durchblutung einzelner Bereiche hinweisen. Die Beurteilung und das weitere Vorgehen legt ein Facharzt für Kardiologie fest', 'Efor sırasında kalp kasılma gücündeki değişiklikler, belirli bölgelerde kan akışının azaldığına işaret edebilir. Değerlendirme ve sonraki adımlara kardiyoloji uzmanı karar verir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'ergometry-stress-test'), 'Stress test with ECG recording during physical exercise on a stationary bike or treadmill', 'Test opterećenja sa snimanjem EKG-a tokom fizičkog napora na bicikl ergometru ili traci za trčanje', 'Тест оптерећења са снимањем ЕКГ-а током физичког напора на бицикл ергометру или траци за трчање', 'Нагрузочный тест с записью ЭКГ во время физической нагрузки на велоэргометре или беговой дорожке', 'Belastungstest mit EKG-Aufzeichnung während körperlicher Belastung auf einem Fahrradergometer oder Laufband', 'Bisiklet ergometresi veya koşu bandında fiziksel efor sırasında EKG kaydı ile yapılan efor testi', 'ECG electrodes and a blood pressure cuff are attached to the body, the patient performs exercise with gradually increasing intensity under the doctor''s supervision until target values are reached or symptoms appear; 20–40 minutes', 'Na tijelo se postavljaju EKG elektrode i manžetna za mjerenje pritiska, pacijent izvodi opterećenje uz postepeno povećanje intenziteta pod nadzorom ljekara do postizanja ciljnih vrijednosti ili pojave simptoma; 20–40 minuta', 'На тијело се постављају ЕКГ електроде и манжетна за мјерење притиска, пацијент изводи оптерећење уз постепено повећање интензитета под надзором љекара до постизања циљних вриједности или појаве симптома; 20–40 минута', 'На тело крепятся электроды ЭКГ и манжета для измерения давления, пациент выполняет нагрузку с постепенным увеличением интенсивности под контролем врача до достижения целевых показателей или появления симптомов; 20–40 минут', 'EKG-Elektroden und eine Blutdruckmanschette werden am Körper angebracht, der Patient absolviert unter ärztlicher Aufsicht eine Belastung mit schrittweise steigender Intensität, bis Zielwerte erreicht sind oder Symptome auftreten; 20–40 Minuten', 'Vücuda EKG elektrotları ve tansiyon manşeti takılır, hasta doktor gözetiminde hedef değerlere ulaşılana veya semptomlar ortaya çıkana kadar giderek artan yoğunlukta efor yapar; 20–40 dakika sürer', 'Chest pain during exercise, assessment of exercise tolerance, monitoring after treatment for cardiovascular disease, occupational screening (sports medicine, certain professions)', 'Bolovi u grudima pri naporu, procjena podnošenja fizičkog napora, kontrola nakon liječenja kardiovaskularnih oboljenja, sistematski pregled (sportska medicina, pojedina zanimanja)', 'Болови у грудима при напору, процјена подношења физичког напора, контрола након лијечења кардиоваскуларних обољења, систематски преглед (спортска медицина, поједина занимања)', 'Боли в груди при нагрузке, оценка переносимости физической нагрузки, контроль после лечения сердечно-сосудистых заболеваний, профосмотр (спортивная медицина, отдельные профессии)', 'Brustschmerzen bei Belastung, Beurteilung der körperlichen Belastbarkeit, Kontrolle nach Behandlung von Herz-Kreislauf-Erkrankungen, arbeitsmedizinische Untersuchung (Sportmedizin, bestimmte Berufe)', 'Efor sırasında göğüs ağrısı, egzersiz toleransının değerlendirilmesi, kalp-damar hastalığı tedavisi sonrası takip, meslek kontrolü (spor hekimliği, bazı meslekler)', 'Comfortable clothing and sports shoes; a light meal 2–3 hours before the test; in agreement with the doctor – discontinuation of certain medications', 'Udobna odjeća i sportska obuća; laganiji obrok 2–3 sata prije testa; u dogovoru sa ljekarom – obustava određenih lijekova', 'Удобна одјећа и спортска обућа; лаганији оброк 2–3 сата прије теста; у договору са љекаром – обустава одређених лијекова', 'Удобная одежда и спортивная обувь; лёгкий приём пищи за 2–3 часа до теста; по согласованию с врачом — отмена некоторых препаратов', 'Bequeme Kleidung und Sportschuhe; eine leichte Mahlzeit 2–3 Stunden vor dem Test; nach Absprache mit dem Arzt – Absetzen bestimmter Medikamente', 'Rahat kıyafet ve spor ayakkabısı; testten 2–3 saat önce hafif bir öğün; doktorla görüşülerek bazı ilaçların kesilmesi', 'Changes in ECG, blood pressure or wellbeing during exercise may indicate reduced blood supply to the heart or rhythm disturbances. Conclusion and diagnosis are given by a cardiologist', 'Promjene na EKG-u, pritisku ili opštem stanju tokom napora mogu ukazivati na smanjenu snabdjevenost srca krvlju ili poremećaje ritma. Zaključak i dijagnozu daje ljekar kardiolog', 'Промјене на ЕКГ-у, притиску или општем стању током напора могу указивати на смањену снабдјевеност срца крвљу или поремећаје ритма. Закључак и дијагнозу даје љекар кардиолог', 'Изменения ЭКГ, давления или самочувствия при нагрузке могут указывать на снижение кровоснабжения сердца или нарушения ритма. Заключение и диагноз даёт врач-кардиолог', 'Veränderungen von EKG, Blutdruck oder Befinden unter Belastung können auf eine verminderte Durchblutung des Herzens oder Rhythmusstörungen hinweisen. Die Beurteilung und Diagnose gibt ein Facharzt für Kardiologie', 'Efor sırasında EKG, tansiyon veya genel durumdaki değişiklikler kalbin kan akışının azaldığına veya ritim bozukluklarına işaret edebilir. Değerlendirme ve tanı kardiyoloji uzmanı tarafından konur')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'panoramic-x-ray'), 'Panoramic X-ray (orthopantomogram) of all teeth, jaws and surrounding bone structures', 'Panoramski snimak (ortopantomogram) svih zuba, vilica i okolnih koštanih struktura', 'Панорамски снимак (ортопантомограм) свих зуба, вилица и околних коштаних структура', 'Панорамный снимок (ортопантомограмма) всех зубов, челюстей и окружающих костных структур', 'Panoramaröntgenaufnahme (Orthopantomogramm) aller Zähne, Kiefer und umliegender Knochenstrukturen', 'Tüm dişlerin, çenelerin ve çevredeki kemik yapıların panoramik röntgeni (ortopantomogram)', 'The patient stands or sits while the machine rotates around the head; the scan takes about a minute. You''ll be asked to remove metal jewelry and removable dentures', 'Pacijent stoji ili sjedi, aparat pravi kružni pokret oko glave, snimanje traje oko minut; zamoliće vas da skinete metalni nakit i mobilne proteze', 'Пацијент стоји или сједи, апарат прави кружни покрет око главе, снимање траје око минут; замолиће вас да скинете метални накит и мобилне протезе', 'Пациент стоит или сидит, аппарат делает круговой оборот вокруг головы, снимок занимает около минуты; попросят снять металлические украшения и съёмные протезы', 'Der Patient steht oder sitzt, das Gerät dreht sich einmal um den Kopf; die Aufnahme dauert etwa eine Minute. Sie werden gebeten, Metallschmuck und herausnehmbaren Zahnersatz abzulegen', 'Hasta ayakta veya oturarak cihazın önünde durur, cihaz baş etrafında dairesel bir hareket yapar; çekim yaklaşık bir dakika sürer; metal takıların ve çıkarılabilir protezlerin çıkarılması istenir', 'Routine check-up before dental treatment, implants or orthodontic treatment, wisdom tooth removal, general assessment of jaw condition', 'Planski pregled prije liječenja zuba, implantacije ili ortodontskog liječenja, vađenje umnjaka, opšta procjena stanja vilica', 'Плански преглед прије лијечења зуба, имплантације или ортодонтског лијечења, вађење умњака, општа процјена стања вилица', 'Плановый осмотр перед лечением зубов, имплантацией или ортодонтическим лечением, удаление зубов мудрости, общая оценка состояния челюстей', 'Routineuntersuchung vor Zahnbehandlung, Implantation oder kieferorthopädischer Behandlung, Weisheitszahnentfernung, allgemeine Beurteilung des Kieferzustands', 'Diş tedavisi, implant veya ortodontik tedavi öncesi rutin muayene, yirmi yaş dişi çekimi, çene durumunun genel değerlendirilmesi', 'No special preparation is needed; remove earrings, glasses and removable dentures before the scan', 'Posebna priprema nije potrebna; skinuti minđuše, naočare i mobilne zubne proteze prije snimanja', 'Посебна припрема није потребна; скинути минђуше, наочаре и мобилне зубне протезе прије снимања', 'Специальной подготовки не требуется; снять серьги, очки и съёмные зубные протезы перед снимком', 'Keine besondere Vorbereitung erforderlich; vor der Aufnahme Ohrringe, Brille und herausnehmbaren Zahnersatz ablegen', 'Özel bir hazırlık gerekmez; çekimden önce küpe, gözlük ve çıkarılabilir diş protezlerinin çıkarılması gerekir', 'Findings may indicate changes in bone tissue, tooth position or inflammatory processes that require further evaluation. The dentist determines the conclusion and treatment plan', 'Nalaz može ukazivati na promjene koštanog tkiva, položaj zuba ili upalne procese koji zahtijevaju dodatno pojašnjenje. Zaključak i plan liječenja određuje stomatolog', 'Налаз може указивати на промјене коштаног ткива, положај зуба или упалне процесе који захтијевају додатно појашњење. Закључак и план лијечења одређује стоматолог', 'Находки могут указывать на изменения костной ткани, положение зубов или воспалительные процессы, требующие уточнения. Заключение и план лечения определяет врач-стоматолог', 'Die Befunde können auf Veränderungen des Knochengewebes, der Zahnstellung oder auf entzündliche Prozesse hinweisen, die weiter abgeklärt werden müssen. Die Beurteilung und den Behandlungsplan legt der Zahnarzt fest', 'Bulgular kemik dokusunda, diş konumunda veya iltihabi süreçlerde ileri değerlendirme gerektiren değişikliklere işaret edebilir. Sonuç ve tedavi planını diş hekimi belirler')
