INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'intraoral-x-ray'), 'Targeted (intraoral) X-ray of one or two teeth for a detailed assessment of their structure and roots', 'Ciljani (intraoralni) snimak jednog do dva zuba radi detaljne procjene njihove strukture i korijena', 'Циљани (интраорални) снимак једног до два зуба ради детаљне процјене њихове структуре и коријена', 'Прицельный (внутриротовой) снимок одного-двух зубов для детальной оценки их структуры и корней', 'Gezielte (intraorale) Röntgenaufnahme von ein bis zwei Zähnen zur detaillierten Beurteilung ihrer Struktur und Wurzeln', 'Bir veya iki dişin yapısını ve köklerini ayrıntılı değerlendirmek için lokal (ağız içi) röntgen', 'A small sensor or film is placed in the mouth next to the tooth in question; the image is taken in a few seconds', 'Mali senzor ili film se postavlja u usta pored zuba koji se snima, snimanje traje nekoliko sekundi', 'Мали сензор или филм се поставља у уста поред зуба који се снима, снимање траје неколико секунди', 'Небольшой датчик или плёнка размещается во рту рядом с нужным зубом, снимок делается за несколько секунд', 'Ein kleiner Sensor oder Film wird im Mund neben dem betreffenden Zahn platziert; die Aufnahme dauert nur wenige Sekunden', 'Ağız içine, ilgili dişin yanına küçük bir sensör veya film yerleştirilir; çekim birkaç saniye sürer', 'Toothache, suspected cavity between teeth, monitoring before and after root canal treatment, assessment before extraction', 'Bol u zubu, sumnja na karijes između zuba, kontrola prije i poslije liječenja korijenskih kanala, procjena stanja prije vađenja', 'Бол у зубу, сумња на каријес између зуба, контрола прије и послије лијечења коријенских канала, процјена стања прије вађења', 'Боль в зубе, подозрение на кариес между зубами, контроль перед и после лечения корневых каналов, оценка состояния перед удалением', 'Zahnschmerzen, Verdacht auf Karies zwischen den Zähnen, Kontrolle vor und nach einer Wurzelkanalbehandlung, Beurteilung vor einer Extraktion', 'Diş ağrısı, dişler arası çürük şüphesi, kanal tedavisi öncesi ve sonrası kontrol, çekim öncesi durum değerlendirmesi', 'No special preparation is needed', 'Posebna priprema nije potrebna', 'Посебна припрема није потребна', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Findings may reflect changes in the hard tooth tissue or surrounding bone that require further evaluation. The dentist determines the conclusion and treatment approach', 'Nalaz može odražavati promjene tvrdog tkiva zuba ili okolne kosti koje zahtijevaju dodatno pojašnjenje. Zaključak i taktiku liječenja određuje stomatolog', 'Налаз може одражавати промјене тврдог ткива зуба или околне кости које захтијевају додатно појашњење. Закључак и тактику лијечења одређује стоматолог', 'Находки могут отражать изменения твёрдых тканей зуба или окружающей кости, требующие уточнения. Заключение и тактику лечения определяет врач-стоматолог', 'Die Befunde können Veränderungen der Zahnhartsubstanz oder des umliegenden Knochens widerspiegeln, die weiter abgeklärt werden müssen. Die Beurteilung und das therapeutische Vorgehen legt der Zahnarzt fest', 'Bulgular, diş sert dokusunda veya çevre kemikte ileri değerlendirme gerektiren değişikliklere işaret edebilir. Sonuç ve tedavi yaklaşımını diş hekimi belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'x-ray-chest-heart'), 'Chest X-ray to assess the lungs, heart and mediastinum', 'Rendgenski snimak grudnog koša radi procjene pluća, srca i medijastinuma', 'Рендгенски снимак грудног коша ради процјене плућа, срца и медијастинума', 'Рентгеновский снимок органов грудной клетки для оценки лёгких, сердца и средостения', 'Röntgenaufnahme des Brustkorbs zur Beurteilung von Lunge, Herz und Mediastinum', 'Akciğerleri, kalbi ve mediasteni değerlendirmek için göğüs röntgeni', 'The patient is positioned at the machine for 1-2 views (usually standing); the scan takes a few minutes. You''ll be asked to remove metal objects from the area being examined', 'Pacijent se postavlja uz aparat u 1-2 projekcije (obično stojeći), snimanje traje nekoliko minuta; zamoliće vas da skinete metalne predmete u zoni snimanja', 'Пацијент се поставља уз апарат у 1-2 пројекције (обично стојећи), снимање траје неколико минута; замолиће вас да скинете металне предмете у зони снимања', 'Пациент располагается у аппарата в 1-2 проекциях (обычно стоя), снимок занимает несколько минут; попросят снять металлические предметы в области съёмки', 'Der Patient wird am Gerät für 1-2 Aufnahmen positioniert (meist stehend); die Aufnahme dauert wenige Minuten. Sie werden gebeten, Metallgegenstände im Untersuchungsbereich abzulegen', 'Hasta cihazın önünde 1-2 pozisyonda (genellikle ayakta) konumlandırılır; çekim birkaç dakika sürer; çekim bölgesindeki metal eşyaların çıkarılması istenir', 'Cough, shortness of breath, chest pain, routine preventive check-up, follow-up after a lung condition', 'Kašalj, otežano disanje, bol u grudima, planski preventivni pregled, kontrola nakon preboljele plućne bolesti', 'Кашаљ, отежано дисање, бол у грудима, плански превентивни преглед, контрола након пребољеле плућне болести', 'Кашель, одышка, боль в грудной клетке, плановый профилактический осмотр, контроль после перенесённого заболевания лёгких', 'Husten, Atemnot, Brustschmerzen, routinemäßige Vorsorgeuntersuchung, Kontrolle nach überstandener Lungenerkrankung', 'Öksürük, nefes darlığı, göğüs ağrısı, rutin koruyucu muayene, geçirilmiş akciğer hastalığı sonrası kontrol', 'No special preparation is needed; inform the staff of a possible pregnancy', 'Posebna priprema nije potrebna; obavijestiti osoblje o mogućoj trudnoći', 'Посебна припрема није потребна; обавијестити особље о могућој трудноћи', 'Специальной подготовки не требуется; сообщить о возможной беременности', 'Keine besondere Vorbereitung erforderlich; über eine mögliche Schwangerschaft informieren', 'Özel bir hazırlık gerekmez; olası hamilelik durumunun bildirilmesi gerekir', 'Findings may reflect changes in the lungs, heart or mediastinum that require further evaluation. The general practitioner/pulmonologist determines the conclusion and next steps', 'Nalaz može odražavati promjene na plućima, srcu ili medijastinumu koje zahtijevaju dodatno pojašnjenje. Zaključak i dalju taktiku određuje ljekar opšte prakse/pulmolog', 'Налаз може одражавати промјене на плућима, срцу или медијастинуму које захтијевају додатно појашњење. Закључак и даљу тактику одређује љекар опште праксе/пулмолог', 'Находки могут отражать изменения в лёгких, сердце или средостении, требующие уточнения. Заключение и дальнейшую тактику определяет врач-терапевт/пульмонолог', 'Die Befunde können auf Veränderungen der Lunge, des Herzens oder des Mediastinums hinweisen, die weiter abgeklärt werden müssen. Die Beurteilung und das weitere Vorgehen legt der Hausarzt/Pneumologe fest', 'Bulgular, akciğerlerde, kalpte veya mediastende ileri değerlendirme gerektiren değişikliklere işaret edebilir. Sonuç ve sonraki adımları pratisyen hekim/göğüs hastalıkları uzmanı belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'x-ray-lumbar-spine-and-sacrum'), 'X-ray of the lumbar spine and sacrum to assess the bone structures of this area', 'Rendgenski snimak slabinskog dijela kičme i krsne kosti radi procjene koštanih struktura ovog predjela', 'Рендгенски снимак слабинског дијела кичме и крсне кости ради процјене коштаних структура овог предјела', 'Рентгеновский снимок поясничного отдела позвоночника и крестца для оценки костных структур этой области', 'Röntgenaufnahme der Lendenwirbelsäule und des Kreuzbeins zur Beurteilung der Knochenstrukturen dieser Region', 'Bu bölgedeki kemik yapıları değerlendirmek için bel omurgası ve sakrum röntgeni', 'The patient is positioned at the machine for 1-2 views; the scan takes a few minutes. You''ll be asked to remove metal objects from the area being examined', 'Pacijent se postavlja uz aparat u 1-2 projekcije, snimanje traje nekoliko minuta; zamoliće vas da skinete metalne predmete u zoni snimanja', 'Пацијент се поставља уз апарат у 1-2 пројекције, снимање траје неколико минута; замолиће вас да скинете металне предмете у зони снимања', 'Пациент располагается у аппарата в 1-2 проекциях, снимок занимает несколько минут; попросят снять металлические предметы в области съёмки', 'Der Patient wird am Gerät für 1-2 Aufnahmen positioniert; die Aufnahme dauert wenige Minuten. Sie werden gebeten, Metallgegenstände im Untersuchungsbereich abzulegen', 'Hasta cihazın önünde 1-2 pozisyonda konumlandırılır; çekim birkaç dakika sürer; çekim bölgesindeki metal eşyaların çıkarılması istenir', 'Lower back pain, injury, follow-up after a spinal fracture or surgery', 'Bol u leđima (slabinski predio), povreda, kontrola nakon preloma ili operacije na kičmi', 'Бол у леђима (слабински предио), повреда, контрола након прелома или операције на кичми', 'Боль в пояснице, травма, контроль после перелома или операции на позвоночнике', 'Schmerzen im unteren Rücken, Verletzung, Kontrolle nach einer Wirbelsäulenfraktur oder -operation', 'Bel ağrısı, travma, omurga kırığı veya ameliyatı sonrası kontrol', 'No special preparation is needed; inform the staff of a possible pregnancy', 'Posebna priprema nije potrebna; obavijestiti osoblje o mogućoj trudnoći', 'Посебна припрема није потребна; обавијестити особље о могућој трудноћи', 'Специальной подготовки не требуется; сообщить о возможной беременности', 'Keine besondere Vorbereitung erforderlich; über eine mögliche Schwangerschaft informieren', 'Özel bir hazırlık gerekmez; olası hamilelik durumunun bildirilmesi gerekir', 'Findings may reflect changes in the bone structures or intervertebral spaces that require further evaluation. The neurologist/orthopedist determines the conclusion and next steps', 'Nalaz može odražavati promjene koštanih struktura ili međupršljenskih prostora koje zahtijevaju dodatno pojašnjenje. Zaključak i dalju taktiku određuje neurolog/ortoped', 'Налаз може одражавати промјене коштаних структура или међупршљенских простора које захтијевају додатно појашњење. Закључак и даљу тактику одређује неуролог/ортопед', 'Находки могут отражать изменения костных структур или межпозвонковых промежутков, требующие уточнения. Заключение и дальнейшую тактику определяет врач-невролог/ортопед', 'Die Befunde können auf Veränderungen der Knochenstrukturen oder der Zwischenwirbelräume hinweisen, die weiter abgeklärt werden müssen. Die Beurteilung und das weitere Vorgehen legt der Neurologe/Orthopäde fest', 'Bulgular, kemik yapılarda veya omurlar arası boşluklarda ileri değerlendirme gerektiren değişikliklere işaret edebilir. Sonuç ve sonraki adımları nörolog/ortopedist belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'x-ray-hand'), 'Hand X-ray to assess the bone structures', 'Rendgenski snimak šake radi procjene koštanih struktura', 'Рендгенски снимак шаке ради процјене коштаних структура', 'Рентгеновский снимок кисти для оценки костных структур', 'Röntgenaufnahme der Hand zur Beurteilung der Knochenstrukturen', 'Kemik yapıları değerlendirmek için el röntgeni', 'The patient is positioned at the machine for 1-2 views; the scan takes a few minutes. You''ll be asked to remove metal objects (rings, watches)', 'Pacijent se postavlja uz aparat u 1-2 projekcije, snimanje traje nekoliko minuta; zamoliće vas da skinete metalne predmete (prstenje, sat)', 'Пацијент се поставља уз апарат у 1-2 пројекције, снимање траје неколико минута; замолиће вас да скинете металне предмете (прстење, сат)', 'Пациент располагается у аппарата в 1-2 проекциях, снимок занимает несколько минут; попросят снять металлические предметы (кольца, часы)', 'Der Patient wird am Gerät für 1-2 Aufnahmen positioniert; die Aufnahme dauert wenige Minuten. Sie werden gebeten, Metallgegenstände (Ringe, Uhren) abzulegen', 'Hasta cihazın önünde 1-2 pozisyonda konumlandırılır; çekim birkaç dakika sürer; metal eşyaların (yüzük, saat) çıkarılması istenir', 'Injury, pain, follow-up after a fracture or hand surgery', 'Povreda, bol, kontrola nakon preloma ili operacije šake', 'Повреда, бол, контрола након прелома или операције шаке', 'Травма, боль, контроль после перелома или операции на кисти', 'Verletzung, Schmerzen, Kontrolle nach einer Fraktur oder Handoperation', 'Travma, ağrı, kırık veya el ameliyatı sonrası kontrol', 'No special preparation is needed; inform the staff of a possible pregnancy', 'Posebna priprema nije potrebna; obavijestiti osoblje o mogućoj trudnoći', 'Посебна припрема није потребна; обавијестити особље о могућој трудноћи', 'Специальной подготовки не требуется; сообщить о возможной беременности', 'Keine besondere Vorbereitung erforderlich; über eine mögliche Schwangerschaft informieren', 'Özel bir hazırlık gerekmez; olası hamilelik durumunun bildirilmesi gerekir', 'Findings may reflect changes in bone tissue or joints that require further evaluation. The traumatologist/orthopedist determines the conclusion and next steps', 'Nalaz može odražavati promjene koštanog tkiva ili zglobova koje zahtijevaju dodatno pojašnjenje. Zaključak i dalju taktiku određuje traumatolog/ortoped', 'Налаз може одражавати промјене коштаног ткива или зглобова које захтијевају додатно појашњење. Закључак и даљу тактику одређује трауматолог/ортопед', 'Находки могут отражать изменения костной ткани или суставов, требующие уточнения. Заключение и дальнейшую тактику определяет врач-травматолог/ортопед', 'Die Befunde können auf Veränderungen des Knochengewebes oder der Gelenke hinweisen, die weiter abgeklärt werden müssen. Die Beurteilung und das weitere Vorgehen legt der Unfallchirurg/Orthopäde fest', 'Bulgular, kemik dokusunda veya eklemlerde ileri değerlendirme gerektiren değişikliklere işaret edebilir. Sonuç ve sonraki adımları travmatolog/ortopedist belirler')
