VALUES ((SELECT id FROM medical_services WHERE slug = 'x-ray-pelvis'), 'Pelvic X-ray to assess the bone structures of this area', 'Rendgenski snimak karlice radi procjene koštanih struktura ovog predjela', 'Рендгенски снимак карлице ради процјене коштаних структура овог предјела', 'Рентгеновский снимок таза для оценки костных структур этой области', 'Röntgenaufnahme des Beckens zur Beurteilung der Knochenstrukturen dieser Region', 'Bu bölgedeki kemik yapıları değerlendirmek için pelvis röntgeni', 'The patient is positioned at the machine for 1-2 views; the scan takes a few minutes. You''ll be asked to remove metal objects from the area being examined', 'Pacijent se postavlja uz aparat u 1-2 projekcije, snimanje traje nekoliko minuta; zamoliće vas da skinete metalne predmete u zoni snimanja', 'Пацијент се поставља уз апарат у 1-2 пројекције, снимање траје неколико минута; замолиће вас да скинете металне предмете у зони снимања', 'Пациент располагается у аппарата в 1-2 проекциях, снимок занимает несколько минут; попросят снять металлические предметы в области съёмки', 'Der Patient wird am Gerät für 1-2 Aufnahmen positioniert; die Aufnahme dauert wenige Minuten. Sie werden gebeten, Metallgegenstände im Untersuchungsbereich abzulegen', 'Hasta cihazın önünde 1-2 pozisyonda konumlandırılır; çekim birkaç dakika sürer; çekim bölgesindeki metal eşyaların çıkarılması istenir', 'Pelvic injury, pain, follow-up after a fracture or surgery in this area', 'Povreda karlice, bol, kontrola nakon preloma ili operacije u ovom predjelu', 'Повреда карлице, бол, контрола након прелома или операције у овом предјелу', 'Травма таза, боль, контроль после перелома или операции в этой области', 'Beckenverletzung, Schmerzen, Kontrolle nach einer Fraktur oder Operation in diesem Bereich', 'Pelvis travması, ağrı, bu bölgede kırık veya ameliyat sonrası kontrol', 'No special preparation is needed; inform the staff of a possible pregnancy', 'Posebna priprema nije potrebna; obavijestiti osoblje o mogućoj trudnoći', 'Посебна припрема није потребна; обавијестити особље о могућој трудноћи', 'Специальной подготовки не требуется; сообщить о возможной беременности', 'Keine besondere Vorbereitung erforderlich; über eine mögliche Schwangerschaft informieren', 'Özel bir hazırlık gerekmez; olası hamilelik durumunun bildirilmesi gerekir', 'Findings may reflect changes in bone tissue or joints that require further evaluation. The traumatologist/orthopedist determines the conclusion and next steps', 'Nalaz može odražavati promjene koštanog tkiva ili zglobova koje zahtijevaju dodatno pojašnjenje. Zaključak i dalju taktiku određuje traumatolog/ortoped', 'Налаз може одражавати промјене коштаног ткива или зглобова које захтијевају додатно појашњење. Закључак и даљу тактику одређује трауматолог/ортопед', 'Находки могут отражать изменения костной ткани или суставов, требующие уточнения. Заключение и дальнейшую тактику определяет врач-травматолог/ортопед', 'Die Befunde können auf Veränderungen des Knochengewebes oder der Gelenke hinweisen, die weiter abgeklärt werden müssen. Die Beurteilung und das weitere Vorgehen legt der Unfallchirurg/Orthopäde fest', 'Bulgular, kemik dokusunda veya eklemlerde ileri değerlendirme gerektiren değişikliklere işaret edebilir. Sonuç ve sonraki adımları travmatolog/ortopedist belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'mammography'), 'Breast X-ray for screening or diagnostic examination', 'Rendgenski snimak dojki za skrining ili dijagnostički pregled', 'Рендгенски снимак дојки за скрининг или дијагностички преглед', 'Рентгеновский снимок молочных желёз для скринингового или диагностического обследования', 'Röntgenaufnahme der Brust zur Vorsorge- oder Diagnoseuntersuchung', 'Tarama veya tanısal inceleme için meme röntgeni', 'The patient is positioned at the machine, and the breast is briefly compressed between plates to obtain a clear image in 1-2 views; the procedure takes a few minutes', 'Pacijentkinja se postavlja uz aparat, dojka se kratko stisne pločama radi dobijanja jasnog snimka u 1-2 projekcije, procedura traje nekoliko minuta', 'Пацијенткиња се поставља уз апарат, дојка се кратко стисне плочама ради добијања јасног снимка у 1-2 пројекције, процедура траје неколико минута', 'Пациентка располагается у аппарата, молочная железа кратковременно сжимается пластинами для получения чёткого снимка в 1-2 проекциях, процедура занимает несколько минут', 'Die Patientin wird am Gerät positioniert, die Brust wird kurz zwischen Platten komprimiert, um eine klare Aufnahme in 1-2 Ebenen zu erhalten; der Vorgang dauert wenige Minuten', 'Hasta cihazın önünde konumlandırılır, net bir görüntü elde etmek için meme kısa süreliğine plakalar arasında sıkıştırılarak 1-2 pozisyonda çekim yapılır; işlem birkaç dakika sürer', 'Preventive screening for women of a certain age, complaints of lumps or breast pain, follow-up of previously detected changes', 'Preventivni skrining kod žena određenog uzrasta, tegobe zbog čvorića ili bola u dojci, kontrola ranije uočenih promjena', 'Превентивни скрининг код жена одређеног узраста, тегобе због чворића или бола у дојци, контрола раније уочених промјена', 'Профилактический скрининг у женщин определённого возраста, жалобы на уплотнения или боль в груди, контроль ранее выявленных изменений', 'Vorsorgeuntersuchung bei Frauen ab einem bestimmten Alter, Beschwerden über Knoten oder Brustschmerzen, Kontrolle bereits festgestellter Veränderungen', 'Belirli yaştaki kadınlarda koruyucu tarama, memede sertlik veya ağrı şikayeti, daha önce saptanmış değişikliklerin kontrolü', 'No special preparation is needed; it''s best to schedule the exam in the first half of the menstrual cycle and avoid deodorant or lotion on the chest and underarms before the procedure', 'Posebna priprema nije potrebna; poželjno je zakazati pregled u prvoj polovini menstrualnog ciklusa i ne koristiti dezodorans ni losion u predjelu grudi i pazuha prije procedure', 'Посебна припрема није потребна; пожељно је заказати преглед у првој половини менструалног циклуса и не користити дезодоранс ни лосион у предјелу груди и пазуха прије процедуре', 'Специальной подготовки не требуется; желательно проводить в первой половине менструального цикла, не использовать дезодорант и лосьоны в области груди и подмышек перед процедурой', 'Keine besondere Vorbereitung erforderlich; die Untersuchung sollte möglichst in der ersten Zyklushälfte erfolgen, vor der Untersuchung kein Deodorant oder Lotion im Brust- und Achselbereich verwenden', 'Özel bir hazırlık gerekmez; işlemin adet döngüsünün ilk yarısında yapılması ve işlem öncesi göğüs ile koltuk altı bölgesinde deodorant veya losyon kullanılmaması önerilir', 'Findings may indicate changes in breast tissue that require further evaluation. The mammologist/oncologist determines the conclusion and next steps', 'Nalaz može ukazivati na promjene tkiva dojke koje zahtijevaju dodatno pojašnjenje. Zaključak i dalju taktiku određuje mamolog/onkolog', 'Налаз може указивати на промјене ткива дојке које захтијевају додатно појашњење. Закључак и даљу тактику одређује мамолог/онколог', 'Находки могут указывать на изменения ткани молочной железы, требующие уточнения. Заключение и дальнейшую тактику определяет врач-маммолог/онколог', 'Die Befunde können auf Veränderungen des Brustgewebes hinweisen, die weiter abgeklärt werden müssen. Die Beurteilung und das weitere Vorgehen legt der Mammologe/Onkologe fest', 'Bulgular, meme dokusunda ileri değerlendirme gerektiren değişikliklere işaret edebilir. Sonuç ve sonraki adımları mamolog/onkolog belirler')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'general-practitioner-examination'), 'Appointment with a general practitioner to assess overall health and provide initial diagnosis', 'Pregled kod ljekara opšte prakse radi procjene opšteg zdravstvenog stanja i prvobitne dijagnostike', 'Преглед код љекара опште праксе ради процјене општег здравственог стања и првобитне дијагностике', 'Приём врача общей практики для оценки общего состояния здоровья и первичной диагностики', 'Termin beim Allgemeinmediziner zur Beurteilung des allgemeinen Gesundheitszustands und Erstdiagnose', 'Genel sağlık durumunu değerlendirmek ve ilk tanıyı koymak için pratisyen hekim muayenesi', 'The doctor asks about symptoms and medical history, performs a general examination (blood pressure, pulse, temperature, auscultation); the appointment takes 20-30 minutes', 'Ljekar raspituje o tegobama i istoriji bolesti, obavlja opšti pregled (mjerenje pritiska, pulsa, temperature, auskultacija), pregled traje 20-30 minuta', 'Љекар распитује о тегобама и историји болести, обавља општи преглед (мјерење притиска, пулса, температуре, аускултација), преглед траје 20-30 минута', 'Врач опрашивает о жалобах и истории болезни, проводит общий осмотр (измерение давления, пульса, температуры, аускультация), приём занимает 20-30 минут', 'Der Arzt erfragt Beschwerden und Krankengeschichte, führt eine allgemeine Untersuchung durch (Blutdruck, Puls, Temperatur, Auskultation); der Termin dauert 20-30 Minuten', 'Doktor şikayetleri ve tıbbi geçmişi sorar, genel muayene yapar (tansiyon, nabız, ateş ölçümü, oskültasyon); muayene 20-30 dakika sürer', 'Routine preventive check-up, common colds, general malaise, referral to a specialist, obtaining medical certificates', 'Planski preventivni pregled, prehlade, opšta slabost, upućivanje kod užeg specijaliste, izdavanje ljekarskih uvjerenja', 'Плански превентивни преглед, прехладе, општа слабост, упућивање код ужег специјалисте, издавање љекарских увјерења', 'Плановый профилактический осмотр, простудные заболевания, общее недомогание, направление к узкому специалисту, оформление справок', 'Routinemäßige Vorsorgeuntersuchung, Erkältungskrankheiten, allgemeines Unwohlsein, Überweisung an einen Facharzt, Ausstellung von Bescheinigungen', 'Rutin koruyucu muayene, soğuk algınlığı hastalıkları, genel halsizlik, bir uzmana sevk, sağlık raporu düzenlenmesi', 'No special preparation is needed', 'Posebna priprema nije potrebna', 'Посебна припрема није потребна', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Based on the examination, the doctor may order additional tests or treatment', 'Na osnovu pregleda ljekar može propisati dodatna ispitivanja ili liječenje', 'На основу прегледа љекар може прописати додатна испитивања или лијечење', 'По результатам осмотра врач может назначить дополнительное обследование или лечение', 'Je nach Untersuchungsergebnis kann der Arzt weitere Untersuchungen oder eine Behandlung veranlassen', 'Muayene sonuçlarına göre doktor ek tetkik veya tedavi isteyebilir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'dermatologist-examination'), 'Appointment with a dermatologist to assess the condition of the skin, nails and hair', 'Pregled kod dermatologa radi procjene stanja kože, noktiju i kose', 'Преглед код дерматолога ради процјене стања коже, ноктију и косе', 'Приём врача-дерматолога для оценки состояния кожи, ногтей и волос', 'Termin beim Dermatologen zur Beurteilung von Haut, Nägeln und Haaren', 'Cilt, tırnak ve saç durumunu değerlendirmek için dermatolog muayenesi', 'The doctor asks about symptoms, examines the skin, nails and scalp, and uses a dermatoscope if needed; the appointment takes 15-30 minutes', 'Ljekar raspituje o tegobama, pregleda kožu, nokte i vlasište, po potrebi koristi dermatoskop; pregled traje 15-30 minuta', 'Љекар распитује о тегобама, прегледа кожу, нокте и власиште, по потреби користи дерматоскоп; преглед траје 15-30 минута', 'Врач опрашивает о жалобах, осматривает кожу, ногти и волосистую часть головы, при необходимости использует дерматоскоп; приём занимает 15-30 минут', 'Der Arzt erfragt die Beschwerden, untersucht Haut, Nägel und Kopfhaut und verwendet bei Bedarf ein Dermatoskop; der Termin dauert 15-30 Minuten', 'Doktor şikayetleri sorar, cildi, tırnakları ve saçlı deriyi muayene eder, gerekirse dermatoskop kullanır; muayene 15-30 dakika sürer', 'Rashes, itching, changes in moles, nail problems or hair loss, preventive skin check-up', 'Osip, svrab, promjene na madežima, problemi sa noktima ili opadanje kose, preventivni pregled kože', 'Осип, свраб, промјене на мадежима, проблеми са ноктима или опадање косе, превентивни преглед коже', 'Высыпания, зуд, изменения родинок, проблемы с ногтями или выпадение волос, профилактический осмотр кожи', 'Hautausschlag, Juckreiz, Veränderungen von Muttermalen, Nagelprobleme oder Haarausfall, präventive Hautuntersuchung', 'Döküntü, kaşıntı, ben değişiklikleri, tırnak sorunları veya saç dökülmesi, koruyucu cilt muayenesi', 'No special preparation is needed; it''s best to come without makeup or nail polish', 'Posebna priprema nije potrebna; poželjno je doći bez šminke i laka za nokte', 'Посебна припрема није потребна; пожељно је доћи без шминке и лака за нокте', 'Специальной подготовки не требуется; желательно приходить без макияжа и лака на ногтях', 'Keine besondere Vorbereitung erforderlich; es ist ratsam, ohne Make-up und Nagellack zu erscheinen', 'Özel bir hazırlık gerekmez; makyajsız ve tırnaklarda oje olmadan gelinmesi önerilir', 'Based on the examination, the doctor may order additional tests or treatment', 'Na osnovu pregleda ljekar može propisati dodatna ispitivanja ili liječenje', 'На основу прегледа љекар може прописати додатна испитивања или лијечење', 'По результатам осмотра врач может назначить дополнительное обследование или лечение', 'Je nach Untersuchungsergebnis kann der Arzt weitere Untersuchungen oder eine Behandlung veranlassen', 'Muayene sonuçlarına göre doktor ek tetkik veya tedavi isteyebilir')
