INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'pulmonologist-examination'), 'Appointment with a pulmonologist to assess the condition of the respiratory system', 'Pregled kod pulmologa radi procjene stanja organa za disanje', 'Преглед код пулмолога ради процјене стања органа за дисање', 'Приём врача-пульмонолога для оценки состояния органов дыхания', 'Termin beim Pneumologen zur Beurteilung der Atemwege', 'Solunum sistemi durumunu değerlendirmek için göğüs hastalıkları (pulmonoloji) uzmanı muayenesi', 'The doctor asks about symptoms, listens to the lungs, and may order spirometry or other functional tests if needed; the appointment takes 20-30 minutes', 'Ljekar raspituje o tegobama, obavlja auskultaciju pluća, po potrebi propisuje spirometriju ili druge funkcionalne testove; pregled traje 20-30 minuta', 'Љекар распитује о тегобама, обавља аускултацију плућа, по потреби прописује спирометрију или друге функционалне тестове; преглед траје 20-30 минута', 'Врач опрашивает о жалобах, проводит аускультацию лёгких, при необходимости назначает спирометрию или другие функциональные пробы; приём занимает 20-30 минут', 'Der Arzt erfragt die Beschwerden, hört die Lunge ab und veranlasst bei Bedarf eine Spirometrie oder andere Funktionstests; der Termin dauert 20-30 Minuten', 'Doktor şikayetleri sorar, akciğerleri dinler, gerekirse spirometri veya diğer fonksiyonel testleri ister; muayene 20-30 dakika sürer', 'Persistent cough, shortness of breath, wheezing, monitoring of chronic lung disease', 'Dugotrajan kašalj, otežano disanje, zviždanje pri disanju, kontrola hroničnih plućnih bolesti', 'Дуготрајан кашаљ, отежано дисање, звиждање при дисању, контрола хроничних плућних болести', 'Длительный кашель, одышка, свистящее дыхание, контроль хронических заболеваний лёгких', 'Anhaltender Husten, Atemnot, pfeifende Atmung, Kontrolle chronischer Lungenerkrankungen', 'Uzun süreli öksürük, nefes darlığı, hırıltılı solunum, kronik akciğer hastalıklarının kontrolü', 'No special preparation is needed', 'Posebna priprema nije potrebna', 'Посебна припрема није потребна', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Based on the examination, the doctor may order additional tests or treatment', 'Na osnovu pregleda ljekar može propisati dodatna ispitivanja ili liječenje', 'На основу прегледа љекар може прописати додатна испитивања или лијечење', 'По результатам осмотра врач может назначить дополнительное обследование или лечение', 'Je nach Untersuchungsergebnis kann der Arzt weitere Untersuchungen oder eine Behandlung veranlassen', 'Muayene sonuçlarına göre doktor ek tetkik veya tedavi isteyebilir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'endocrinologist-examination'), 'Appointment with an endocrinologist to assess the function of the hormonal system', 'Pregled kod endokrinologa radi procjene rada hormonalnog sistema', 'Преглед код ендокринолога ради процјене рада хормоналног система', 'Приём врача-эндокринолога для оценки работы гормональной системы', 'Termin beim Endokrinologen zur Beurteilung des Hormonsystems', 'Hormon sisteminin işleyişini değerlendirmek için endokrinolog muayenesi', 'The doctor asks about symptoms, performs an examination (including palpation of the thyroid gland), and reviews test results if available; the appointment takes 20-30 minutes', 'Ljekar raspituje o tegobama, obavlja pregled (uključujući palpaciju štitne žlijezde), procjenjuje rezultate analiza ukoliko postoje; pregled traje 20-30 minuta', 'Љекар распитује о тегобама, обавља преглед (укључујући палпацију штитне жлијезде), процјењује резултате анализа уколико постоје; преглед траје 20-30 минута', 'Врач опрашивает о жалобах, проводит осмотр (включая пальпацию щитовидной железы), оценивает результаты анализов при их наличии; приём занимает 20-30 минут', 'Der Arzt erfragt die Beschwerden, führt eine Untersuchung durch (einschließlich Abtasten der Schilddrüse) und wertet vorhandene Laborergebnisse aus; der Termin dauert 20-30 Minuten', 'Doktor şikayetleri sorar, muayene yapar (tiroid bezinin palpasyonu dahil), varsa tahlil sonuçlarını değerlendirir; muayene 20-30 dakika sürer', 'Thyroid-related symptoms, weight fluctuations, increased fatigue, monitoring of diabetes or other endocrine disorders', 'Simptomi vezani za štitnu žlijezdu, kolebanja tjelesne težine, pojačan zamor, kontrola šećerne bolesti ili drugih endokrinih poremećaja', 'Симптоми везани за штитну жлијезду, колебања тјелесне тежине, појачан замор, контрола шећерне болести или других ендокриних поремећаја', 'Симптомы со стороны щитовидной железы, колебания веса, повышенная утомляемость, контроль сахарного диабета или других эндокринных нарушений', 'Schilddrüsenbedingte Symptome, Gewichtsschwankungen, erhöhte Müdigkeit, Kontrolle von Diabetes oder anderen endokrinen Störungen', 'Tiroidle ilgili belirtiler, kilo dalgalanmaları, artan yorgunluk, diyabet veya diğer endokrin bozuklukların kontrolü', 'No special preparation is needed; it''s best to bring recent test results if you have them', 'Posebna priprema nije potrebna; poželjno je ponijeti rezultate skorašnjih analiza ukoliko postoje', 'Посебна припрема није потребна; пожељно је понијети резултате скорашњих анализа уколико постоје', 'Специальной подготовки не требуется; желательно принести результаты недавних анализов, если они есть', 'Keine besondere Vorbereitung erforderlich; es ist ratsam, aktuelle Laborergebnisse mitzubringen, falls vorhanden', 'Özel bir hazırlık gerekmez; varsa yakın zamandaki tahlil sonuçlarının getirilmesi önerilir', 'Based on the examination, the doctor may order additional tests or treatment', 'Na osnovu pregleda ljekar može propisati dodatna ispitivanja ili liječenje', 'На основу прегледа љекар може прописати додатна испитивања или лијечење', 'По результатам осмотра врач может назначить дополнительное обследование или лечение', 'Je nach Untersuchungsergebnis kann der Arzt weitere Untersuchungen oder eine Behandlung veranlassen', 'Muayene sonuçlarına göre doktor ek tetkik veya tedavi isteyebilir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'first-gastroenterologist-examination'), 'Initial appointment with a gastroenterologist to assess the function of the digestive system', 'Prvi pregled kod gastroenterologa radi procjene rada organa za varenje', 'Први преглед код гастроентеролога ради процјене рада органа за варење', 'Первичный приём врача-гастроэнтеролога для оценки работы органов пищеварения', 'Erstuntersuchung beim Gastroenterologen zur Beurteilung der Verdauungsorgane', 'Sindirim sisteminin işleyişini değerlendirmek için ilk gastroenteroloji muayenesi', 'The doctor asks about symptoms and eating habits, examines and palpates the abdomen, and orders further tests if needed; the appointment takes 20-30 minutes', 'Ljekar raspituje o tegobama i načinu ishrane, obavlja pregled i palpaciju stomaka, po potrebi propisuje dodatna ispitivanja; pregled traje 20-30 minuta', 'Љекар распитује о тегобама и начину исхране, обавља преглед и палпацију стомака, по потреби прописује додатна испитивања; преглед траје 20-30 минута', 'Врач опрашивает о жалобах и характере питания, проводит осмотр и пальпацию живота, при необходимости назначает дополнительные исследования; приём занимает 20-30 минут', 'Der Arzt erfragt Beschwerden und Essgewohnheiten, untersucht und tastet den Bauch ab und veranlasst bei Bedarf weitere Untersuchungen; der Termin dauert 20-30 Minuten', 'Doktor şikayetleri ve beslenme alışkanlıklarını sorar, karnı muayene edip palpe eder, gerekirse ek tetkikler ister; muayene 20-30 dakika sürer', 'Abdominal pain, heartburn, digestive disorders, bloating, changes in bowel habits', 'Bolovi u stomaku, žgaravica, poremećaji varenja, nadutost, promjene u pražnjenju crijeva', 'Болови у стомаку, жгаравица, поремећаји варења, надутост, промјене у пражњењу цријева', 'Боли в животе, изжога, нарушения пищеварения, вздутие, изменения стула', 'Bauchschmerzen, Sodbrennen, Verdauungsstörungen, Blähungen, Veränderungen des Stuhlgangs', 'Karın ağrısı, mide ekşimesi, sindirim bozuklukları, şişkinlik, dışkılama alışkanlığında değişiklik', 'No special preparation is needed; it''s best to bring the results of previous examinations if you have them', 'Posebna priprema nije potrebna; poželjno je ponijeti rezultate ranijih pregleda ukoliko postoje', 'Посебна припрема није потребна; пожељно је понијети резултате ранијих прегледа уколико постоје', 'Специальной подготовки не требуется; желательно принести результаты предыдущих обследований, если они есть', 'Keine besondere Vorbereitung erforderlich; es ist ratsam, Ergebnisse früherer Untersuchungen mitzubringen, falls vorhanden', 'Özel bir hazırlık gerekmez; varsa önceki muayene sonuçlarının getirilmesi önerilir', 'Based on the examination, the doctor may order additional tests or treatment', 'Na osnovu pregleda ljekar može propisati dodatna ispitivanja ili liječenje', 'На основу прегледа љекар може прописати додатна испитивања или лијечење', 'По результатам осмотра врач может назначить дополнительное обследование или лечение', 'Je nach Untersuchungsergebnis kann der Arzt weitere Untersuchungen oder eine Behandlung veranlassen', 'Muayene sonuçlarına göre doktor ek tetkik veya tedavi isteyebilir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

