INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'orthopedist-examination'), 'Appointment with an orthopedist to assess the condition of the bones, joints and spine', 'Pregled kod ortopeda radi procjene stanja kostiju, zglobova i kičme', 'Преглед код ортопеда ради процјене стања костију, зглобова и кичме', 'Приём врача-ортопеда для оценки состояния костей, суставов и позвоночника', 'Termin beim Orthopäden zur Beurteilung von Knochen, Gelenken und Wirbelsäule', 'Kemik, eklem ve omurga durumunu değerlendirmek için ortopedist muayenesi', 'The doctor asks about symptoms, examines and palpates the affected area, and checks the range of motion; the appointment takes 20-30 minutes', 'Ljekar raspituje o tegobama, pregleda i palpira problematičnu oblast, provjerava obim pokreta; pregled traje 20-30 minuta', 'Љекар распитује о тегобама, прегледа и палпира проблематичну област, провјерава обим покрета; преглед траје 20-30 минута', 'Врач опрашивает о жалобах, осматривает и пальпирует проблемную область, проверяет объём движений; приём занимает 20-30 минут', 'Der Arzt erfragt die Beschwerden, untersucht und tastet den betroffenen Bereich ab und prüft den Bewegungsumfang; der Termin dauert 20-30 Minuten', 'Doktor şikayetleri sorar, sorunlu bölgeyi muayene edip palpe eder, hareket açıklığını kontrol eder; muayene 20-30 dakika sürer', 'Joint or back pain, limited mobility, effects of past injuries, posture problems', 'Bolovi u zglobovima ili leđima, ograničena pokretljivost, posljedice povreda, poremećaji držanja', 'Болови у зглобовима или леђима, ограничена покретљивост, посљедице повреда, поремећаји држања', 'Боли в суставах или спине, ограничение подвижности, последствия травм, нарушения осанки', 'Gelenk- oder Rückenschmerzen, eingeschränkte Beweglichkeit, Folgen von Verletzungen, Haltungsstörungen', 'Eklem veya sırt ağrısı, hareket kısıtlılığı, geçirilmiş travma sonuçları, duruş bozuklukları', 'No special preparation is needed; it''s best to bring any existing X-rays or MRI results', 'Posebna priprema nije potrebna; poželjno je ponijeti postojeće snimke ili rezultate MR-a', 'Посебна припрема није потребна; пожељно је понијети постојеће снимке или резултате МР-а', 'Специальной подготовки не требуется; желательно принести имеющиеся снимки или результаты МРТ', 'Keine besondere Vorbereitung erforderlich; es ist ratsam, vorhandene Röntgen- oder MRT-Bilder mitzubringen', 'Özel bir hazırlık gerekmez; varsa mevcut röntgen veya MR sonuçlarının getirilmesi önerilir', 'Based on the examination, the doctor may order additional tests or treatment', 'Na osnovu pregleda ljekar može propisati dodatna ispitivanja ili liječenje', 'На основу прегледа љекар може прописати додатна испитивања или лијечење', 'По результатам осмотра врач может назначить дополнительное обследование или лечение', 'Je nach Untersuchungsergebnis kann der Arzt weitere Untersuchungen oder eine Behandlung veranlassen', 'Muayene sonuçlarına göre doktor ek tetkik veya tedavi isteyebilir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'ent-specialist-examination'), 'Appointment with an ENT specialist to assess the condition of the ears, throat and nose', 'Pregled kod ORL specijaliste (otorinolaringologa) radi procjene stanja uha, grla i nosa', 'Преглед код ОРЛ специјалисте (оториноларинголога) ради процјене стања уха, грла и носа', 'Приём ЛОР-врача для оценки состояния уха, горла и носа', 'Termin beim HNO-Arzt zur Beurteilung von Ohren, Hals und Nase', 'Kulak, boğaz ve burun durumunu değerlendirmek için KBB uzmanı muayenesi', 'The doctor asks about symptoms and examines the ears, throat and nose using special instruments (otoscope, rhinoscope); the appointment takes 15-30 minutes', 'Ljekar raspituje o tegobama, pregleda uho, grlo i nos pomoću posebnih instrumenata (otoskop, rinoskop); pregled traje 15-30 minuta', 'Љекар распитује о тегобама, прегледа ухо, грло и нос помоћу посебних инструмената (отоскоп, риноскоп); преглед траје 15-30 минута', 'Врач опрашивает о жалобах, осматривает ухо, горло и нос с помощью специальных инструментов (отоскоп, риноскоп); приём занимает 15-30 минут', 'Der Arzt erfragt die Beschwerden und untersucht Ohren, Hals und Nase mit speziellen Instrumenten (Otoskop, Rhinoskop); der Termin dauert 15-30 Minuten', 'Doktor şikayetleri sorar, özel aletlerle (otoskop, rinoskop) kulak, boğaz ve burnu muayene eder; muayene 15-30 dakika sürer', 'Sore throat, nasal congestion, hearing loss, ear pain, frequent sinusitis', 'Bol u grlu, začepljen nos, oslabljen sluh, bol u uhu, česti sinusitisi', 'Бол у грлу, зачепљен нос, ослабљен слух, бол у уху, чести синуситиси', 'Боль в горле, заложенность носа, снижение слуха, боль в ухе, частые синуситы', 'Halsschmerzen, verstopfte Nase, Hörminderung, Ohrenschmerzen, häufige Nasennebenhöhlenentzündungen', 'Boğaz ağrısı, burun tıkanıklığı, işitme kaybı, kulak ağrısı, sık sinüzit', 'No special preparation is needed', 'Posebna priprema nije potrebna', 'Посебна припрема није потребна', 'Специальной подготовки не требуется', 'Keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'Based on the examination, the doctor may order additional tests or treatment', 'Na osnovu pregleda ljekar može propisati dodatna ispitivanja ili liječenje', 'На основу прегледа љекар може прописати додатна испитивања или лијечење', 'По результатам осмотра врач может назначить дополнительное обследование или лечение', 'Je nach Untersuchungsergebnis kann der Arzt weitere Untersuchungen oder eine Behandlung veranlassen', 'Muayene sonuçlarına göre doktor ek tetkik veya tedavi isteyebilir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'metal-free-zirconia-ceramic-crown'), 'A crown made of zirconium dioxide without a metal framework, matching the shape and color of a natural tooth', 'Kruna od cirkonijum-dioksida bez metalnog okvira, koja prati oblik i boju prirodnog zuba', 'Круна од цирконијум-диоксида без металног оквира, која прати облик и боју природног зуба', 'Коронка из диоксида циркония без металлического каркаса, повторяющая форму и цвет натурального зуба', 'Eine Krone aus Zirkoniumdioxid ohne Metallgerüst, die Form und Farbe eines natürlichen Zahns nachbildet', 'Doğal dişin şeklini ve rengini taklit eden, metal alt yapısı olmayan zirkonyum dioksit kron', 'Tooth preparation (grinding down), taking an impression or digital scan, fabrication in a dental laboratory, and cementation; usually 2 visits a few days apart (a temporary crown is placed on the tooth in between)', 'Brušenje zuba, uzimanje otiska ili skeniranje, izrada u zubotehničkoj laboratoriji i fiksiranje; obično 2 posjete u razmaku od nekoliko dana (u međuvremenu se na zub postavlja privremena kruna)', 'Брушење зуба, узимање отиска или скенирање, израда у зуботехничкој лабораторији и фиксирање; обично 2 посјете у размаку од неколико дана (у међувремену се на зуб поставља привремена круна)', 'Обтачивание зуба, снятие слепка или сканирование, изготовление в зуботехнической лаборатории и фиксация; обычно 2 визита с промежутком в несколько дней (между ними на зуб ставится временная коронка)', 'Beschleifen des Zahns, Abdrucknahme oder digitaler Scan, Anfertigung im zahntechnischen Labor und Eingliederung; in der Regel 2 Termine im Abstand von einigen Tagen (dazwischen wird eine provisorische Krone eingesetzt)', 'Dişin aşındırılması, ölçü alınması veya dijital tarama, diş laboratuvarında üretim ve yapıştırma; genellikle birkaç gün arayla 2 seans (aralarında dişe geçici kron takılır)', 'Restoration of a badly damaged or root-canal-treated tooth, aesthetic restoration of front teeth, replacement of an old metal-ceramic crown', 'Obnova oštećenog ili depulpiranog zuba, estetska restauracija prednjih zuba, zamjena stare metal-keramike', 'Обнова оштећеног или депулпираног зуба, естетска рестаурација предњих зуба, замјена старе метал-керамике', 'Восстановление разрушенного или депульпированного зуба, эстетическая реставрация передних зубов, замена старой металлокерамики', 'Wiederherstellung eines stark geschädigten oder wurzelbehandelten Zahns, ästhetische Versorgung der Frontzähne, Ersatz einer alten Metallkeramikkrone', 'Çürük veya kanal tedavisi görmüş dişin restorasyonu, ön dişlerde estetik restorasyon, eski metal-seramik kronun değiştirilmesi', 'No special preparation is required; if needed, the tooth is treated with a root canal beforehand', 'Posebna priprema nije potrebna; po potrebi se zub prethodno liječi kanalno', 'Посебна припрема није потребна; по потреби се зуб претходно лијечи канално', 'Специальной подготовки не требуется; при необходимости зуб предварительно лечат по каналу', 'Keine besondere Vorbereitung erforderlich; bei Bedarf wird der Zahn vorab wurzelbehandelt', 'Özel bir hazırlık gerekmez; gerekirse diş önceden kanal tedavisinden geçirilir', 'Mild sensitivity to temperature or discomfort when biting in the first few days is normal; if pain increases or the crown rubs against the gum, see a dentist for an adjustment', 'Blaga osjetljivost na temperaturu ili nelagodnost pri zagrizanju prvih dana je uobičajena pojava; ako bol postaje jača ili kruna nažulji desni, treba se obratiti stomatologu radi korekcije', 'Блага осјетљивост на температуру или нелагодност при загризању првих дана је уобичајена појава; ако бол постаје јача или круна нажуљи десни, треба се обратити стоматологу ради корекције', 'Лёгкая чувствительность к температуре или дискомфорт при накусывании в первые дни — обычное явление; если боль усиливается или коронка натирает десну, нужно обратиться к стоматологу для коррекции', 'Leichte Temperaturempfindlichkeit oder ein unangenehmes Gefühl beim Zubeißen in den ersten Tagen sind normal; bei zunehmenden Schmerzen oder wenn die Krone am Zahnfleisch reibt, sollte ein Zahnarzt zur Korrektur aufgesucht werden', 'İlk günlerde sıcaklığa karşı hafif hassasiyet veya ısırırken hafif rahatsızlık normaldir; ağrı artarsa veya kron diş etini tahriş ederse düzeltme için diş hekimine başvurulmalıdır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'ceramic-veneer'), 'A thin ceramic shell bonded to the front surface of a tooth to change its shape or color', 'Tanka keramička ljuska koja se lijepi na prednju površinu zuba radi promjene oblika ili boje', 'Танка керамичка љуска која се лијепи на предњу површину зуба ради промјене облика или боје', 'Тонкая керамическая накладка на переднюю поверхность зуба для изменения его формы или цвета', 'Eine dünne Keramikschale, die auf die Vorderseite eines Zahns geklebt wird, um Form oder Farbe zu verändern', 'Şeklini veya rengini değiştirmek için dişin ön yüzeyine yapıştırılan ince seramik kaplama', 'Minimal removal of enamel, taking an impression or digital scan, laboratory fabrication, and bonding with composite cement; usually 2 visits', 'Minimalno brušenje cakline, uzimanje otiska ili skeniranje, izrada u laboratoriji i fiksiranje kompozitnim cementom; obično 2 posjete', 'Минимално брушење цаклине, узимање отиска или скенирање, израда у лабораторији и фиксирање композитним цементом; обично 2 посјете', 'Минимальное сошлифовывание эмали, снятие слепка или сканирование, изготовление в лаборатории и фиксация на композитный цемент; обычно 2 визита', 'Minimales Abschleifen des Zahnschmelzes, Abdrucknahme oder digitaler Scan, Anfertigung im Labor und Befestigung mit Kompositzement; in der Regel 2 Termine', 'Minimum düzeyde mine aşındırma, ölçü alma veya dijital tarama, laboratuvarda üretim ve kompozit çimento ile yapıştırma; genellikle 2 seans', 'Correcting the shape, color, chips, or gaps of front teeth for aesthetic reasons', 'Korekcija oblika, boje, okrnjenih ivica ili razmaka između prednjih zuba iz estetskih razloga', 'Корекција облика, боје, окрњених ивица или размака између предњих зуба из естетских разлога', 'Коррекция формы, цвета, сколов или щелей между передними зубами по эстетическим показаниям', 'Korrektur von Form, Farbe, Absplitterungen oder Lücken der Frontzähne aus ästhetischen Gründen', 'Estetik nedenlerle ön dişlerin şeklinin, renginin, kırıklarının veya aralarındaki boşlukların düzeltilmesi', 'No special preparation is required; an additional consultation to assess the bite is sometimes needed', 'Posebna priprema nije potrebna; ponekad je potrebna dodatna konsultacija radi procjene zagriza', 'Посебна припрема није потребна; понекад је потребна додатна консултација ради процјене загриза', 'Специальной подготовки не требуется; иногда нужна дополнительная консультация для оценки прикуса', 'Keine besondere Vorbereitung erforderlich; manchmal ist eine zusätzliche Beratung zur Beurteilung des Bisses nötig', 'Özel bir hazırlık gerekmez; bazen kapanışı değerlendirmek için ek konsültasyon gerekebilir', 'Mild tooth sensitivity in the first few days is a normal reaction; if the veneer shifts, chips, or biting becomes uncomfortable, see a dentist', 'Blaga osjetljivost zuba prvih dana je uobičajena reakcija; ako se vinir pomjeri, okrnji ili se javi nelagodnost pri zagrizanju, treba se obratiti stomatologu', 'Блага осјетљивост зуба првих дана је уобичајена реакција; ако се винир помјери, окрњи или се јави нелагодност при загризању, треба се обратити стоматологу', 'Небольшая чувствительность зубов в первые дни — обычная реакция; если винир сместился, откололся или появился дискомфорт при накусывании, следует обратиться к стоматологу', 'Leichte Zahnempfindlichkeit in den ersten Tagen ist eine normale Reaktion; wenn sich das Veneer löst, absplittert oder das Zubeißen unangenehm wird, sollte ein Zahnarzt aufgesucht werden', 'İlk günlerde hafif diş hassasiyeti normal bir tepkidir; laminate yerinden oynarsa, kırılırsa veya ısırırken rahatsızlık hissedilirse diş hekimine başvurulmalıdır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'metal-ceramic-crown'), 'A crown with a metal framework veneered with ceramic', 'Kruna sa metalnim okvirom obloženim keramikom', 'Круна са металним оквиром обложеним керамиком', 'Коронка с металлическим каркасом, облицованным керамикой', 'Eine Krone mit Metallgerüst, das mit Keramik verblendet ist', 'Seramikle kaplanmış metal alt yapıya sahip kron', 'Tooth preparation, taking an impression or digital scan, laboratory fabrication with a temporary crown worn in the meantime; usually 2 visits', 'Brušenje zuba, uzimanje otiska ili skeniranje, izrada u laboratoriji uz privremenu krunu za period čekanja; obično 2 posjete', 'Брушење зуба, узимање отиска или скенирање, израда у лабораторији уз привремену круну за период чекања; обично 2 посјете', 'Обтачивание зуба, снятие слепка или сканирование, изготовление в лаборатории с временной коронкой на период ожидания; обычно 2 визита', 'Beschleifen des Zahns, Abdrucknahme oder digitaler Scan, Anfertigung im Labor mit einer provisorischen Krone für die Wartezeit; in der Regel 2 Termine', 'Dişin aşındırılması, ölçü alınması veya dijital tarama, bekleme süresi için geçici kronla birlikte laboratuvarda üretim; genellikle 2 seans', 'Restoration of a badly damaged or root-canal-treated tooth, including molars where the strength of the construction matters', 'Obnova oštećenog ili depulpiranog zuba, uključujući bočne zube kod kojih je važna čvrstoća konstrukcije', 'Обнова оштећеног или депулпираног зуба, укључујући бочне зубе код којих је важна чврстоћа конструкције', 'Восстановление разрушенного или депульпированного зуба, в том числе жевательных, где важна прочность конструкции', 'Wiederherstellung eines stark geschädigten oder wurzelbehandelten Zahns, auch im Seitenzahnbereich, wo die Stabilität der Konstruktion wichtig ist', 'Özellikle yapının dayanıklılığının önemli olduğu azı dişleri dahil, çürük veya kanal tedavisi görmüş dişin restorasyonu', 'No special preparation is required; if needed, the tooth is treated with a root canal beforehand', 'Posebna priprema nije potrebna; po potrebi se zub prethodno liječi kanalno', 'Посебна припрема није потребна; по потреби се зуб претходно лијечи канално', 'Специальной подготовки не требуется; при необходимости зуб предварительно лечат по каналу', 'Keine besondere Vorbereitung erforderlich; bei Bedarf wird der Zahn vorab wurzelbehandelt', 'Özel bir hazırlık gerekmez; gerekirse diş önceden kanal tedavisinden geçirilir', 'Mild sensitivity after cementation is normal; if there is pain, the crown becomes loose, or the gum around its edge becomes inflamed, see a dentist', 'Blaga osjetljivost nakon fiksiranja je normalna; u slučaju bola, klimanja krune ili upale desni uz njenu ivicu treba se javiti stomatologu', 'Блага осјетљивост након фиксирања је нормална; у случају бола, климања круне или упале десни уз њену ивицу треба се јавити стоматологу', 'Небольшая чувствительность после фиксации — норма; при боли, расшатывании коронки или воспалении десны у её края нужно показаться стоматологу', 'Leichte Empfindlichkeit nach dem Einsetzen ist normal; bei Schmerzen, einer lockeren Krone oder einer Entzündung des Zahnfleischs am Kronenrand sollte ein Zahnarzt aufgesucht werden', 'Yapıştırma sonrası hafif hassasiyet normaldir; ağrı, kronun gevşemesi veya kron kenarındaki diş etinde iltihaplanma durumunda diş hekimine görünülmelidir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'surgical-tooth-extraction'), 'Tooth removal involving an incision in the gum and/or sectioning the tooth into fragments — used in complex cases', 'Vađenje zuba uz rez desni i/ili rasijecanje zuba na dijelove — primjenjuje se u složenim slučajevima', 'Вађење зуба уз рез десни и/или расијецање зуба на дијелове — примјењује се у сложеним случајевима', 'Удаление зуба с разрезом десны и/или распилом зуба на фрагменты — применяется в сложных случаях', 'Zahnentfernung mit Schnitt im Zahnfleisch und/oder Zerteilen des Zahns in mehrere Teile — wird in komplexen Fällen angewendet', 'Diş etinde kesi yapılarak ve/veya diş parçalara ayrılarak yapılan diş çekimi — karmaşık vakalarda uygulanır', 'Local anesthesia, incision of soft tissue and, if needed, sectioning the tooth, followed by suturing; 30-60 minutes, one visit plus suture removal after 7-10 days', 'Lokalna anestezija, rez mekog tkiva i po potrebi rasijecanje zuba, postavljanje šavova; 30-60 minuta, jedna posjeta plus skidanje šavova poslije 7-10 dana', 'Локална анестезија, рез меког ткива и по потреби расијецање зуба, постављање шавова; 30-60 минута, једна посјета плус скидање шавова послије 7-10 дана', 'Местная анестезия, разрез мягких тканей и при необходимости фрагментация зуба, наложение швов; 30-60 минут, один визит плюс снятие швов через 7-10 дней', 'Lokalanästhesie, Einschnitt des Weichgewebes und bei Bedarf Zerteilen des Zahns, anschließendes Nähen; 30-60 Minuten, ein Termin plus Fadenentfernung nach 7-10 Tagen', 'Lokal anestezi, yumuşak dokuda kesi ve gerekirse dişin parçalara ayrılması, ardından dikiş atılması; 30-60 dakika, bir seans artı 7-10 gün sonra dikiş alınması', 'Impacted or partially impacted wisdom teeth, broken roots, teeth with curved or fused roots', 'Impaktirani ili djelimično impaktirani umnjaci, slomljeni korijeni, zubi sa savijenim ili sraslim korijenima', 'Импактирани или дјелимично импактирани умњаци, сломљени коријени, зуби са савијеним или сраслим коријенима', 'Ретинированные или полуретинированные зубы мудрости, сломанные корни, зубы с изогнутыми или сросшимися корнями', 'Retinierte oder teilretinierte Weisheitszähne, gebrochene Wurzeln, Zähne mit gekrümmten oder verwachsenen Wurzeln', 'Gömülü veya yarı gömülü yirmi yaş dişleri, kırık kökler, eğri veya kaynaşmış köklü dişler', 'Eat a full meal before the procedure, inform the dentist about any medications being taken (especially blood thinners), avoid physical exertion on the day of surgery', 'Dobro se najesti prije zahvata, obavijestiti stomatologa o lijekovima koje uzimate (naročito onim za razrjeđivanje krvi), ne planirati fizičke napore na dan operacije', 'Добро се најести прије захвата, обавијестити стоматолога о лијековима које узимате (нарочито оним за разрјеђивање крви), не планирати физичке напоре на дан операције', 'Плотно поесть перед процедурой, сообщить о принимаемых препаратах (особенно разжижающих кровь), не планировать физические нагрузки в день операции', 'Vor dem Eingriff eine vollständige Mahlzeit einnehmen, den Zahnarzt über eingenommene Medikamente informieren (insbesondere Blutverdünner), am Operationstag keine körperliche Anstrengung planen', 'İşlemden önce doyurucu bir öğün yemek, kullanılan ilaçları (özellikle kan sulandırıcıları) bildirmek, ameliyat günü fiziksel efor planlamamak', 'Swelling, mild pain, and bruising on the cheek in the first 2-3 days are a normal reaction; heavy bleeding, fever, or pain that worsens after the third day is a reason to contact a dentist urgently', 'Oticanje, blaga bol i modrica na obrazu prvih 2-3 dana su uobičajena reakcija; jako krvarenje, povišena temperatura ili bol koja se pojačava poslije trećeg dana razlog su za hitno obraćanje stomatologu', 'Отицање, блага бол и модрица на образу првих 2-3 дана су уобичајена реакција; јако крварење, повишена температура или бол која се појачава послије трећег дана разлог су за хитно обраћање стоматологу', 'Отёк, лёгкая боль и синяк на щеке в первые 2-3 дня — обычная реакция; сильное кровотечение, температура или боль, нарастающая после третьего дня, — повод срочно обратиться к стоматологу', 'Schwellung, leichte Schmerzen und ein Bluterguss an der Wange in den ersten 2-3 Tagen sind eine normale Reaktion; starke Blutung, Fieber oder Schmerzen, die sich nach dem dritten Tag verstärken, sind ein Grund, umgehend einen Zahnarzt aufzusuchen', 'İlk 2-3 gün şişlik, hafif ağrı ve yanakta morluk normal bir tepkidir; şiddetli kanama, ateş veya üçüncü günden sonra artan ağrı acilen diş hekimine başvurma nedenidir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'tooth-extraction'), 'Removal of a whole tooth through its socket, without incisions', 'Vađenje cijelog zuba kroz alveolu, bez rezova', 'Вађење цијелог зуба кроз алвеолу, без резова', 'Удаление зуба целиком через лунку, без разрезов', 'Entfernung eines ganzen Zahns aus dem Zahnfach, ohne Einschnitte', 'Kesi yapılmadan dişin soketinden bütün olarak çıkarılması', 'Local anesthesia, loosening and extracting the tooth with forceps; usually 10-20 minutes, one visit', 'Lokalna anestezija, klimanje i izvlačenje zuba kliještima; obično 10-20 minuta, jedna posjeta', 'Локална анестезија, климање и извлачење зуба клијештима; обично 10-20 минута, једна посјета', 'Местная анестезия, расшатывание и извлечение зуба щипцами; обычно 10-20 минут, один визит', 'Lokalanästhesie, Lockern und Herausziehen des Zahns mit einer Zange; in der Regel 10-20 Minuten, ein Termin', 'Lokal anestezi, dişin gevşetilip pensle çekilmesi; genellikle 10-20 dakika, bir seans', 'A tooth beyond repair due to decay or mobility, indications for orthodontic treatment, a chronic source of infection', 'Zub se ne može liječiti zbog oštećenja ili pokretljivosti, indikacije za ortodontsku terapiju, hronično žarište infekcije', 'Зуб се не може лијечити због оштећења или покретљивости, индикације за ортодонтску терапију, хронично жариште инфекције', 'Зуб не подлежит лечению из-за разрушения или подвижности, показания к ортодонтическому лечению, хронический очаг инфекции', 'Ein durch Zerstörung oder Lockerung nicht mehr erhaltungswürdiger Zahn, Indikationen für eine kieferorthopädische Behandlung, ein chronischer Infektionsherd', 'Çürük veya hareketlilik nedeniyle tedavi edilemeyen diş, ortodontik tedavi endikasyonu, kronik enfeksiyon odağı', 'Eat a full meal before the procedure, inform the dentist about chronic conditions and medications being taken', 'Dobro se najesti prije zahvata, obavijestiti o hroničnim bolestima i lijekovima koje uzimate', 'Добро се најести прије захвата, обавијестити о хроничним болестима и лијековима које узимате', 'Плотно поесть перед процедурой, сообщить о хронических заболеваниях и принимаемых лекарствах', 'Vor dem Eingriff eine vollständige Mahlzeit einnehmen, über chronische Erkrankungen und eingenommene Medikamente informieren', 'İşlemden önce doyurucu bir öğün yemek, kronik hastalıkları ve kullanılan ilaçları bildirmek', 'Slight bleeding and swelling in the first 24 hours are normal; if bleeding does not stop, severe pain develops, or there is an unpleasant smell from the socket, see a dentist', 'Blago krvarenje i oticanje prvog dana su uobičajeni; ako se krvarenje ne zaustavlja, javi se jaka bol ili neprijatan miris iz alveole, treba se obratiti stomatologu', 'Благо крварење и отицање првог дана су уобичајени; ако се крварење не зауставља, јави се јака бол или непријатан мирис из алвеоле, треба се обратити стоматологу', 'Небольшая кровоточивость и отёк в первые сутки — норма; если кровотечение не останавливается, появляется сильная боль или неприятный запах из лунки, нужно обратиться к стоматологу', 'Leichte Blutung und Schwellung im ersten Tag sind normal; wenn die Blutung nicht aufhört, starke Schmerzen auftreten oder ein unangenehmer Geruch aus dem Zahnfach entsteht, sollte ein Zahnarzt aufgesucht werden', 'İlk 24 saatte hafif kanama ve şişlik normaldir; kanama durmazsa, şiddetli ağrı gelişirse veya soketten kötü koku gelirse diş hekimine başvurulmalıdır')
