INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'root-canal-retreatment'), 'Repeated root canal treatment when inflammation persists or returns after the initial treatment', 'Ponovljeno liječenje korijenskog kanala kada se upala održava ili se ponovo javi nakon prvobitnog liječenja', 'Поновљено лијечење коријенског канала када се упала одржава или се поново јави након првобитног лијечења', 'Повторное лечение корневого канала при сохранении или возобновлении воспаления после первичного лечения', 'Erneute Wurzelkanalbehandlung, wenn eine Entzündung nach der ersten Behandlung fortbesteht oder wiederkehrt', 'İlk tedaviden sonra iltihabın devam etmesi veya tekrarlaması durumunda kök kanalının yeniden tedavi edilmesi', 'Removing the old filling material from the canal, re-cleaning and disinfecting, and refilling the canal; usually 1-2 visits', 'Uklanjanje starog materijala za punjenje iz kanala, ponovno čišćenje i dezinfekcija, novo punjenje kanala; obično 1-2 posjete', 'Уклањање старог материјала за пуњење из канала, поновно чишћење и дезинфекција, ново пуњење канала; обично 1-2 посјете', 'Удаление старого пломбировочного материала из канала, повторная очистка и дезинфекция, новое пломбирование; обычно 1-2 визита', 'Entfernen des alten Füllmaterials aus dem Kanal, erneute Reinigung und Desinfektion, neue Füllung des Kanals; in der Regel 1-2 Termine', 'Kanaldan eski dolgu maddesinin çıkarılması, yeniden temizlik ve dezenfeksiyon, kanalın yeniden doldurulması; genellikle 1-2 seans', 'Pain or inflammation in a previously treated tooth, a cyst or granuloma visible on an X-ray, a poorly sealed old root canal filling', 'Bol ili upala u ranije liječenom zubu, cista ili granulom vidljivi na snimku, nedovoljno zaptiveno staro punjenje kanala', 'Бол или упала у раније лијеченом зубу, циста или гранулом видљиви на снимку, недовољно заптивено старо пуњење канала', 'Боль или воспаление в ранее леченном зубе, киста или гранулема на снимке, негерметичная старая пломбировка канала', 'Schmerzen oder Entzündung in einem zuvor behandelten Zahn, eine auf Röntgenbildern sichtbare Zyste oder ein Granulom, eine undichte alte Wurzelkanalfüllung', 'Daha önce tedavi edilmiş dişte ağrı veya iltihap, röntgende görülen kist veya granülom, sızdıran eski kanal dolgusu', 'No special preparation is required; it is helpful to provide the dentist with X-rays from the previous treatment', 'Posebna priprema nije potrebna; poželjno je stomatologu donijeti snimke prethodnog liječenja', 'Посебна припрема није потребна; пожељно је стоматологу донијети снимке претходног лијечења', 'Специальной подготовки не требуется; желательно предоставить стоматологу снимки предыдущего лечения', 'Keine besondere Vorbereitung erforderlich; es ist hilfreich, dem Zahnarzt Röntgenbilder der vorherigen Behandlung mitzubringen', 'Özel bir hazırlık gerekmez; önceki tedaviye ait röntgenlerin diş hekimine getirilmesi faydalıdır', 'A dull sensitivity when biting in the first few days is a normal occurrence; worsening pain, swelling, or fever is a reason for an unscheduled visit', 'Tupa osjetljivost pri zagrizanju prvih dana je uobičajena pojava; pojačana bol, oticanje ili povišena temperatura razlog su za vanredni pregled', 'Тупа осјетљивост при загризању првих дана је уобичајена појава; појачана бол, отицање или повишена температура разлог су за ванредни преглед', 'Ноющая чувствительность при накусывании в первые дни — обычное явление; усиливающаяся боль, отёк или температура — повод для внепланового визита', 'Ein dumpfes Gefühl beim Zubeißen in den ersten Tagen ist normal; zunehmende Schmerzen, Schwellung oder Fieber sind ein Grund für einen außerplanmäßigen Termin', 'İlk günlerde ısırırken hissedilen künt hassasiyet normal bir durumdur; artan ağrı, şişlik veya ateş plansız bir ziyareti gerektirir')
