INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'teeth-whitening'), 'Lightening the color of tooth enamel using a peroxide-based whitening gel', 'Posvjetljivanje boje cakline pomoću gela za izbjeljivanje na bazi peroksida', 'Посвјетљивање боје цаклине помоћу гела за избјељивање на бази пероксида', 'Осветление цвета эмали с помощью отбеливающего геля на основе пероксида', 'Aufhellung der Zahnschmelzfarbe mit einem peroxidhaltigen Bleichgel', 'Peroksit bazlı beyazlatma jeli kullanılarak diş minesinin renginin açılması', 'Applying the gel to the teeth in-office under a lamp or activator light, or wearing custom trays with gel at home; the in-office procedure takes 45-60 minutes per visit, the at-home method takes several days to weeks', 'Nanošenje gela na zube u ordinaciji uz lampu ili aktivator, ili nošenje individualnih kapa sa gelom kod kuće; ordinacijska procedura traje 45-60 minuta po posjeti, kućna nekoliko dana do nekoliko sedmica', 'Наношење гела на зубе у ординацији уз лампу или активатор, или ношење индивидуалних капа са гелом код куће; ординацијска процедура траје 45-60 минута по посјети, кућна неколико дана до неколико седмица', 'Нанесение геля на зубы в кабинете под лампой или активатором, либо ношение индивидуальных кап с гелем дома; кабинетная процедура — 45-60 минут за визит, домашняя — несколько дней-недель', 'Auftragen des Gels auf die Zähne in der Praxis unter einer Lampe oder einem Aktivator, oder Tragen individueller Schienen mit Gel zu Hause; die Behandlung in der Praxis dauert 45-60 Minuten pro Termin, die Anwendung zu Hause mehrere Tage bis Wochen', 'Jelin klinikte bir lamba veya aktivatör altında dişlere uygulanması ya da evde jelli özel plaklar takılması; klinik uygulaması seans başına 45-60 dakika, evde uygulama birkaç gün ile birkaç hafta sürer', 'Wanting to lighten the natural tooth color or remove staining caused by age, coffee, tea, or smoking', 'Želja za posvjetljivanjem prirodne boje zuba ili uklanjanjem potamnjenja usljed starosti, kafe, čaja ili pušenja', 'Жеља за посвјетљивањем природне боје зуба или уклањањем потамњења усљед старости, кафе, чаја или пушења', 'Желание осветлить естественный цвет зубов или устранить потемнение от возраста, кофе, чая, курения', 'Wunsch, die natürliche Zahnfarbe aufzuhellen oder Verfärbungen durch Alter, Kaffee, Tee oder Rauchen zu entfernen', 'Doğal diş renginin açılması veya yaş, kahve, çay ya da sigaraya bağlı renk koyulaşmasının giderilmesi isteği', 'A professional teeth cleaning before whitening is recommended; treatment of cavities and cracks should be completed beforehand', 'Poželjno je uraditi profesionalno čišćenje zuba prije izbjeljivanja; liječenje karijesa i pukotina treba biti završeno unaprijed', 'Пожељно је урадити професионално чишћење зуба прије избјељивања; лијечење каријеса и пукотина треба бити завршено унапријед', 'Желательна профессиональная чистка зубов до отбеливания; лечение кариеса и трещин должно быть завершено заранее', 'Eine professionelle Zahnreinigung vor dem Bleaching wird empfohlen; die Behandlung von Karies und Rissen sollte vorher abgeschlossen sein', 'Beyazlatmadan önce profesyonel diş temizliği yapılması önerilir; çürük ve çatlak tedavilerinin önceden tamamlanmış olması gerekir', 'Increased tooth sensitivity and mild gum irritation in the first few days are a common and usually temporary reaction; if sensitivity is severe or persists for a long time, it is worth seeing a dentist', 'Pojačana osjetljivost zuba i blaga iritacija desni prvih dana su česta i obično prolazna reakcija; ako je osjetljivost jaka ili se dugo ne povlači, treba se obratiti stomatologu', 'Појачана осјетљивост зуба и блага иритација десни првих дана су честа и обично пролазна реакција; ако је осјетљивост јака или се дуго не повлачи, треба се обратити стоматологу', 'Повышенная чувствительность зубов и лёгкое раздражение дёсен в первые дни — частая и обычно временная реакция; если чувствительность сильная или долго не проходит, стоит обратиться к стоматологу', 'Erhöhte Zahnempfindlichkeit und leichte Zahnfleischreizung in den ersten Tagen sind eine häufige und meist vorübergehende Reaktion; ist die Empfindlichkeit stark oder hält sie lange an, sollte ein Zahnarzt aufgesucht werden', 'İlk günlerde artan diş hassasiyeti ve hafif diş eti tahrişi yaygın ve genellikle geçici bir tepkidir; hassasiyet şiddetliyse veya uzun süre geçmiyorsa diş hekimine başvurmakta fayda vardır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'dental-consultation'), 'An initial examination by a dentist to assess the condition of the teeth and draw up a treatment plan', 'Prvi pregled kod stomatologa sa procjenom stanja zuba i izradom plana liječenja', 'Први преглед код стоматолога са процјеном стања зуба и израдом плана лијечења', 'Первичный осмотр стоматологом с оценкой состояния зубов и составлением плана лечения', 'Eine erste Untersuchung durch den Zahnarzt zur Beurteilung des Zahnzustands und Erstellung eines Behandlungsplans', 'Diş hekimi tarafından dişlerin durumunun değerlendirildiği ve tedavi planının oluşturulduğu ilk muayene', 'A discussion of symptoms, visual examination of the mouth, X-rays if needed; usually 20-30 minutes, one visit', 'Razgovor o tegobama, vizuelni pregled usne duplje, po potrebi snimci; obično 20-30 minuta, jedna posjeta', 'Разговор о тегобама, визуелни преглед усне дупље, по потреби снимци; обично 20-30 минута, једна посјета', 'Опрос, визуальный осмотр полости рта, при необходимости — снимки; обычно 20-30 минут, один визит', 'Anamnesegespräch, visuelle Untersuchung der Mundhöhle, bei Bedarf Röntgenaufnahmen; in der Regel 20-30 Minuten, ein Termin', 'Şikayetlerin sorulması, ağız içinin görsel muayenesi, gerekirse röntgen; genellikle 20-30 dakika, bir seans', 'A routine check-up, pain or discomfort, planning prosthetic or orthodontic treatment, a first visit to a new dentist', 'Redovni pregled, bol ili nelagodnost, planiranje protetike ili ortodontske terapije, prvi odlazak kod novog stomatologa', 'Редовни преглед, бол или нелагодност, планирање протетике или ортодонтске терапије, први одлазак код новог стоматолога', 'Плановый осмотр, боль или дискомфорт, планирование протезирования или ортодонтического лечения, первое обращение к новому стоматологу', 'Routineuntersuchung, Schmerzen oder Beschwerden, Planung von Zahnersatz oder einer kieferorthopädischen Behandlung, erster Besuch bei einem neuen Zahnarzt', 'Rutin kontrol, ağrı veya rahatsızlık, protez veya ortodontik tedavi planlaması, yeni bir diş hekimine ilk başvuru', 'No special preparation is required; it is helpful to bring previous X-rays and a list of medications being taken', 'Posebna priprema nije potrebna; korisno je ponijeti prethodne snimke i spisak lijekova koje uzimate', 'Посебна припрема није потребна; корисно је понијети претходне снимке и списак лијекова које узимате', 'Специальной подготовки не требуется; полезно взять с собой предыдущие снимки и список принимаемых лекарств', 'Keine besondere Vorbereitung erforderlich; es ist hilfreich, vorhandene Röntgenbilder und eine Liste der eingenommenen Medikamente mitzubringen', 'Özel bir hazırlık gerekmez; önceki röntgenleri ve kullanılan ilaçların listesini getirmek faydalıdır', 'Not applicable — this is a diagnostic visit; based on it the dentist will suggest further examination or treatment', 'Nije primjenjivo — riječ je o dijagnostičkom pregledu; na osnovu njega stomatolog će predložiti dalju dijagnostiku ili liječenje', 'Није примјењиво — ријеч је о дијагностичком прегледу; на основу њега стоматолог ће предложити даљу дијагностику или лијечење', 'Не применимо — это диагностический приём; по его итогам стоматолог предложит дальнейшее обследование или лечение', 'Nicht zutreffend — es handelt sich um einen diagnostischen Termin; auf dessen Grundlage schlägt der Zahnarzt weitere Untersuchungen oder eine Behandlung vor', 'Uygulanamaz — bu tanısal bir ziyarettir; sonucuna göre diş hekimi ileri inceleme veya tedavi önerecektir')
