INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'periodontal-scaling-root-planing'), 'Deep cleaning below the gumline with smoothing of the root surface for gum disease', 'Duboko čišćenje ispod desni sa izravnavanjem površine korijena kod bolesti desni', 'Дубоко чишћење испод десни са изравнавањем површине коријена код болести десни', 'Глубокая чистка под десной с выравниванием поверхности корня при заболеваниях дёсен', 'Tiefenreinigung unterhalb des Zahnfleischrands mit Glättung der Wurzeloberfläche bei Zahnfleischerkrankungen', 'Diş eti hastalıklarında diş eti altının derinlemesine temizlenmesi ve kök yüzeyinin düzleştirilmesi', 'Removing tartar and plaque from periodontal pockets with hand instruments or ultrasound, followed by root smoothing; under local anesthesia, usually 1-2 visits (half the jaw at a time)', 'Uklanjanje kamenca i naslaga iz parodontalnih džepova ručnim instrumentima ili ultrazvukom uz poliranje korijena; u lokalnoj anesteziji, obično 1-2 posjete (po polovina vilice odjednom)', 'Уклањање каменца и наслага из пародонталних џепова ручним инструментима или ултразвуком уз полирање коријена; у локалној анестезији, обично 1-2 посјете (по половина вилице одједном)', 'Удаление зубного камня и налёта из пародонтальных карманов ручными инструментами или ультразвуком с полировкой корня; под местной анестезией, обычно 1-2 визита (по половине челюсти за раз)', 'Entfernen von Zahnstein und Belag aus den Parodontaltaschen mit Handinstrumenten oder Ultraschall, anschließendes Glätten der Wurzel; unter Lokalanästhesie, in der Regel 1-2 Termine (jeweils eine Kieferhälfte)', 'Periodontal ceplerden diş taşı ve plağın el aletleri veya ultrasonla temizlenmesi ve kök yüzeyinin düzleştirilmesi; lokal anestezi altında, genellikle 1-2 seans (her seferinde çenenin yarısı)', 'Periodontitis, bleeding and inflamed gums, periodontal pockets deeper than 3-4 mm', 'Parodontitis, krvarenje i upala desni, parodontalni džepovi dublji od 3-4 mm', 'Пародонтитис, крварење и упала десни, пародонтални џепови дубљи од 3-4 мм', 'Пародонтит, кровоточивость и воспаление дёсен, пародонтальные карманы глубже 3-4 мм', 'Parodontitis, blutendes und entzündetes Zahnfleisch, Parodontaltaschen tiefer als 3-4 mm', 'Periodontitis, diş etinde kanama ve iltihaplanma, 3-4 mm''den derin periodontal cepler', 'No special preparation is required; inform the dentist about any anticoagulants being taken', 'Posebna priprema nije potrebna; obavijestiti o uzimanju antikoagulansa', 'Посебна припрема није потребна; обавијестити о узимању антикоагуланса', 'Специальной подготовки не требуется; сообщить о приёме антикоагулянтов', 'Keine besondere Vorbereitung erforderlich; über eingenommene Blutgerinnungshemmer informieren', 'Özel bir hazırlık gerekmez; kullanılan kan sulandırıcı ilaçlar hakkında bilgi verilmelidir', 'Tooth sensitivity, mild bleeding, and sore gums in the first few days are an expected reaction; if inflammation does not subside within 1-2 weeks or the pockets do not shrink, a follow-up examination with a periodontist is needed', 'Osjetljivost zuba, blago krvarenje i bolna desni prvih dana su očekivana reakcija; ako se upala ne povuče za 1-2 sedmice ili se džepovi ne smanje, potreban je kontrolni pregled kod parodontologa', 'Осјетљивост зуба, благо крварење и болна десни првих дана су очекивана реакција; ако се упала не повуче за 1-2 седмице или се џепови не смање, потребан је контролни преглед код пародонтолога', 'Чувствительность зубов, лёгкая кровоточивость и болезненность дёсен в первые дни — ожидаемая реакция; если воспаление не спадает через 1-2 недели или карманы не уменьшаются, нужен повторный осмотр у пародонтолога', 'Zahnempfindlichkeit, leichte Blutung und schmerzendes Zahnfleisch in den ersten Tagen sind eine zu erwartende Reaktion; klingt die Entzündung nicht innerhalb von 1-2 Wochen ab oder verkleinern sich die Taschen nicht, ist eine Nachuntersuchung beim Parodontologen erforderlich', 'İlk günlerde diş hassasiyeti, hafif kanama ve diş etinde ağrı beklenen bir tepkidir; iltihap 1-2 hafta içinde gerilemezse veya cepler küçülmezse periodontologla kontrol muayenesi gereklidir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'fixed-braces-metal-per-jaw'), 'A fixed orthodontic system of metal brackets and an archwire for one jaw, used to correct the bite and tooth position', 'Fiksni ortodontski aparat od metalnih bravica i žice za jednu vilicu, za ispravljanje zagriza i položaja zuba', 'Фиксни ортодонтски апарат од металних бравица и жице за једну вилицу, за исправљање загриза и положаја зуба', 'Несъёмная ортодонтическая система из металлических брекетов и дуги на одну челюсть для исправления прикуса и положения зубов', 'Eine festsitzende kieferorthopädische Apparatur aus Metallbrackets und einem Bogen für einen Kiefer zur Korrektur von Biss und Zahnstellung', 'Isırma ve diş konumunu düzeltmek için tek bir çene için metal braketler ve teldan oluşan sabit ortodontik sistem', 'Bonding the brackets to the teeth with composite adhesive and placing the archwire; the placement itself takes 1-1.5 hours, followed by monthly visits to adjust the archwire throughout treatment', 'Lijepljenje bravica na zube kompozitnim ljepilom i postavljanje žice; samo postavljanje traje 1-1,5 sat, a zatim slijede mjesečne posjete radi korekcije žice tokom cijelog liječenja', 'Лијепљење бравица на зубе композитним љепилом и постављање жице; само постављање траје 1-1,5 сат, а затим слиједе мјесечне посјете ради корекције жице током цијелог лијечења', 'Фиксация брекетов на зубы композитным клеем и установка дуги; сама установка занимает 1-1.5 часа, далее — ежемесячные визиты для коррекции дуги на протяжении лечения', 'Kleben der Brackets auf die Zähne mit Kompositkleber und Einsetzen des Bogens; das Einsetzen selbst dauert 1-1,5 Stunden, danach folgen monatliche Termine zur Anpassung des Bogens während der gesamten Behandlung', 'Braketlerin kompozit yapıştırıcıyla dişlere yapıştırılması ve telin takılması; takma işlemi 1-1,5 saat sürer, ardından tedavi boyunca telin ayarlanması için aylık ziyaretler yapılır', 'Crowded teeth, malocclusion, gaps between teeth, preparation for prosthetic treatment', 'Zbijenost zuba, nepravilan zagriz, razmaci između zuba, priprema za protetiku', 'Збијеност зуба, неправилан загриз, размаци између зуба, припрема за протетику', 'Скученность зубов, неправильный прикус, промежутки между зубами, подготовка к протезированию', 'Zahnengstand, Fehlbiss, Zahnlücken, Vorbereitung auf Zahnersatz', 'Diş sıkışıklığı, kapanış bozukluğu, dişler arası boşluklar, protez tedavisine hazırlık', 'Oral health should ideally be addressed beforehand — treating cavities and a professional cleaning', 'Poželjna je sanacija usne duplje — liječenje karijesa i profesionalno čišćenje — prije postavljanja', 'Пожељна је санација усне дупље — лијечење каријеса и професионално чишћење — прије постављања', 'Желательна санация полости рта — лечение кариеса и профессиональная чистка — до установки', 'Eine Sanierung der Mundhöhle — Behandlung von Karies und professionelle Zahnreinigung — vor dem Einsetzen ist empfehlenswert', 'Takmadan önce ağız sağlığının düzenlenmesi — çürük tedavisi ve profesyonel temizlik — önerilir', 'Discomfort and tooth soreness when biting in the first few days after placement and after each adjustment are normal; the archwire rubbing against the cheeks or lips, or a bracket coming loose, are reasons to see an orthodontist', 'Nelagodnost i bolna osjetljivost zuba pri zagrizanju prvih dana nakon postavljanja i poslije svake korekcije su normalni; nažuljena obraza ili usne od žice, kao i odlijepljena bravica, razlog su za obraćanje ortodontu', 'Нелагодност и болна осјетљивост зуба при загризању првих дана након постављања и послије сваке корекције су нормални; нажуљена образа или усне од жице, као и одлијепљена бравица, разлог су за обраћање ортодонту', 'Дискомфорт и болезненность зубов при накусывании в первые дни после установки и после каждой коррекции — норма; натирание щёк или губ дугой, а также отклеившийся брекет — повод обратиться к ортодонту', 'Unbehagen und Druckempfindlichkeit der Zähne beim Zubeißen in den ersten Tagen nach dem Einsetzen und nach jeder Anpassung sind normal; wenn der Bogen an Wangen oder Lippen reibt oder sich ein Bracket löst, sollte ein Kieferorthopäde aufgesucht werden', 'Takıldıktan sonraki ilk günlerde ve her ayardan sonra ısırırken hissedilen rahatsızlık ve diş hassasiyeti normaldir; telin yanakları veya dudakları tahriş etmesi ya da bir braketin yerinden çıkması durumunda ortodontiste başvurulmalıdır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'ultrasound-therapy'), 'A physiotherapy procedure in which ultrasound waves act on tissue to relieve pain and reduce inflammation', 'Fizioterapeutska procedura kod koje ultrazvučni talasi djeluju na tkivo radi ublažavanja bola i upale', 'Физиотерапеутска процедура код које ултразвучни таласи дјелују на ткиво ради ублажавања бола и упале', 'Физиотерапевтическая процедура, при которой ультразвуковые волны воздействуют на ткани для снятия боли и воспаления', 'Eine physiotherapeutische Behandlung, bei der Ultraschallwellen auf das Gewebe einwirken, um Schmerzen und Entzündungen zu lindern', 'Ultrason dalgalarının ağrı ve iltihabı azaltmak için dokuya uygulandığı bir fizyoterapi yöntemi', 'The doctor applies gel to the skin and moves a special applicator over the affected area; the session lasts 5–10 minutes', 'Ljekar nanosi gel na kožu i vodi posebnim aplikatorom preko problematične zone; seansa traje 5–10 minuta', 'Љекар наноси гел на кожу и води посебним апликатором преко проблематичне зоне; сеанса траје 5–10 минута', 'Врач наносит гель на кожу и водит специальным аппликатором по проблемной зоне; сеанс длится 5–10 минут', 'Der Arzt trägt Gel auf die Haut auf und führt einen speziellen Applikator über die betroffene Stelle; die Sitzung dauert 5–10 Minuten', 'Hekim cilde jel uygular ve özel bir uygulayıcıyı sorunlu bölge üzerinde gezdirir; seans 5–10 dakika sürer', 'Muscle and joint pain, tendon inflammation, sprains, rehabilitation after injuries', 'Bolovi u mišićima i zglobovima, upala tetiva, uganuća, rehabilitacija poslije povreda', 'Болови у мишићима и зглобовима, упала тетива, уганућа, рехабилитација послије повреда', 'Боли в мышцах и суставах, воспаление сухожилий, растяжения, реабилитация после травм', 'Muskel- und Gelenkschmerzen, Sehnenentzündungen, Verstauchungen, Rehabilitation nach Verletzungen', 'Kas ve eklem ağrıları, tendon iltihabı, burkulmalar, yaralanma sonrası rehabilitasyon', 'No special preparation is required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Es ist keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'This is a treatment, not a diagnostic procedure — the physiotherapist assesses effectiveness and course length based on how symptoms progress; if there is no improvement, a follow-up visit is recommended', 'Ovo je terapijska, a ne dijagnostička procedura — efikasnost i trajanje tretmana procjenjuje fizioterapeut prema toku simptoma; ako nema poboljšanja, treba se ponovo obratiti ljekaru', 'Ово је терапијска, а не дијагностичка процедура — ефикасност и трајање третмана процјењује физиотерапеут према току симптома; ако нема побољшања, треба се поново обратити љекару', 'Это лечебная, а не диагностическая процедура — эффективность и длительность курса оценивает врач-физиотерапевт по динамике симптомов; при отсутствии улучшения стоит обратиться к нему повторно', 'Dies ist eine Behandlung, keine diagnostische Untersuchung — Wirksamkeit und Dauer der Behandlung beurteilt der Physiotherapeut anhand des Symptomverlaufs; bei ausbleibender Besserung wird ein erneuter Termin empfohlen', 'Bu tanısal değil tedavi amaçlı bir işlemdir — etkinliği ve tedavi süresini fizyoterapist semptomların seyrine göre değerlendirir; iyileşme olmazsa hekime tekrar başvurulması önerilir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'laser-therapy'), 'Physiotherapy treatment using low-intensity laser light to relieve pain and speed up tissue healing', 'Fizioterapeutski tretman niskointenzivnim laserskim zračenjem radi ublažavanja bola i ubrzanja zarastanja tkiva', 'Физиотерапеутски третман нискоинтензивним ласерским зрачењем ради ублажавања бола и убрзања зарастања ткива', 'Физиотерапевтическое лечение низкоинтенсивным лазерным излучением для снятия боли и ускорения заживления тканей', 'Physiotherapeutische Behandlung mit niedrig dosiertem Laserlicht zur Schmerzlinderung und Beschleunigung der Gewebeheilung', 'Ağrıyı azaltmak ve doku iyileşmesini hızlandırmak için düşük yoğunluklu lazer ışığı kullanan fizyoterapi yöntemi', 'The doctor or physiotherapist directs a laser applicator at the target area of skin; the procedure is painless and takes 5–15 minutes', 'Ljekar ili fizioterapeut usmjerava laserski aplikator na odgovarajuću zonu kože; procedura je bezbolna i traje 5–15 minuta', 'Љекар или физиотерапеут усмјерава ласерски апликатор на одговарајућу зону коже; процедура је безболна и траје 5–15 минута', 'Врач или физиотерапевт направляет лазерный аппликатор на нужную зону кожи; процедура безболезненна и занимает 5–15 минут', 'Der Arzt oder Physiotherapeut richtet einen Laserapplikator auf die betroffene Hautstelle; der Vorgang ist schmerzlos und dauert 5–15 Minuten', 'Hekim veya fizyoterapist lazer uygulayıcısını ilgili cilt bölgesine yöneltir; işlem ağrısızdır ve 5–15 dakika sürer', 'Joint and muscle pain, inflammatory processes, slow wound healing, rehabilitation after injuries', 'Bolovi u zglobovima i mišićima, upalni procesi, usporeno zarastanje rana, rehabilitacija poslije povreda', 'Болови у зглобовима и мишићима, упални процеси, успорено зарастање рана, рехабилитација послије повреда', 'Боли в суставах и мышцах, воспалительные процессы, замедленное заживление ран, реабилитация после травм', 'Gelenk- und Muskelschmerzen, entzündliche Prozesse, verzögerte Wundheilung, Rehabilitation nach Verletzungen', 'Eklem ve kas ağrıları, iltihabi süreçler, yara iyileşmesinde gecikme, yaralanma sonrası rehabilitasyon', 'No special preparation is required', 'Nije potrebna posebna priprema', 'Није потребна посебна припрема', 'Специальной подготовки не требуется', 'Es ist keine besondere Vorbereitung erforderlich', 'Özel bir hazırlık gerekmez', 'If there is no improvement after a course of treatment, see a doctor to reassess the diagnosis and treatment plan', 'Ako poslije niza procedura ne dođe do poboljšanja, treba se obratiti ljekaru radi preciziranja dijagnoze i plana liječenja', 'Ако послије низа процедура не дође до побољшања, треба се обратити љекару ради прецизирања дијагнозе и плана лијечења', 'Если после курса процедур улучшения не наступает, необходимо обратиться к врачу для уточнения диагноза и плана лечения', 'Tritt nach einer Behandlungsserie keine Besserung ein, sollte ein Arzt zur Abklärung der Diagnose und des Behandlungsplans aufgesucht werden', 'Bir dizi seans sonrasında iyileşme görülmezse, tanının ve tedavi planının gözden geçirilmesi için hekime başvurulmalıdır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'shock-wave-therapy'), 'A physiotherapy method that uses acoustic shock waves to treat chronic pain in muscles and tendons', 'Metoda fizioterapije koja koristi akustične udarne talase za liječenje hroničnih bolova u mišićima i tetivama', 'Метода физиотерапије која користи акустичне ударне таласе за лијечење хроничних болова у мишићима и тетивама', 'Метод физиотерапии, использующий акустические ударные волны для лечения хронических болей в мышцах и сухожилиях', 'Ein physiotherapeutisches Verfahren, das akustische Stoßwellen zur Behandlung chronischer Schmerzen in Muskeln und Sehnen einsetzt', 'Kas ve tendonlardaki kronik ağrıları tedavi etmek için akustik şok dalgaları kullanan bir fizyoterapi yöntemi', 'The doctor applies an applicator to the painful area and delivers wave pulses; the sensation can be slightly uncomfortable, and the procedure lasts 10–20 minutes', 'Ljekar prislanja aplikator na bolno mjesto i emituje impulse talasa; osjećaj može biti pomalo neprijatan, procedura traje 10–20 minuta', 'Љекар прислања апликатор на болно мјесто и емитује импулсе таласа; осјећај може бити помало непријатан, процедура траје 10–20 минута', 'Врач прикладывает аппликатор к болезненной зоне и подаёт импульсы волн; ощущения могут быть слегка неприятными, процедура длится 10–20 минут', 'Der Arzt setzt einen Applikator auf die schmerzende Stelle und gibt Wellenimpulse ab; das Gefühl kann leicht unangenehm sein, die Behandlung dauert 10–20 Minuten', 'Hekim ağrılı bölgeye bir uygulayıcı yerleştirir ve dalga darbeleri verir; his hafif rahatsız edici olabilir, işlem 10–20 dakika sürer', 'Heel spur, tendinitis, ligament inflammation, chronic musculoskeletal pain syndromes', 'Peta ostruga, tendinitis, upala ligamenata, hronični bolni sindromi lokomotornog sistema', 'Пета оструга, тендинитис, упала лигамената, хронични болни синдроми локомоторног система', 'Пяточная шпора, тендиниты, воспаление связок, хронические болевые синдромы опорно-двигательного аппарата', 'Fersensporn, Sehnenentzündungen, Bänderentzündungen, chronische Schmerzsyndrome des Bewegungsapparats', 'Topuk dikeni, tendinit, bağ iltihabı, kas-iskelet sisteminin kronik ağrı sendromları', 'No special preparation is required; the doctor may recommend avoiding painkillers before the session', 'Nije potrebna posebna priprema; ljekar može preporučiti da se prije seanse ne uzimaju analgetici', 'Није потребна посебна припрема; љекар може препоручити да се прије сеансе не узимају аналгетици', 'Специальной подготовки не требуется; врач может рекомендовать не принимать обезболивающие перед сеансом', 'Es ist keine besondere Vorbereitung erforderlich; der Arzt kann empfehlen, vor der Sitzung keine Schmerzmittel einzunehmen', 'Özel bir hazırlık gerekmez; hekim seanstan önce ağrı kesici alınmamasını önerebilir', 'If pain persists after several sessions, a follow-up consultation is needed to reconsider the treatment approach', 'Ako bol potraje i nakon nekoliko seansi, potrebna je nova konsultacija sa ljekarom radi izmjene taktike liječenja', 'Ако бол потраје и након неколико сеанси, потребна је нова консултација са љекаром ради измјене тактике лијечења', 'Если боль сохраняется после нескольких сеансов, нужна повторная консультация врача для пересмотра тактики лечения', 'Hält der Schmerz nach mehreren Sitzungen an, ist eine erneute ärztliche Beratung notwendig, um die Behandlungsstrategie zu überdenken', 'Ağrı birkaç seans sonrasında da devam ederse, tedavi yaklaşımının gözden geçirilmesi için hekimle tekrar görüşülmelidir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'kinesiotherapy'), 'Therapeutic exercise — a set of exercises to restore mobility, strength and coordination', 'Kineziterapija — skup vježbi za obnavljanje pokretljivosti, snage i koordinacije', 'Кинезитерапија — скуп вјежби за обнављање покретљивости, снаге и координације', 'Лечебная физкультура — комплекс упражнений для восстановления подвижности, силы и координации', 'Bewegungstherapie — ein Übungsprogramm zur Wiederherstellung von Beweglichkeit, Kraft und Koordination', 'Terapötik egzersiz — hareket kabiliyeti, kuvvet ve koordinasyonu yeniden kazandırmaya yönelik egzersiz programı', 'The patient performs exercises under the supervision of an instructor or physiotherapist, individually or in a group; a session lasts 30–60 minutes', 'Pacijent izvodi vježbe pod nadzorom instruktora ili ljekara-fizioterapeuta, individualno ili u grupi; termin traje 30–60 minuta', 'Пацијент изводи вјежбе под надзором инструктора или љекара-физиотерапеута, индивидуално или у групи; термин траје 30–60 минута', 'Пациент выполняет упражнения под контролем инструктора или врача-физиотерапевта, индивидуально или в группе; занятие длится 30–60 минут', 'Der Patient führt die Übungen unter Anleitung eines Trainers oder Physiotherapeuten einzeln oder in der Gruppe durch; eine Einheit dauert 30–60 Minuten', 'Hasta, bir eğitmen veya fizyoterapist gözetiminde bireysel ya da grup halinde egzersizler yapar; seans 30–60 dakika sürer', 'Rehabilitation after injuries and surgery, musculoskeletal conditions, posture problems, chronic back pain', 'Rehabilitacija poslije povreda i operacija, oboljenja lokomotornog sistema, poremećaji držanja tijela, hronični bolovi u leđima', 'Рехабилитација послије повреда и операција, обољења локомоторног система, поремећаји држања тијела, хронични болови у леђима', 'Реабилитация после травм и операций, заболевания опорно-двигательного аппарата, нарушения осанки, хронические боли в спине', 'Rehabilitation nach Verletzungen und Operationen, Erkrankungen des Bewegungsapparats, Haltungsschäden, chronische Rückenschmerzen', 'Yaralanma ve ameliyat sonrası rehabilitasyon, kas-iskelet sistemi hastalıkları, duruş bozuklukları, kronik sırt ağrıları', 'Comfortable clothing and shoes for exercising; no special preparation is required', 'Udobna odjeća i obuća za vježbanje; nije potrebna posebna priprema', 'Удобна одјећа и обућа за вјежбање; није потребна посебна припрема', 'Удобная одежда и обувь для занятий; специальной подготовки не требуется', 'Bequeme Kleidung und Schuhe zum Üben; es ist keine besondere Vorbereitung erforderlich', 'Egzersiz için rahat kıyafet ve ayakkabı; özel bir hazırlık gerekmez', 'If exercises cause increased pain or discomfort, this should be reported to the doctor or instructor so the program can be adjusted', 'Ako vježbe izazivaju pojačan bol ili nelagodu, o tome treba obavijestiti ljekara ili instruktora radi prilagođavanja programa', 'Ако вјежбе изазивају појачан бол или нелагоду, о томе треба обавијестити љекара или инструктора ради прилагођавања програма', 'Если упражнения вызывают усиление боли или дискомфорт, об этом нужно сообщить врачу или инструктору для корректировки программы', 'Verursachen die Übungen verstärkte Schmerzen oder Beschwerden, sollte dies dem Arzt oder Trainer gemeldet werden, damit das Programm angepasst werden kann', 'Egzersizler ağrı veya rahatsızlığı artırıyorsa, programın uyarlanması için bu durum hekime veya eğitmene bildirilmelidir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'manual-therapy'), 'A hands-on treatment method — the doctor works on the joints, muscles and spine to relieve pain and restore mobility', 'Metoda liječenja rukama — ljekar djeluje na zglobove, mišiće i kičmu radi ublažavanja bola i uspostavljanja pokretljivosti', 'Метода лијечења рукама — љекар дјелује на зглобове, мишиће и кичму ради ублажавања бола и успостављања покретљивости', 'Метод лечения руками — врач воздействует на суставы, мышцы и позвоночник для снятия боли и восстановления подвижности', 'Eine manuelle Behandlungsmethode — der Arzt behandelt Gelenke, Muskeln und Wirbelsäule, um Schmerzen zu lindern und die Beweglichkeit wiederherzustellen', 'Elle uygulanan bir tedavi yöntemi — hekim ağrıyı azaltmak ve hareket kabiliyetini yeniden kazandırmak için eklemlere, kaslara ve omurgaya müdahale eder', 'The doctor performs mobilisation and gentle manipulation on the affected areas of the body; the session takes 20–40 minutes', 'Ljekar izvodi mobilizaciju i blage manipulacije na problematičnim dijelovima tijela; seansa traje 20–40 minuta', 'Љекар изводи мобилизацију и благе манипулације на проблематичним дијеловима тијела; сеанса траје 20–40 минута', 'Врач выполняет мобилизацию и мягкие манипуляции на проблемных участках тела; сеанс занимает 20–40 минут', 'Der Arzt führt Mobilisationen und sanfte Handgriffe an den betroffenen Körperstellen durch; die Sitzung dauert 20–40 Minuten', 'Hekim vücudun sorunlu bölgelerinde mobilizasyon ve hafif manipülasyonlar uygular; seans 20–40 dakika sürer', 'Back and neck pain, restricted joint mobility, consequences of posture problems, rehabilitation', 'Bolovi u leđima i vratu, ograničena pokretljivost zglobova, posljedice poremećaja držanja tijela, rehabilitacija', 'Болови у леђима и врату, ограничена покретљивост зглобова, посљедице поремећаја држања тијела, рехабилитација', 'Боли в спине и шее, ограничение подвижности суставов, последствия нарушений осанки, реабилитация', 'Rücken- und Nackenschmerzen, eingeschränkte Gelenkbeweglichkeit, Folgen von Haltungsschäden, Rehabilitation', 'Sırt ve boyun ağrıları, eklem hareketliliğinde kısıtlanma, duruş bozukluklarının sonuçları, rehabilitasyon', 'No special preparation is required; comfortable clothing is recommended', 'Nije potrebna posebna priprema; preporučuje se udobna odjeća', 'Није потребна посебна припрема; препоручује се удобна одјећа', 'Специальной подготовки не требуется; рекомендуется удобная одежда', 'Es ist keine besondere Vorbereitung erforderlich; bequeme Kleidung wird empfohlen', 'Özel bir hazırlık gerekmez; rahat kıyafet giyilmesi önerilir', 'If there is no improvement or the pain increases, this should be reported to the doctor — further examination may be needed', 'Ako nema poboljšanja ili se bol pojača, potrebno je obavijestiti ljekara — možda će biti potreban dodatni pregled', 'Ако нема побољшања или се бол појача, потребно је обавијестити љекара — можда ће бити потребан додатни преглед', 'При отсутствии улучшения или усилении боли необходимо сообщить врачу — возможно, потребуется дополнительное обследование', 'Bei ausbleibender Besserung oder zunehmenden Schmerzen sollte dies dem Arzt mitgeteilt werden — eventuell ist eine weitere Untersuchung nötig', 'İyileşme olmazsa veya ağrı artarsa hekime bildirilmelidir — ek bir inceleme gerekebilir')
