INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'acupuncture'), 'A reflexotherapy method — thin needles are inserted at specific points on the body to relieve pain and improve wellbeing', 'Metoda refleksoterapije — ubadanje tankih igala u određene tačke na tijelu radi ublažavanja bola i poboljšanja opšteg stanja', 'Метода рефлексотерапије — убадање танких игала у одређене тачке на тијелу ради ублажавања бола и побољшања општег стања', 'Метод рефлексотерапии — введение тонких игл в определённые точки тела для облегчения боли и улучшения самочувствия', 'Eine Methode der Reflexzonentherapie — dünne Nadeln werden an bestimmten Körperpunkten gesetzt, um Schmerzen zu lindern und das Wohlbefinden zu verbessern', 'Bir refleksoterapi yöntemi — ağrıyı hafifletmek ve genel iyilik halini artırmak için vücuttaki belirli noktalara ince iğneler yerleştirilir', 'The doctor inserts sterile single-use needles to a shallow depth at selected points; the needles are left in place for 15–30 minutes', 'Ljekar uvodi sterilne igle za jednokratnu upotrebu na malu dubinu u odabrane tačke; igle se ostavljaju 15–30 minuta', 'Љекар уводи стерилне игле за једнократну употребу на малу дубину у одабране тачке; игле се остављају 15–30 минута', 'Врач вводит стерильные одноразовые иглы на небольшую глубину в выбранные точки; иглы оставляют на 15–30 минут', 'Der Arzt setzt sterile Einmalnadeln flach in ausgewählte Punkte; die Nadeln verbleiben 15–30 Minuten', 'Hekim steril tek kullanımlık iğneleri seçilen noktalara az derinlikte batırır; iğneler 15–30 dakika bırakılır', 'Chronic pain, migraine, stress and insomnia — as a complement to primary treatment prescribed by a doctor', 'Hronični bolovi, migrena, stres i nesanica — kao dopuna osnovnom liječenju po preporuci ljekara', 'Хронични болови, мигрена, стрес и несаница — као допуна основном лијечењу по препоруци љекара', 'Хронические боли, мигрень, стресс и бессонница — как дополнение к основному лечению по назначению врача', 'Chronische Schmerzen, Migräne, Stress und Schlaflosigkeit — als Ergänzung zur ärztlich verordneten Hauptbehandlung', 'Kronik ağrılar, migren, stres ve uykusuzluk — hekim tarafından belirlenen esas tedaviye ek olarak', 'Do not come on an empty stomach or in a state of strong emotional agitation; tell the doctor if you are taking anticoagulants', 'Ne dolaziti natašte niti u stanju jake emocionalne uzbuđenosti; obavijestiti ljekara o uzimanju antikoagulanasa', 'Не долазити наташте нити у стању јаке емоционалне узбуђености; обавијестити љекара о узимању антикоагуланаса', 'Не приходить натощак и в состоянии сильного эмоционального возбуждения; сообщить врачу о приёме антикоагулянтов', 'Nicht nüchtern und nicht in starker emotionaler Erregung erscheinen; den Arzt über die Einnahme von Antikoagulanzien informieren', 'Aç karnına veya yoğun duygusal gerginlik halinde gelinmemelidir; antikoagülan kullanıyorsanız hekime bildirin', 'If an unusual reaction occurs after the procedure (severe pain, prolonged redness), the doctor should be notified', 'Ako se poslije procedure javi neuobičajena reakcija (jak bol, dugotrajno crvenilo), potrebno je obavijestiti ljekara', 'Ако се послије процедуре јави неуобичајена реакција (јак бол, дуготрајно црвенило), потребно је обавијестити љекара', 'Если после процедуры возникает необычная реакция (сильная боль, длительное покраснение), нужно сообщить врачу', 'Tritt nach der Behandlung eine ungewöhnliche Reaktion auf (starke Schmerzen, anhaltende Rötung), sollte der Arzt informiert werden', 'İşlem sonrasında olağandışı bir tepki (şiddetli ağrı, uzun süreli kızarıklık) görülürse hekime bildirilmelidir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'colposcopy'), 'A gynaecological examination of the cervix using a colposcope, an instrument that provides a magnified view', 'Ginekološki pregled grlića materice pomoću kolposkopa, aparata koji daje uvećanu sliku', 'Гинеколошки преглед грлића материце помоћу колпоскопа, апарата који даје увећану слику', 'Гинекологическое обследование шейки матки с помощью прибора-кольпоскопа, дающего увеличенное изображение', 'Eine gynäkologische Untersuchung des Gebärmutterhalses mit einem Kolposkop, einem Gerät, das ein vergrößertes Bild liefert', 'Rahim ağzının, büyütülmüş görüntü sağlayan kolposkop adlı cihazla incelendiği jinekolojik muayene', 'The gynaecologist examines the cervix with a colposcope without inserting any instruments into the body, sometimes applying a solution to improve visualisation; it takes 10–15 minutes', 'Ginekolog pregleda grlić materice kolposkopom bez uvođenja instrumenata u tijelo, ponekad uz nanošenje rastvora radi bolje vidljivosti; traje 10–15 minuta', 'Гинеколог прегледа грлић материце колпоскопом без увођења инструмената у тијело, понекад уз наношење раствора ради боље видљивости; траје 10–15 минута', 'Врач-гинеколог осматривает шейку матки с помощью кольпоскопа без введения инструментов внутрь тела, иногда с обработкой раствором для лучшей визуализации; занимает 10–15 минут', 'Die Frauenärztin oder der Frauenarzt untersucht den Gebärmutterhals mit dem Kolposkop, ohne Instrumente in den Körper einzuführen, manchmal wird zur besseren Sichtbarkeit eine Lösung aufgetragen; die Untersuchung dauert 10–15 Minuten', 'Jinekolog, vücuda herhangi bir alet sokmadan rahim ağzını kolposkopla inceler, görüntüyü netleştirmek için bazen bir solüsyon uygulanır; işlem 10–15 dakika sürer', 'Routine gynaecological screening (usually every 1–3 years as recommended by a doctor), or following an atypical Pap smear result', 'Redovni ginekološki skrining (obično jednom u 1-3 godine po preporuci ljekara), kao i nakon netipičnog rezultata brisa na citologiju', 'Редовни гинеколошки скрининг (обично једном у 1-3 године по препоруци љекара), као и након нетипичног резултата бриса на цитологију', 'Плановый гинекологический скрининг (обычно раз в 1-3 года по рекомендации врача), а также после нетипичного результата мазка на цитологию', 'Routinemäßiges gynäkologisches Screening (in der Regel alle 1–3 Jahre nach ärztlicher Empfehlung) sowie nach einem auffälligen Pap-Abstrich', 'Rutin jinekolojik tarama (genellikle hekim önerisiyle 1-3 yılda bir) veya sitoloji smear testinde tipik olmayan bir sonuç sonrasında', 'Not performed during menstruation; it is recommended to avoid sexual intercourse, douching and vaginal products for 1–2 days before the exam', 'Ne obavlja se za vrijeme menstruacije; 1-2 dana prije pregleda preporučuje se izbjegavati polne odnose, tuširanje unutrašnjosti vagine i vaginalne preparate', 'Не обавља се за вријеме менструације; 1-2 дана прије прегледа препоручује се избјегавати полне односе, туширање унутрашњости вагине и вагиналне препарате', 'Не проводится во время менструации; за 1-2 дня до осмотра рекомендуется избегать половых контактов, спринцеваний и вагинальных препаратов', 'Wird nicht während der Menstruation durchgeführt; 1–2 Tage vor der Untersuchung sollte auf Geschlechtsverkehr, Vaginalspülungen und vaginale Präparate verzichtet werden', 'Adet döneminde uygulanmaz; muayeneden 1-2 gün önce cinsel ilişki, vajinal duş ve vajinal ürünlerden kaçınılması önerilir', 'Changed cells require further monitoring or a follow-up examination by a gynaecologist — no need to panic, most changes are not related to a malignant process', 'Promijenjene ćelije zahtijevaju dalje praćenje ili dodatni pregled kod ginekologa, bez panike — većina promjena nije povezana sa malignim procesom', 'Промијењене ћелије захтијевају даље праћење или додатни преглед код гинеколога, без панике — већина промјена није повезана са малигним процесом', 'Изменённые клетки требуют дальнейшего наблюдения или уточняющего обследования у гинеколога, без паники — большинство изменений не связаны со злокачественным процессом', 'Veränderte Zellen erfordern eine weitere Beobachtung oder eine ergänzende Untersuchung durch die Frauenärztin bzw. den Frauenarzt — kein Grund zur Panik, die meisten Veränderungen stehen nicht im Zusammenhang mit einem bösartigen Prozess', 'Değişmiş hücreler jinekolog tarafından daha ileri takip veya ek inceleme gerektirir — panik yapmaya gerek yok, değişikliklerin çoğu kötü huylu bir süreçle ilişkili değildir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'pap-test-with-smear-collection'), 'A screening test — cells are collected from the surface of the cervix for cytological examination', 'Skrining test — uzimanje ćelija sa površine grlića materice radi citološke analize', 'Скрининг тест — узимање ћелија са површине грлића материце ради цитолошке анализе', 'Скрининговый тест — забор клеток с поверхности шейки матки для цитологического исследования', 'Ein Screening-Test — von der Oberfläche des Gebärmutterhalses werden Zellen für eine zytologische Untersuchung entnommen', 'Bir tarama testi — sitolojik inceleme için rahim ağzı yüzeyinden hücre örneği alınır', 'The gynaecologist takes a smear with a small brush during a routine gynaecological exam; the procedure is quick and only mildly uncomfortable, taking a few minutes', 'Ginekolog uzima bris posebnom četkicom u toku redovnog ginekološkog pregleda; procedura je brza i gotovo bezbolna, traje nekoliko minuta', 'Гинеколог узима брис посебном четкицом у току редовног гинеколошког прегледа; процедура је брза и готово безболна, траје неколико минута', 'Врач-гинеколог берёт мазок специальной щёточкой во время обычного гинекологического осмотра; процедура быстрая и малоболезненная, занимает несколько минут', 'Die Frauenärztin oder der Frauenarzt entnimmt mit einem kleinen Bürstchen einen Abstrich im Rahmen einer routinemäßigen gynäkologischen Untersuchung; der Vorgang ist schnell und nur leicht unangenehm und dauert wenige Minuten', 'Jinekolog, rutin jinekolojik muayene sırasında özel bir fırçayla smear alır; işlem hızlıdır ve hafif rahatsızlık verir, birkaç dakika sürer', 'Routine gynaecological screening (usually every 1–3 years as recommended by a doctor)', 'Redovni ginekološki skrining (obično jednom u 1-3 godine po preporuci ljekara)', 'Редовни гинеколошки скрининг (обично једном у 1-3 године по препоруци љекара)', 'Плановый гинекологический скрининг (обычно раз в 1-3 года по рекомендации врача)', 'Routinemäßiges gynäkologisches Screening (in der Regel alle 1–3 Jahre nach ärztlicher Empfehlung)', 'Rutin jinekolojik tarama (genellikle hekim önerisiyle 1-3 yılda bir)', 'Not performed during menstruation; it is recommended to avoid sexual intercourse, douching, vaginal suppositories and creams for 1–2 days before the test', 'Ne obavlja se za vrijeme menstruacije; 1-2 dana prije testa preporučuje se izbjegavati polne odnose, tuširanje unutrašnjosti vagine, vaginalne globule i kreme', 'Не обавља се за вријеме менструације; 1-2 дана прије теста препоручује се избјегавати полне односе, туширање унутрашњости вагине, вагиналне глобуле и креме', 'Не проводится во время менструации; за 1-2 дня до теста рекомендуется избегать половых контактов, спринцеваний, вагинальных свечей и кремов', 'Wird nicht während der Menstruation durchgeführt; 1–2 Tage vor dem Test sollte auf Geschlechtsverkehr, Vaginalspülungen, Vaginalzäpfchen und -cremes verzichtet werden', 'Adet döneminde uygulanmaz; testten 1-2 gün önce cinsel ilişki, vajinal duş, vajinal fitil ve kremlerden kaçınılması önerilir', 'Changed cells require further monitoring or a follow-up examination by a gynaecologist — no need to panic, most changes are not related to a malignant process', 'Promijenjene ćelije zahtijevaju dalje praćenje ili dodatni pregled kod ginekologa, bez panike — većina promjena nije povezana sa malignim procesom', 'Промијењене ћелије захтијевају даље праћење или додатни преглед код гинеколога, без панике — већина промјена није повезана са малигним процесом', 'Изменённые клетки требуют дальнейшего наблюдения или уточняющего обследования у гинеколога, без паники — большинство изменений не связаны со злокачественным процессом', 'Veränderte Zellen erfordern eine weitere Beobachtung oder eine ergänzende Untersuchung durch die Frauenärztin bzw. den Frauenarzt — kein Grund zur Panik, die meisten Veränderungen stehen nicht im Zusammenhang mit einem bösartigen Prozess', 'Değişmiş hücreler jinekolog tarafından daha ileri takip veya ek inceleme gerektirir — panik yapmaya gerek yok, değişikliklerin çoğu kötü huylu bir süreçle ilişkili değildir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'ctg-fetal-monitoring'), 'Cardiotocography — a method for monitoring the fetal heartbeat and uterine contractions during pregnancy', 'Kardiotokografija — metoda praćenja otkucaja srca ploda i kontraktilne aktivnosti materice tokom trudnoće', 'Кардиотокографија — метода праћења откуцаја срца плода и контрактилне активности материце током трудноће', 'Кардиотокография — метод мониторинга сердцебиения плода и сократительной активности матки при беременности', 'Kardiotokographie (CTG) — eine Methode zur Überwachung des fetalen Herzschlags und der Gebärmutterkontraktionen während der Schwangerschaft', 'Kardiyotokografi (KTG) — gebelikte fetal kalp atışını ve rahim kasılmalarını izleme yöntemi', 'Sensors connected to a monitor are attached to the pregnant woman''s abdomen and record data for 20–40 minutes; the procedure is painless', 'Na stomak trudnice se postavljaju senzori povezani sa aparatom koji bilježi podatke u trajanju od 20–40 minuta; procedura je bezbolna', 'На стомак труднице се постављају сензори повезани са апаратом који биљежи податке у трајању од 20–40 минута; процедура је безболна', 'На живот беременной крепят датчики, соединённые с прибором, который записывает данные в течение 20–40 минут; процедура безболезненна', 'Der Schwangeren werden Sensoren am Bauch angebracht, die mit einem Gerät verbunden sind und 20–40 Minuten lang Daten aufzeichnen; der Vorgang ist schmerzlos', 'Gebe kadının karnına, verileri 20–40 dakika boyunca kaydeden bir cihaza bağlı sensörler yerleştirilir; işlem ağrısızdır', 'Routine monitoring in the third trimester of pregnancy, and during labour as directed by the obstetrician-gynaecologist', 'Redovno praćenje u trećem trimestru trudnoće, kao i tokom porođaja po nalogu ginekologa-akušera', 'Редовно праћење у трећем триместру трудноће, као и током порођаја по налогу гинеколога-акушера', 'Плановое наблюдение в третьем триместре беременности, а также в родах по назначению акушера-гинеколога', 'Routineüberwachung im dritten Trimester der Schwangerschaft sowie während der Geburt nach Anweisung des Facharztes bzw. der Fachärztin für Geburtshilfe', 'Gebeliğin üçüncü trimesterinde rutin izlem ve doğum sırasında kadın doğum uzmanının talimatıyla', 'No special preparation is required; it is recommended not to be hungry before the procedure, as this may affect fetal activity', 'Nije potrebna posebna priprema; preporučuje se da trudnica ne bude gladna prije procedure, jer to može uticati na aktivnost ploda', 'Није потребна посебна припрема; препоручује се да трудница не буде гладна прије процедуре, јер то може утицати на активност плода', 'Специальной подготовки не требуется; рекомендуется не быть голодной перед процедурой, так как это может повлиять на активность плода', 'Es ist keine besondere Vorbereitung erforderlich; es wird empfohlen, vor dem Vorgang nicht hungrig zu sein, da dies die Aktivität des Fötus beeinflussen kann', 'Özel bir hazırlık gerekmez; fetüsün hareketliliğini etkileyebileceğinden işlemden önce aç kalınmaması önerilir', 'The recording is assessed by the obstetrician-gynaecologist together with other data on the course of the pregnancy — self-interpretation of the result is not recommended', 'Zapis procjenjuje ginekolog-akušer u sklopu ostalih podataka o toku trudnoće — samostalno tumačenje rezultata se ne preporučuje', 'Запис процјењује гинеколог-акушер у склопу осталих података о току трудноће — самостално тумачење резултата се не препоручује', 'Запись оценивает акушер-гинеколог в комплексе с другими данными о течении беременности — самостоятельная интерпретация результата не рекомендуется', 'Die Aufzeichnung wird von der Fachärztin bzw. dem Facharzt für Geburtshilfe zusammen mit weiteren Daten zum Schwangerschaftsverlauf beurteilt — eine eigenständige Interpretation des Ergebnisses wird nicht empfohlen', 'Kayıt, gebeliğin seyrine ilişkin diğer verilerle birlikte kadın doğum uzmanı tarafından değerlendirilir — sonucun kendi başına yorumlanması önerilmez')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'iud-insertion'), 'Insertion of an intrauterine device (IUD) — a method of long-acting reversible contraception', 'Ugradnja spirale — metoda dugotrajne reverzibilne kontracepcije', 'Уградња спирале — метода дуготрајне реверзибилне контрацепције', 'Установка внутриматочной спирали — метод длительной обратимой контрацепции', 'Einsetzen einer Spirale (IUP) — eine Methode der langfristig wirksamen, reversiblen Verhütung', 'Rahim içi araç (RİA/spiral) takılması — uzun etkili, geri dönüşümlü bir doğum kontrol yöntemi', 'The gynaecologist inserts the IUD through the cervix into the uterine cavity using a special applicator; the procedure takes 10–15 minutes', 'Ginekolog uvodi spiralu kroz grlić materice u šupljinu materice pomoću posebnog aplikatora; procedura traje 10–15 minuta', 'Гинеколог уводи спиралу кроз грлић материце у шупљину материце помоћу посебног апликатора; процедура траје 10–15 минута', 'Врач-гинеколог вводит спираль через шейку матки в полость матки с помощью специального аппликатора; процедура занимает 10–15 минут', 'Die Frauenärztin bzw. der Frauenarzt führt die Spirale mit einem speziellen Applikator durch den Gebärmutterhals in die Gebärmutterhöhle ein; der Vorgang dauert 10–15 Minuten', 'Jinekolog, özel bir uygulayıcı yardımıyla spirali rahim ağzından rahim boşluğuna yerleştirir; işlem 10–15 dakika sürer', 'At the patient''s request as a method of contraception, following a consultation with a gynaecologist about the suitable type of IUD', 'Na želju pacijentkinje kao metoda kontracepcije, nakon konsultacije sa ginekologom o odgovarajućem tipu spirale', 'На жељу пацијенткиње као метода контрацепције, након консултације са гинекологом о одговарајућем типу спирале', 'По желанию пациентки как метод контрацепции, после консультации с гинекологом о подходящем типе спирали', 'Auf Wunsch der Patientin als Verhütungsmethode, nach einer Beratung mit der Frauenärztin bzw. dem Frauenarzt über den passenden Spiraltyp', 'Hastanın talebi doğrultusunda bir doğum kontrol yöntemi olarak, uygun spiral türü konusunda jinekologla görüşüldükten sonra', 'The procedure is usually performed on specific days of the menstrual cycle as recommended by the doctor; a prior consultation and gynaecological examination are required', 'Procedura se obično obavlja određenih dana menstrualnog ciklusa po preporuci ljekara; potrebna je prethodna konsultacija i pregled kod ginekologa', 'Процедура се обично обавља одређених дана менструалног циклуса по препоруци љекара; потребна је претходна консултација и преглед код гинеколога', 'Процедура обычно проводится в определённые дни менструального цикла по рекомендации врача; необходима предварительная консультация и осмотр у гинеколога', 'Der Eingriff wird meist an bestimmten Tagen des Menstruationszyklus nach ärztlicher Empfehlung durchgeführt; vorab sind eine Beratung und eine gynäkologische Untersuchung erforderlich', 'İşlem genellikle hekimin önerdiği menstrüel döngünün belirli günlerinde yapılır; önceden jinekolog görüşmesi ve muayenesi gereklidir', 'Any questions about tolerability or sensations after insertion should be discussed with the gynaecologist at the follow-up visit', 'Sva pitanja o podnošljivosti i osjećajima nakon ugradnje treba razmotriti sa ginekologom na kontrolnom pregledu', 'Сва питања о подношљивости и осјећајима након уградње треба размотрити са гинекологом на контролном прегледу', 'Все вопросы о переносимости и ощущениях после установки следует обсуждать с гинекологом на контрольном приёме', 'Alle Fragen zur Verträglichkeit und zu Empfindungen nach dem Einsetzen sollten beim Kontrolltermin mit der Frauenärztin bzw. dem Frauenarzt besprochen werden', 'Takma sonrası tolerans ve hissedilenlerle ilgili tüm sorular kontrol muayenesinde jinekologla görüşülmelidir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'gastroscopy-without-anesthesia'), 'An endoscopic examination of the oesophagus, stomach and duodenum using a thin flexible tube with a camera', 'Endoskopski pregled jednjaka, želuca i dvanaestopalačnog crijeva pomoću tankog fleksibilnog instrumenta sa kamerom', 'Ендоскопски преглед једњака, желуца и дванаестопалачног цријева помоћу танког флексибилног инструмента са камером', 'Эндоскопическое исследование пищевода, желудка и двенадцатиперстной кишки с помощью тонкого гибкого зонда с камерой', 'Eine endoskopische Untersuchung von Speiseröhre, Magen und Zwölffingerdarm mit einem dünnen, flexiblen Schlauch mit Kamera', 'İnce, esnek ve kameralı bir sonda ile yemek borusu, mide ve on iki parmak bağırsağının endoskopik olarak incelenmesi', 'The doctor passes the endoscope through the mouth and oesophagus into the stomach without general anaesthesia (local throat anaesthesia with a spray is possible); the examination takes 5–15 minutes', 'Ljekar uvodi endoskop kroz usta i jednjak u želudac bez opšte anestezije (moguća je lokalna anestezija grla sprejom); pregled traje 5–15 minuta', 'Љекар уводи ендоскоп кроз уста и једњак у желудац без опште анестезије (могућа је локална анестезија грла спрејом); преглед траје 5–15 минута', 'Врач вводит эндоскоп через рот и пищевод в желудок без наркоза (возможна местная анестезия горла спреем); исследование занимает 5–15 минут', 'Der Arzt führt das Endoskop ohne Vollnarkose durch Mund und Speiseröhre in den Magen ein (eine lokale Rachenbetäubung per Spray ist möglich); die Untersuchung dauert 5–15 Minuten', 'Hekim endoskopu genel anestezi olmadan ağızdan ve yemek borusundan geçirerek mideye ulaştırır (boğaza sprey ile lokal anestezi uygulanabilir); işlem 5–15 dakika sürer', 'Abdominal pain, heartburn, suspected gastritis or ulcer, monitoring of the mucosal condition, investigating the cause of anaemia', 'Bolovi u stomaku, žgaravica, sumnja na gastritis ili čir, kontrola stanja sluznice, traženje uzroka anemije', 'Болови у стомаку, жгаравица, сумња на гастритис или чир, контрола стања слузнице, тражење узрока анемије', 'Боли в животе, изжога, подозрение на гастрит или язву, контроль состояния слизистой, поиск причины анемии', 'Bauchschmerzen, Sodbrennen, Verdacht auf Gastritis oder Geschwür, Kontrolle des Schleimhautzustands, Abklärung der Ursache einer Anämie', 'Karın ağrısı, mide ekşimesi, gastrit veya ülser şüphesi, mukoza durumunun kontrolü, anemi nedeninin araştırılması', 'No food for 6–8 hours before the procedure, no drinks for 2–4 hours; inform the doctor about any medications being taken, especially anticoagulants', 'Ne jesti 6-8 sati prije procedure, ne piti 2-4 sata prije; obavijestiti ljekara o lijekovima koje pacijent uzima, naročito antikoagulansima', 'Не јести 6-8 сати прије процедуре, не пити 2-4 сата прије; обавијестити љекара о лијековима које пацијент узима, нарочито антикоагулансима', 'Не есть 6-8 часов до процедуры, не пить за 2-4 часа; сообщить врачу о принимаемых лекарствах, особенно антикоагулянтах', '6–8 Stunden vor der Untersuchung nichts essen, 2–4 Stunden vorher nichts trinken; den Arzt über eingenommene Medikamente informieren, insbesondere Antikoagulanzien', 'İşlemden 6-8 saat önce yemek yenmemeli, 2-4 saat önce sıvı alınmamalıdır; kullanılan ilaçlar, özellikle antikoagülanlar hakkında hekime bilgi verilmelidir', 'Any changes found in the mucosa are assessed by the gastroenterologist/endoscopist; a biopsy or further examination may be ordered if needed', 'Uočene promjene na sluznici procjenjuje gastroenterolog/endoskopičar, a po potrebi se određuje biopsija ili dodatni pregled', 'Уочене промјене на слузници процјењује гастроентеролог/ендоскопичар, а по потреби се одређује биопсија или додатни преглед', 'Обнаруженные изменения слизистой оценивает врач-гастроэнтеролог/эндоскопист, при необходимости назначается биопсия или дополнительное обследование', 'Festgestellte Veränderungen der Schleimhaut werden vom Gastroenterologen bzw. Endoskopiker beurteilt; bei Bedarf wird eine Biopsie oder eine weitere Untersuchung veranlasst', 'Mukozada saptanan değişiklikler gastroenterolog/endoskopist tarafından değerlendirilir; gerekirse biyopsi veya ek inceleme istenir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'colonoscopy-without-anesthesia'), 'An endoscopic examination of the colon using a flexible tube with a camera', 'Endoskopski pregled debelog crijeva pomoću fleksibilnog instrumenta sa kamerom', 'Ендоскопски преглед дебелог цријева помоћу флексибилног инструмента са камером', 'Эндоскопическое исследование толстой кишки с помощью гибкого зонда с камерой', 'Eine endoskopische Untersuchung des Dickdarms mit einem flexiblen Schlauch mit Kamera', 'Kameralı esnek bir sonda ile kalın bağırsağın endoskopik olarak incelenmesi', 'The doctor inserts the endoscope through the anus and advances it through the colon without general anaesthesia; the examination takes 20–40 minutes', 'Ljekar uvodi endoskop kroz čmar i pomjera ga kroz debelo crijevo bez opšte anestezije; pregled traje 20–40 minuta', 'Љекар уводи ендоскоп кроз чмар и помјера га кроз дебело цријево без опште анестезије; преглед траје 20–40 минута', 'Врач вводит эндоскоп через задний проход и продвигает его по толстой кишке без наркоза; исследование занимает 20–40 минут', 'Der Arzt führt das Endoskop ohne Vollnarkose durch den After ein und schiebt es durch den Dickdarm vor; die Untersuchung dauert 20–40 Minuten', 'Hekim endoskopu anüsten geçirerek genel anestezi olmadan kalın bağırsak boyunca ilerletir; işlem 20–40 dakika sürer', 'Abdominal pain, changes in bowel habits, blood in the stool, family history of colorectal disease, preventive screening after age 45–50', 'Bolovi u stomaku, promjene u pražnjenju crijeva, krv u stolici, porodična anamneza kolorektalnih oboljenja, preventivni skrining poslije 45-50 godina', 'Болови у стомаку, промјене у пражњењу цријева, крв у столици, породична анамнеза колоректалних обољења, превентивни скрининг послије 45-50 година', 'Боли в животе, изменения стула, кровь в стуле, семейный анамнез колоректальных заболеваний, профилактический скрининг после 45-50 лет', 'Bauchschmerzen, veränderter Stuhlgang, Blut im Stuhl, familiäre Vorbelastung mit Darmkrebs, Vorsorgeuntersuchung ab 45–50 Jahren', 'Karın ağrısı, dışkılama alışkanlığında değişiklik, dışkıda kan, ailede kolorektal hastalık öyküsü, 45-50 yaş sonrası koruyucu tarama', 'A special diet and bowel cleansing with laxatives for 1–2 days before the procedure, following a schedule prescribed by the doctor', 'Posebna dijeta i čišćenje crijeva laksativima 1-2 dana prije procedure po šemi koju odredi ljekar', 'Посебна дијета и чишћење цријева лаксативима 1-2 дана прије процедуре по шеми коју одреди љекар', 'Специальная диета и очищение кишечника слабительными препаратами за 1-2 дня до процедуры по схеме, назначенной врачом', 'Spezielle Diät und Darmreinigung mit Abführmitteln 1–2 Tage vor dem Eingriff nach einem vom Arzt vorgegebenen Schema', 'İşlemden 1-2 gün önce hekim tarafından belirlenen programa göre özel diyet ve laksatiflerle bağırsak temizliği', 'Any changes found (such as polyps) are assessed by the gastroenterologist/endoscopist; a biopsy or removal of the growth with subsequent histological examination may be performed if needed', 'Uočene promjene (na primjer, polipi) procjenjuje gastroenterolog/endoskopičar, a po potrebi se radi biopsija ili uklanjanje tvorevine uz dalju histološku analizu', 'Уочене промјене (на примјер, полипи) процјењује гастроентеролог/ендоскопичар, а по потреби се ради биопсија или уклањање творевине уз даљу хистолошку анализу', 'Обнаруженные изменения (например, полипы) оценивает врач-гастроэнтеролог/эндоскопист, при необходимости выполняется биопсия или удаление образования с дальнейшим гистологическим исследованием', 'Festgestellte Veränderungen (z. B. Polypen) werden vom Gastroenterologen bzw. Endoskopiker beurteilt; bei Bedarf werden eine Biopsie oder die Entfernung der Wucherung mit anschließender histologischer Untersuchung durchgeführt', 'Saptanan değişiklikler (örneğin polipler) gastroenterolog/endoskopist tarafından değerlendirilir; gerekirse biyopsi veya oluşumun çıkarılıp histolojik incelemeye gönderilmesi uygulanır')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'amniocentesis'), 'An invasive prenatal procedure — collecting a small amount of amniotic fluid for laboratory and genetic testing', 'Invazivna prenatalna procedura — uzimanje male količine plodove vode radi laboratorijske i genetske analize', 'Инвазивна пренатална процедура — узимање мале количине плодове воде ради лабораторијске и генетске анализе', 'Инвазивная пренатальная процедура — забор небольшого объёма околоплодных вод для лабораторного и генетического исследования', 'Ein invasiver pränataler Eingriff — Entnahme einer kleinen Menge Fruchtwasser zur Labor- und genetischen Untersuchung', 'İnvaziv bir prenatal işlem — laboratuvar ve genetik inceleme için az miktarda amniyon sıvısının alınması', 'Under ultrasound guidance, a thin needle is used to draw a sample of amniotic fluid through the abdominal wall; the procedure itself takes only a few minutes', 'Pod kontrolom ultrazvuka, tankom iglom kroz trbušni zid uzima se uzorak amnionske tečnosti; sama procedura traje samo nekoliko minuta', 'Под контролом ултразвука, танком иглом кроз трбушни зид узима се узорак амнионске течности; сама процедура траје само неколико минута', 'Под контролем УЗИ тонкой иглой через переднюю брюшную стенку берут образец амниотической жидкости; сама процедура занимает несколько минут', 'Unter Ultraschallkontrolle wird mit einer dünnen Nadel durch die Bauchdecke eine Fruchtwasserprobe entnommen; der Eingriff selbst dauert nur wenige Minuten', 'Ultrason eşliğinde ince bir iğneyle karın duvarından amniyon sıvısı örneği alınır; işlemin kendisi yalnızca birkaç dakika sürer', 'Abnormal prenatal screening results, a significant family history, maternal age, or other indications — as recommended by a doctor', 'Odstupanja u rezultatima prenatalnog skrininga, opterećena porodična anamneza, starost majke i druge indikacije — po preporuci ljekara', 'Одступања у резултатима пренаталног скрининга, оптерећена породична анамнеза, старост мајке и друге индикације — по препоруци љекара', 'Отклонения в результатах пренатального скрининга, отягощённый семейный анамнез, возраст матери и другие показания — по рекомендации врача', 'Auffällige Ergebnisse des pränatalen Screenings, belastete Familienanamnese, mütterliches Alter oder andere Indikationen — nach ärztlicher Empfehlung', 'Prenatal tarama sonuçlarında sapma, ağır aile öyküsü, anne yaşı ve diğer endikasyonlar — hekim önerisiyle', 'An ultrasound scan right before the procedure; no special preparation is usually required, but the doctor should be informed about blood thinners or allergies', 'Ultrazvučni pregled neposredno prije procedure; posebna priprema obično nije potrebna, ali ljekara treba obavijestiti o uzimanju antikoagulanasa i alergijama', 'Ултразвучни преглед непосредно прије процедуре; посебна припрема обично није потребна, али љекара треба обавијестити о узимању антикоагуланаса и алергијама', 'УЗИ непосредственно перед процедурой; специальной подготовки обычно не требуется, но нужно сообщить врачу о приёме антикоагулянтов и аллергиях', 'Ultraschalluntersuchung unmittelbar vor dem Eingriff; in der Regel keine besondere Vorbereitung nötig, der Arzt sollte jedoch über Blutverdünner und Allergien informiert werden', 'İşlemden hemen önce ultrason yapılır; genellikle özel bir hazırlık gerekmez, ancak kan sulandırıcı kullanımı ve alerjiler hekime bildirilmelidir', 'Results are interpreted by a geneticist or obstetrician together with the overall clinical picture; the possible risks and complications of the procedure itself are discussed with the doctor beforehand', 'Rezultate tumači ljekar genetičar ili ginekolog-akušer uzimajući u obzir cjelokupnu kliničku sliku; mogući rizici i komplikacije same procedure razmatraju se sa ljekarom unaprijed', 'Резултате тумачи љекар генетичар или гинеколог-акушер узимајући у обзир цјелокупну клиничку слику; могући ризици и компликације саме процедуре разматрају се са љекаром унапријед', 'Результаты интерпретирует врач-генетик или акушер-гинеколог с учётом полной клинической картины; возможные риски и осложнения самой процедуры обсуждаются с врачом заранее', 'Die Ergebnisse werden von einem Genetiker oder Gynäkologen im Zusammenhang mit dem gesamten klinischen Bild interpretiert; mögliche Risiken und Komplikationen des Eingriffs selbst werden vorab mit dem Arzt besprochen', 'Sonuçlar, genel klinik tablo dikkate alınarak bir genetik uzmanı veya kadın doğum uzmanı tarafından yorumlanır; işlemin kendisine ait olası riskler ve komplikasyonlar önceden hekimle görüşülür')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'vaginal-delivery-anterior-occiput-presentation'), 'Vaginal delivery with the baby in the most physiological position — head down, facing the mother''s back (occiput anterior)', 'Vaginalni porođaj sa bebom u najpovoljnijem položaju — glavicom nadole, potiljkom naprijed', 'Вагинални порођај са бебом у најповољнијем положају — главицом надоле, потиљком напријед', 'Естественные роды через родовые пути при наиболее физиологичном положении плода — затылочном предлежании, лицом назад', 'Vaginale Geburt mit dem Baby in der günstigsten Position — Kopf nach unten, Hinterhaupt nach vorne', 'Bebeğin en uygun pozisyonda olduğu — başı aşağıda, ense öne bakacak şekilde — vajinal doğum', 'Labor proceeds in stages (cervical dilation, pushing, delivery of the placenta) under the supervision of the obstetric team; duration varies individually', 'Porođaj protiče u fazama (otvaranje grlića materice, period tiskanja, rađanje posteljice) pod nadzorom akušerskog tima; trajanje je individualno', 'Порођај протиче у фазама (отварање грлића материце, период тискања, рађање постељице) под надзором акушерског тима; трајање је индивидуално', 'Роды проходят поэтапно (раскрытие шейки матки, потужной период, рождение последа) под наблюдением акушерской бригады; длительность индивидуальна', 'Die Geburt verläuft in Phasen (Muttermundöffnung, Presswehen, Ausstoßung der Plazenta) unter Aufsicht des geburtshilflichen Teams; die Dauer ist individuell', 'Doğum aşamalar halinde ilerler (rahim ağzının açılması, ıkınma dönemi, plasentanın çıkması) ve doğum ekibi gözetiminde gerçekleşir; süresi kişiden kişiye değişir', 'Full-term pregnancy, head-down fetal position, and no contraindications to vaginal delivery', 'Terminska trudnoća, glavično predlaganje ploda i odsustvo kontraindikacija za vaginalni porođaj', 'Терминска трудноћа, главично предлагање плода и одсуство контраиндикација за вагинални порођај', 'Доношенная беременность, головное предлежание плода, отсутствие противопоказаний к родам через естественные родовые пути', 'Termingerechte Schwangerschaft, Schädellage des Kindes und keine Kontraindikationen für eine vaginale Geburt', 'Zamanında (miadında) gebelik, bebeğin baş geliş pozisyonunda olması ve vajinal doğuma engel bir durumun bulunmaması', 'Regular prenatal check-ups throughout the pregnancy, arrangements with the clinic regarding delivery conditions, and prenatal preparation as recommended by the doctor', 'Redovne kontrole tokom trudnoće, dogovor sa klinikom o uslovima porođaja, priprema za porođaj po preporuci ljekara', 'Редовне контроле током трудноће, договор са клиником о условима порођаја, припрема за порођај по препоруци љекара', 'Плановое наблюдение на протяжении беременности, договорённость с клиникой об условиях родов, предродовая подготовка по рекомендации врача', 'Regelmäßige Vorsorgeuntersuchungen während der Schwangerschaft, Absprache mit der Klinik zu den Geburtsbedingungen, Geburtsvorbereitung nach ärztlicher Empfehlung', 'Gebelik boyunca düzenli kontroller, doğum koşulları konusunda klinikle anlaşma, hekim önerisiyle doğuma hazırlık', 'The management of labor (continuing vaginal delivery, induction, or switching to a cesarean section if needed) is decided by the obstetrician based on ongoing monitoring of the mother and baby', 'Tok porođaja (nastavak vaginalnog porođaja, stimulacija ili, ako je potrebno, prelazak na carski rez) određuje ginekolog-akušer na osnovu praćenja stanja majke i bebe', 'Ток порођаја (наставак вагиналног порођаја, стимулација или, ако је потребно, прелазак на царски рез) одређује гинеколог-акушер на основу праћења стања мајке и бебе', 'Тактика ведения родов (продолжение естественных родов, стимуляция, при необходимости переход к кесареву сечению) определяется акушером-гинекологом по ходу наблюдения за состоянием матери и плода', 'Der Geburtsverlauf (Fortsetzung der vaginalen Geburt, Einleitung oder bei Bedarf Übergang zum Kaiserschnitt) wird vom Geburtshelfer anhand der laufenden Überwachung von Mutter und Kind entschieden', 'Doğumun seyri (vajinal doğuma devam, indüksiyon veya gerekirse sezaryene geçiş) anne ve bebeğin durumu izlenerek kadın doğum uzmanı tarafından belirlenir')
ON DUPLICATE KEY UPDATE what_en=VALUES(what_en), what_sr=VALUES(what_sr), what_sr_cyrl=VALUES(what_sr_cyrl), what_ru=VALUES(what_ru), what_de=VALUES(what_de), what_tr=VALUES(what_tr), how_en=VALUES(how_en), how_sr=VALUES(how_sr), how_sr_cyrl=VALUES(how_sr_cyrl), how_ru=VALUES(how_ru), how_de=VALUES(how_de), how_tr=VALUES(how_tr), indications_en=VALUES(indications_en), indications_sr=VALUES(indications_sr), indications_sr_cyrl=VALUES(indications_sr_cyrl), indications_ru=VALUES(indications_ru), indications_de=VALUES(indications_de), indications_tr=VALUES(indications_tr), prep_en=VALUES(prep_en), prep_sr=VALUES(prep_sr), prep_sr_cyrl=VALUES(prep_sr_cyrl), prep_ru=VALUES(prep_ru), prep_de=VALUES(prep_de), prep_tr=VALUES(prep_tr), abnormal_en=VALUES(abnormal_en), abnormal_sr=VALUES(abnormal_sr), abnormal_sr_cyrl=VALUES(abnormal_sr_cyrl), abnormal_ru=VALUES(abnormal_ru), abnormal_de=VALUES(abnormal_de), abnormal_tr=VALUES(abnormal_tr);

INSERT INTO medical_service_reference_info (medical_service_id, what_en, what_sr, what_sr_cyrl, what_ru, what_de, what_tr, how_en, how_sr, how_sr_cyrl, how_ru, how_de, how_tr, indications_en, indications_sr, indications_sr_cyrl, indications_ru, indications_de, indications_tr, prep_en, prep_sr, prep_sr_cyrl, prep_ru, prep_de, prep_tr, abnormal_en, abnormal_sr, abnormal_sr_cyrl, abnormal_ru, abnormal_de, abnormal_tr)
VALUES ((SELECT id FROM medical_services WHERE slug = 'low-isthmic-cesarean-section-with-delivery'), 'A surgical delivery performed through an incision in the lower segment of the uterus', 'Hirurški porođaj kroz rez u donjem segmentu materice', 'Хируршки порођај кроз рез у доњем сегменту материце', 'Хирургическая операция родоразрешения через разрез в нижнем сегменте матки', 'Eine operative Entbindung durch einen Schnitt im unteren Gebärmuttersegment', 'Rahmin alt segmentinden yapılan bir kesi ile gerçekleştirilen cerrahi doğum', 'Performed under anesthesia (spinal, epidural, or general); involves an incision in the abdominal wall and uterus, delivery of the baby, and closure of the tissues', 'Izvodi se u anesteziji (spinalnoj, epiduralnoj ili opštoj); obuhvata rez trbušnog zida i materice, izvođenje bebe i potom šivenje tkiva', 'Изводи се у анестезији (спиналној, епидуралној или општој); обухвата рез трбушног зида и материце, извођење бебе и потом шивење ткива', 'Проводится под анестезией (спинальной, эпидуральной или общей); включает разрез передней брюшной стенки и матки, извлечение ребёнка и последующее ушивание тканей', 'Wird unter Anästhesie durchgeführt (Spinal-, Periduralanästhesie oder Vollnarkose); umfasst einen Schnitt in Bauchdecke und Gebärmutter, die Entbindung des Kindes und das anschließende Vernähen des Gewebes', 'Anestezi altında (spinal, epidural veya genel) uygulanır; karın duvarı ve rahimde kesi yapılmasını, bebeğin çıkarılmasını ve ardından dokuların dikilmesini içerir', 'Planned or emergency indications on the part of the mother or baby, determined by the obstetrician (previous cesarean section, abnormal fetal position, conditions where vaginal delivery is contraindicated, and others)', 'Planirane ili hitne indikacije sa strane majke ili bebe, koje određuje ginekolog-akušer (prethodni carski rez, nepravilan položaj ploda, stanja kod kojih je vaginalni porođaj kontraindikovan i drugo)', 'Планиране или хитне индикације са стране мајке или бебе, које одређује гинеколог-акушер (претходни царски рез, неправилан положај плода, стања код којих је вагинални порођај контраиндикован и друго)', 'Плановые или экстренные показания со стороны матери или плода — определяются акушером-гинекологом (предыдущее кесарево сечение, неправильное положение плода, состояния, при которых естественные роды противопоказаны, и другие)', 'Geplante oder notfallmäßige Indikationen seitens der Mutter oder des Kindes, die vom Geburtshelfer festgelegt werden (vorheriger Kaiserschnitt, regelwidrige Kindslage, Zustände, bei denen eine vaginale Geburt kontraindiziert ist, und andere)', 'Anne veya bebek tarafından kaynaklanan, kadın doğum uzmanı tarafından belirlenen planlı veya acil endikasyonlar (önceki sezaryen, bebeğin anormal pozisyonu, vajinal doğumun kontrendike olduğu durumlar ve diğerleri)', 'Preoperative work-up, an anesthesiologist consultation, and restrictions on food intake before surgery as instructed by the doctor', 'Predoperativni pregledi, konsultacija sa anesteziologom, ograničenje unosa hrane prije operacije po nalogu ljekara', 'Предоперативни прегледи, консултација са анестезиологом, ограничење уноса хране прије операције по налогу љекара', 'Предоперационное обследование, консультация анестезиолога, ограничение приёма пищи перед операцией по назначению врача', 'Präoperative Untersuchungen, eine anästhesiologische Beratung sowie Einschränkungen bei der Nahrungsaufnahme vor der Operation nach ärztlicher Anweisung', 'Ameliyat öncesi tetkikler, anestezi uzmanı konsültasyonu ve hekim talimatına göre ameliyat öncesi gıda kısıtlaması', 'The postoperative course and any possible complications are assessed by the treating doctor; the choice of delivery method is made individually by the obstetrician in each case', 'Tok postoperativnog perioda i eventualne komplikacije procjenjuje ljekar koji vodi slučaj; odluku o načinu porođaja ginekolog-akušer donosi individualno za svaki slučaj', 'Ток постоперативног периода и евентуалне компликације процјењује љекар који води случај; одлуку о начину порођаја гинеколог-акушер доноси индивидуално за сваки случај', 'Течение послеоперационного периода и возможные осложнения оценивает лечащий врач; решение о методе родоразрешения в каждом случае принимает акушер-гинеколог индивидуально', 'Der postoperative Verlauf und mögliche Komplikationen werden vom behandelnden Arzt beurteilt; die Wahl der Entbindungsmethode trifft der Geburtshelfer in jedem Einzelfall individuell', 'Ameliyat sonrası süreç ve olası komplikasyonlar tedaviyi yürüten hekim tarafından değerlendirilir; doğum yöntemine karar verme her vakada kadın doğum uzmanı tarafından ayrı ayrı yapılır')
